const genericSpecs = {
  capitalizing_vs_expensing: {
    title: 'The expense line decides when management’s promise becomes an asset.',
    dek: 'Ind AS 38 makes capitalization a recognition judgment governed by identifiable future benefits and reliable measurement, not a choice made to smooth profit.',
    sourceList: [source('icai_ind_as_38_material', 'ICAI Educational Material on Ind AS 38, Intangible Assets', 'https://www.icai.org/post/release-educational-material-indas38')],
    mechanics: 'Test whether the expenditure creates an identifiable resource controlled by the entity, whether future economic benefits are probable, and whether cost can be measured reliably. Capitalized cost then enters amortization and impairment analysis.',
    formula: { label: 'Recognition boundary', lhsLatex: String.raw`\text{Recognised asset}`, relationLatex: '=', rhsLatex: String.raw`\text{identifiable controlled resource with probable future benefits and reliable measurement}`, latex: String.raw`\text{Recognised asset} = \text{identifiable controlled resource with probable future benefits and reliable measurement}`, sourceId: 'icai_ind_as_38_material', glossary: { identifiable: { term: 'Identifiable resource', definition: 'A resource that is separable or arises from contractual or other legal rights.', location: 'Balance sheet and intangible asset note.', financialInterpretation: 'Identifiability prevents general business expectations from being recorded as a separately measurable asset.', commonExaminationTrap: 'Calling employee skill or internally generated reputation a recognized asset merely because it has value.' }, control: { term: 'Control', definition: 'The entity’s power to obtain future economic benefits and restrict others’ access to those benefits.', location: 'Recognition assessment and asset note.', financialInterpretation: 'Control distinguishes an owned or enforceable resource from a benefit that depends on market participation or staff retention.', commonExaminationTrap: 'Confusing expenditure with control.' }, benefits: { term: 'Future economic benefits', definition: 'Future inflows of cash, reductions in cash outflows, or other economic advantages expected from use or sale of the resource.', location: 'Recognition assessment and impairment analysis.', financialInterpretation: 'Expected benefit is the economic reason capitalization can be justified.', commonExaminationTrap: 'Treating management optimism as sufficient evidence.' } } },
    knowledgeMap: { whyItExists: 'Financial reporting must assign an expenditure to the periods that receive the related economic benefit. The recognition boundary prevents current profit from being reduced by a resource that will generate benefits later, while also preventing uncertain hopes from being presented as assets.', informationIsolated: 'The rule isolates controlled, identifiable resources from spending that supports the business without creating a separately measurable asset. It therefore separates investment in a resource from current period consumption.', decisionEnabled: 'The conclusion affects reported profit, assets, amortization, impairment, return on assets, and the credibility of management’s growth narrative. It also determines what a lender or investor must test in later periods.', validityAssumptions: 'The assessment depends on control, identifiability, probable future benefits, reliable measurement, and the distinction between research and development phases. A favorable forecast cannot cure the absence of control or reliable measurement.', criticalQuestion: 'What evidence shows that the expenditure created a controlled resource whose future benefits are probable, rather than merely funding current operations or management’s expectation of future success?' },
    sections: { 'case-context': ['Ind AS 38 governs the recognition boundary for intangible assets. The standard matters because expenditure can affect current profit or remain on the balance sheet, even when the cash payment occurs at the same time.', 'The accounting question is not whether the spending was strategically important. It is whether the entity has a separately identifiable resource that meets the recognition conditions.'], 'governing-question': ['When should an expenditure be carried forward as an asset because it creates future economic benefits, and when should it reduce current period profit?'], 'conceptual-foundation': ['Capitalization changes timing. The cash leaves when the expenditure is paid, but expense recognition may occur through amortization or impairment when the resource is consumed or loses recoverable value.', 'The standard protects comparability by demanding an identifiable resource rather than allowing management to capitalize every expenditure that supports a long range plan.', 'Research expenditure and development expenditure are not interchangeable. The latter requires evidence that technical feasibility, intention, resources, probable benefits, and measurement conditions are satisfied.'], 'economic-logic': ['Capitalization can increase current profit because the cost is deferred. That accounting effect makes the recognition threshold economically important, particularly when performance targets, covenants, or valuation narratives depend on current earnings.', 'Expensing can reduce current profit even when the spending supports future growth. The economic substance therefore depends on whether a separable resource exists and whether the entity controls the expected benefits.', 'The subsequent accounting is part of the original decision. An asset that is capitalized without a credible consumption pattern can defer a loss until impairment becomes unavoidable.'], 'formula-construction': ['The recognition formula is a decision rule, not an arithmetic identity. All conditions must be satisfied before cost can be carried forward.', 'Once recognized, the cost is allocated over the useful life when the asset has a finite life, or tested for impairment when the benefit pattern or life requires that treatment.', 'The formula cannot convert an unidentifiable benefit into an asset. The accounting judgment precedes the arithmetic.'], eli5: ['If you pay for a machine that will help the factory for years, the payment happens today but the machine is used over time. Accounting records the machine as an asset and recognizes its cost as it is consumed.', 'If the spending does not create a resource the company controls, it is a cost of running the business and belongs in current profit.'], 'comparative-framework': ['Capitalization defers expense recognition. Expensing recognizes the cost immediately. The choice changes the timing of profit but not the cash paid.', 'A tangible asset normally has physical form, while an intangible asset depends on rights, separability, or enforceable access to benefits. The absence of physical form does not remove the recognition test.', 'Goodwill, internally generated brands, research, and development require distinct analysis. Treating every future benefit as an intangible asset destroys the boundary the standard is designed to preserve.'], interpretation: ['A capitalized balance is a claim about future benefits. The reviewer should therefore examine the evidence supporting the forecast, the useful life, the amortization method, and impairment indicators.', 'A rising asset balance alongside weak cash generation can indicate investment, but it can also indicate delayed expense recognition. The conclusion depends on the nature of the spending and subsequent economic performance.', 'The correct benchmark is the governing standard and comparable accounting policies, not a universal capitalization percentage.'], 'assumptions-limitations': ['Recognition judgments depend on forecasts and legal rights. A resource can fail because the entity lacks control even when the commercial project is valuable.', 'Capitalization does not improve economics. It changes presentation and shifts expense recognition into later periods, which can make early performance appear stronger.', 'The standard does not remove uncertainty. It requires the uncertainty to be addressed through recognition, measurement, amortization, and impairment rules.'], 'case-resolution': ['The Ind AS 38 framework resolves the question by moving the debate away from managerial preference and toward evidence of a controlled, identifiable resource.', 'For MBA finance analysis, the central implication is that reported earnings can be affected by recognition timing. Any comparison of profitability must examine the asset policy and the future amortization or impairment burden.'] },
    definitions: [definition('capitalization', 'Capitalization', 'Recognition', 'The accounting treatment that records a qualifying expenditure as an asset because it is expected to provide future economic benefits under the governing recognition criteria.', 'It changes the timing of expense recognition and therefore affects reported profit and asset balances.', 'Assuming capitalization is permitted whenever management expects a project to succeed.'), definition('expensing', 'Expensing', 'Recognition', 'The recognition of an expenditure in current period profit or loss because it does not meet the criteria for recognition as a controlled, identifiable resource.', 'It prevents uncertain future benefits from being presented as current assets.', 'Treating current expense as evidence that the spending had no strategic value.'), definition('amortization', 'Amortization', 'Subsequent measurement', 'The systematic allocation of the depreciable amount of an intangible asset over its finite useful life.', 'It connects the asset balance to the periods receiving its benefits.', 'Ignoring useful life changes and impairment indicators.'), definition('impairment', 'Impairment', 'Subsequent measurement', 'A reduction in the carrying amount of an asset when its recoverable amount is below the amount reported.', 'It tests whether a previously capitalized benefit still supports the carrying value.', 'Treating impairment as a non economic accounting event.'), definition('research_and_development', 'Research and development', 'Innovation spending', 'Research investigates knowledge while development applies knowledge to a plan that may meet separate recognition conditions once feasibility and benefit evidence exist.', 'The distinction prevents early uncertainty from being capitalized as if commercial viability were already established.', 'Capitalizing research merely because development may follow.')],
    coverage: [coverage('recognition boundary', 'Conceptual Foundation', ['capitalization', 'expensing']), coverage('subsequent measurement', 'Formula Construction', ['amortization', 'impairment']), coverage('innovation spending', 'Comparative Framework', ['research_and_development'])],
    questions: [question('Why does capitalization increase current profit?', 'Capitalization removes the expenditure from current period expense and places it on the balance sheet. The cost is recognized later through amortization or impairment, so current profit rises relative to immediate expensing even though cash has already been paid.'), question('What must be proved before an intangible asset is recognized?', 'The entity must demonstrate an identifiable resource, control over the expected benefits, probable future economic benefits, and reliable measurement of cost. A strategic plan or optimistic forecast is not a substitute for those conditions.'), question('Why is the research phase treated differently from development?', 'Research is exploratory and does not yet establish technical feasibility or probable commercial benefits. Development may qualify only after the entity can demonstrate the required evidence that the project will be completed, used or sold, and generate benefits.'), question('How does capitalization affect return on assets?', 'Capitalization increases assets and avoids immediate expense recognition, which can increase current profit but also enlarge the denominator in return on assets. The direction of the ratio depends on the relative effect on profit and asset carrying value.'), question('Why does impairment matter after capitalization?', 'Capitalization creates a future claim about economic benefits. Impairment tests whether that claim remains supportable. If expected benefits fall, the carrying value must be reduced, often producing a concentrated loss after earlier periods benefited from deferred expense recognition.'), question('Can two companies with identical cash spending report different profit?', 'Yes. Different recognition judgments, standards, useful lives, or evidence about control can change whether spending is expensed or capitalized. The cash flow can be identical while reported profit and asset balances differ.'), question('What is the most important question for a lender?', 'The lender should ask whether the asset balance represents realizable or productive economic value that supports repayment. Capitalized costs that cannot generate cash do not strengthen debt capacity merely because they appear as assets.'), question('What is the core MBA finance lesson?', 'Accounting recognition is a timing and evidence problem. A finance professional must separate cash investment, reported profit, asset carrying value, and future economic benefit instead of treating one line as a complete description of the project.')],
  },
};

const referenceConfigs = {
  revenue_recognition: {
    title: 'Revenue is not a billing event. It is a transfer claim.',
    dek: 'IFRS 15 makes reported revenue follow the transfer of promised goods or services, which is why contract design and performance obligations matter more than invoice timing.',
    sources: [source('ifrs_15_standard', 'IFRS 15 Revenue from Contracts with Customers', 'https://www.ifrs.org/issued-standards/list-of-standards/ifrs-15-revenue-from-contracts/')],
    mechanics: 'Apply the five step model: identify the contract, identify performance obligations, determine transaction price, allocate price to obligations, and recognize revenue when each obligation is satisfied.',
    formula: { label: 'Revenue recognition', lhsLatex: String.raw`\text{Revenue}_t`, relationLatex: '=', rhsLatex: String.raw`\text{allocated transaction price for performance obligations satisfied in period }t`, latex: String.raw`\text{Revenue}_t = \text{allocated transaction price for performance obligations satisfied in period }t`, sourceId: 'ifrs_15_standard' },
    terms: [
      ['performance_obligation', 'Performance obligation', 'Revenue measurement', 'A promise in a customer contract to transfer a distinct good or service, or a series of distinct goods or services with the same transfer pattern.', 'It determines what must be delivered before revenue can be recognized.', 'Treating every invoice line as a separate performance obligation without testing whether the promise is distinct.'],
      ['transaction_price', 'Transaction price', 'Revenue measurement', 'The amount of consideration to which an entity expects to be entitled in exchange for transferring promised goods or services, including the effect of variable consideration and financing components when relevant.', 'It prevents gross billings from being mistaken for realizable revenue.', 'Ignoring rebates, returns, penalties, refunds, or significant financing effects.'],
      ['contract_asset', 'Contract asset', 'Contract balance', 'An entity’s right to consideration in exchange for goods or services already transferred when that right depends on something other than the passage of time.', 'It explains why recognized revenue can precede an unconditional receivable.', 'Calling every unbilled amount a receivable.'],
      ['contract_liability', 'Contract liability', 'Contract balance', 'An entity’s obligation to transfer goods or services for which consideration has already been received or is due from the customer.', 'It prevents advance cash collection from being reported as earned revenue.', 'Treating customer deposits as profit.'],
      ['point_in_time', 'Point in time recognition', 'Timing', 'Recognition when control of a promised good transfers at a particular moment rather than continuously.', 'It makes delivery, acceptance, title, and control evidence central to cutoff.', 'Using invoice date as a substitute for control transfer.'],
      ['over_time', 'Over time recognition', 'Timing', 'Recognition as an entity satisfies a performance obligation continuously under the criteria for transfer over time.', 'It links revenue to measured progress rather than arbitrary billing milestones.', 'Recognizing revenue over time without a reliable measure of progress.'],
    ],
    governing: 'When should reported revenue reflect economic transfer to the customer rather than billing or cash collection?',
    paragraphs: {
      'case-context': ['IFRS 15 is a reference anchor rather than a company anecdote because the governing problem is contractual. The same invoice can produce different accounting depending on what the entity promised, when control transfers, and whether consideration is variable.', 'The standard therefore moves revenue analysis away from the billing system and toward the economics of the customer contract.'],
      'conceptual-foundation': ['Revenue represents the transfer of promised goods or services for consideration. The five step model is a sequence of judgments that identifies the promise, measures the consideration, and determines the transfer pattern.', 'The customer is the reference point. The accounting question is when the customer obtains control, not when management issues an invoice or receives cash.', 'The model protects the period by preventing advance consideration, refundable amounts, and unsatisfied obligations from inflating earned revenue.'],
      'economic-logic': ['Revenue timing affects margins, growth rates, working capital, covenants, valuation, and management compensation. That makes performance obligation design an economic issue, not an administrative detail.', 'Variable consideration creates a second judgment. Expected consideration must be constrained when recognizing it would create a significant risk of reversal.', 'A contract can contain multiple promises. Allocating one transaction price across those promises determines which periods receive the reported revenue and which periods carry the remaining obligation.'],
      'formula-construction': ['The formula is a period allocation rule. It does not say that cash equals revenue. It says that the portion of transaction price allocated to satisfied obligations belongs in the period in which transfer occurs.', 'Point in time obligations require evidence of control transfer. Over time obligations require a faithful measure of progress toward completion.', 'The calculation begins with contract analysis. Arithmetic allocation cannot repair an incorrect conclusion about what was promised or when it was transferred.'],
      eli5: ['A customer can pay before receiving what was promised. The money is cash, but it is not earned revenue until the company performs.', 'Revenue follows the handover of the promised benefit, not the moment the invoice is printed.'],
      'comparative-framework': ['Billing measures a claim for payment. Cash collection measures settlement. Revenue recognition measures performance under the contract. These three events can occur in different periods.', 'A receivable is unconditional consideration due after performance. A contract asset depends on another condition. A contract liability represents performance still owed.', 'The correct benchmark is the governing standard and the entity’s contract pattern. There is no universal timing rule that replaces contract analysis.'],
      interpretation: ['Revenue quality improves when recognition aligns with transfer, consideration is constrained for reversal risk, and contract balances explain the timing difference between performance and cash.', 'A sharp rise in revenue with a growing contract asset or deteriorating cash conversion requires analysis of contract terms, acceptance provisions, and progress measurement.', 'The central question is whether the reported revenue describes performance delivered to the customer during the period.'],
      'assumptions-limitations': ['The model depends on enforceable contract terms, a defensible assessment of distinct promises, and evidence that control has transferred.', 'Estimates of variable consideration and progress can be revised. The possibility of revision does not invalidate the model, but it makes disclosure and reversal analysis essential.', 'Industry practice matters. A software license, a construction service, a subscription, and a commodity shipment can transfer control under different patterns.'],
      'case-resolution': ['IFRS 15 resolves the billing problem by requiring the entity to reconstruct the contract and follow the transfer of promised performance.', 'For MBA finance analysis, the implication is direct: revenue growth is not economically informative until the analyst understands what has been delivered, what remains owed, and how much consideration can still reverse.'],
    },
    questions: [
      ['Why is billing not the same as revenue?', 'Billing establishes an invoiced claim, while revenue reflects transfer of promised goods or services. A company can bill before performance and record a contract liability, or perform before an unconditional right to payment exists and record a contract asset.'],
      ['What is the purpose of identifying performance obligations?', 'The step identifies the separate promises that require delivery. It prevents an entity from recognizing the full contract price when only one component has been transferred and makes allocation and timing explicit.'],
      ['How does variable consideration affect revenue?', 'Expected variable consideration is included only to the extent that a significant reversal is not probable. Rebates, returns, penalties, and service level credits therefore affect both measurement and the evidence required for recognition.'],
      ['What is the difference between a contract asset and a receivable?', 'A receivable is an unconditional right to consideration that depends only on the passage of time. A contract asset depends on another condition, such as completing a milestone, even though the entity has already transferred some performance.'],
      ['When is revenue recognized over time?', 'Revenue is recognized over time when the customer receives and consumes benefits as the entity performs, controls the asset as it is created, or the entity has no alternative use for the asset and an enforceable right to payment for performance completed.'],
      ['Why can revenue growth coexist with weak cash flow?', 'Revenue can be recognized before cash collection, especially when receivables or contract assets expand. The cash flow statement and contract balance disclosures therefore test whether reported performance has converted into cash.'],
      ['What is the most important cutoff test?', 'The reviewer should identify the exact point at which control transferred and compare that point with the reporting date. Invoice date, shipping date, acceptance date, and customer use may differ under the contract.'],
      ['What is the durable finance lesson?', 'Reported revenue is a claim about completed economic performance. The quality of that claim depends on contract substance, transfer evidence, consideration uncertainty, and the timing of obligations that remain unsatisfied.'],
    ],
  },
  deferred_tax_asset: {
    title: 'A tax benefit is an asset only when future profit can use it.',
    dek: 'Ind AS 12 links deferred tax asset recognition to future taxable profit, turning tax accounting into an evidence problem rather than a mechanical multiplication exercise.',
    sources: [source('icai_ind_as_12_material', 'ICAI Educational Material on Ind AS 12, Income Taxes', 'https://www.icai.org/post/educational-material-on-indas-12-income-taxes'), source('icai_ind_as_12_pdf', 'ICAI Educational Material on Ind AS 12, Income Taxes PDF', 'https://kb.icai.org/pdfs/PDFFile664ae4ef5c4c05.26743208.pdf')],
    mechanics: 'Identify deductible temporary differences, unused tax losses, and unused tax credits; measure the future tax benefit using the applicable tax rate; recognize it only when sufficient future taxable profit is probable.',
    formula: { label: 'Deferred tax asset', lhsLatex: String.raw`\text{DTA}`, relationLatex: '=', rhsLatex: String.raw`\text{deductible temporary difference} \times \text{applicable tax rate}`, latex: String.raw`\text{DTA} = \text{deductible temporary difference} \times \text{applicable tax rate}`, sourceId: 'icai_ind_as_12_material' },
    terms: [['temporary_difference', 'Temporary difference', 'Tax accounting', 'The difference between the carrying amount of an asset or liability in the statement of financial position and its tax base.', 'It explains why accounting profit and taxable profit can diverge without a permanent tax difference.', 'Confusing a timing difference with a permanent difference.'], ['tax_base', 'Tax base', 'Tax accounting', 'The amount attributed to an asset or liability for tax purposes that determines future taxable or deductible amounts.', 'It provides the reference point for measuring future tax consequences.', 'Using book value as the tax base without checking tax law.'], ['deductible_difference', 'Deductible temporary difference', 'Tax accounting', 'A temporary difference that will produce amounts deductible in determining taxable profit when the carrying amount is recovered or settled.', 'It is the source of a future tax benefit.', 'Recognizing the benefit without evidence of taxable profit against which it can be used.'], ['tax_loss_carryforward', 'Unused tax loss carryforward', 'Tax accounting', 'A tax loss available to reduce taxable profit in future periods under applicable tax rules.', 'It can create a DTA but also exposes the entity to a utilization judgment.', 'Treating an expiring loss as if it were an unrestricted asset.'], ['probable_taxable_profit', 'Probable taxable profit', 'Recognition evidence', 'Future taxable profit supported by evidence and forecasts that is sufficient to justify utilization of a deferred tax benefit.', 'It is the recognition gate that prevents unsupported tax assets from overstating resources.', 'Relying only on optimistic budgets when recent losses provide contrary evidence.']],
    governing: 'When does an accounting difference create a future tax benefit that can be recognized as an asset, and what evidence supports recognition?',
    paragraphs: { 'case-context': ['Ind AS 12 treats deferred tax as a balance sheet consequence of timing differences. The difficult judgment is not the tax multiplication; it is whether the future benefit is usable.', 'A loss can therefore create a potential tax asset without creating an immediately realizable economic resource. Recognition depends on future taxable profit and the legal period in which the benefit can be used.'], 'conceptual-foundation': ['A deferred tax asset represents future reduction in tax payments. It arises when accounting recognition today will produce a tax deduction later, or when tax losses and credits can offset future taxable profit.', 'The asset is conditional. It has value only if the entity generates taxable profit, remains within the legal carryforward period, and satisfies the relevant tax rules.', 'The accounting standard therefore requires evidence. Historical losses, forecast profit, reversal of taxable temporary differences, tax planning, and the expiry profile all matter.'], 'economic-logic': ['Recognizing a DTA increases assets and can reduce tax expense, but it does not create cash today. The benefit is a claim on future taxable income.', 'That claim can be informative when the business has visible recurring profit and predictable reversals. It becomes fragile when the entity has sustained losses, uncertain turnaround plans, or expiring tax attributes.', 'Management incentives matter because a DTA can improve reported equity and earnings. The correct review therefore tests utilization evidence rather than accepting the balance as cash like value.'], 'formula-construction': ['The multiplication converts a deductible temporary difference into a tax amount using the enacted or substantively enacted tax rate expected on reversal.', 'Recognition is a separate gate. A measured benefit can still be unrecognized or reduced when future taxable profit is not probable.', 'The DTA must be reassessed at each reporting date. New losses, revised forecasts, tax law changes, and reversal timing can change the amount supportable.'], eli5: ['A deferred tax asset is like a coupon that can reduce a future tax bill. The coupon has value only if you will have a tax bill and the coupon has not expired.', 'A company cannot treat every tax coupon as wealth when it may not earn taxable profit.'], 'comparative-framework': ['A current tax asset concerns tax recoverable or payable for the current period. A deferred tax asset concerns future tax consequences of a difference that reverses later.', 'A DTA differs from goodwill or an operating asset because its value depends on taxable profit and tax law rather than direct cash generation.', 'The correct benchmark is evidence of utilization, not a universal percentage of assets or equity.'], interpretation: ['A DTA is strongest when supported by a history of taxable profit, identifiable reversing differences, and a credible forecast within the legal utilization period.', 'A large DTA alongside persistent losses is not automatically wrong, but it requires strong evidence such as reversing taxable differences or convincing tax planning.', 'The finance question is whether the balance reduces future cash tax or merely records a benefit that the business may never use.'], 'assumptions-limitations': ['Tax rates, carryforward periods, jurisdiction, and legal restrictions affect measurement and recoverability.', 'Forecast taxable profit is uncertain. The standard requires judgment but does not allow unsupported optimism to substitute for evidence.', 'A DTA does not measure liquidity. It can reduce future cash taxes while providing no immediate funding for debt service.'], 'case-resolution': ['Ind AS 12 resolves the concept by separating measurement from recognition. The mathematical benefit can be calculated, but the asset enters the accounts only when future utilization is supported.', 'For MBA finance analysis, the DTA is a bridge between accounting profit and future cash tax. Its value depends on the future business that must generate taxable income.'] },
    questions: [['Why is a DTA not the same as cash?', 'A DTA reduces future tax payments only when the entity generates taxable profit and can use the underlying difference or tax attribute. It does not provide immediate liquidity and can lose value if profit does not materialize or the legal period expires.'], ['What is the difference between a temporary and permanent difference?', 'A temporary difference reverses in a later period and creates a future tax consequence. A permanent difference never reverses for tax purposes, so it does not create deferred tax in the same way.'], ['Why do recent losses matter?', 'Recent losses are negative evidence about future taxable profit. They do not make a DTA impossible, but they raise the burden of proof and require evidence such as reversing taxable differences, reliable forecasts, or tax planning opportunities.'], ['How is a DTA measured?', 'The temporary difference or tax attribute is multiplied by the tax rate expected to apply when the benefit is realized, subject to the applicable tax rules. Measurement does not remove the separate recognition test.'], ['What causes a DTA to be reduced?', 'A DTA is reduced when expected taxable profit falls, tax law changes, carryforward rights expire, reversal timing changes, or evidence no longer supports utilization. The reduction records that the future tax benefit is no longer sufficiently supportable.'], ['Can tax planning support recognition?', 'Tax planning can support recognition when it is feasible, legally available, and creates taxable profit within the relevant period. It cannot be a vague intention to restructure without evidence that the plan can be executed.'], ['How should a lender interpret a large DTA?', 'A lender should treat it as conditional support for future tax cash flow, not as a liquid asset available for repayment. The lender should test utilization, expiry, jurisdiction, and the business forecast that creates taxable income.'], ['What is the central finance lesson?', 'Deferred tax accounting records future tax consequences, but economic value depends on future taxable profit. Recognition is therefore a forecast credibility question as much as an accounting calculation.']] },
};

Object.assign(referenceConfigs, {
  smart_beta: {
    title: 'The index is passive only until someone chooses the rules.',
    dek: 'Smart Beta turns an investment hypothesis into a transparent portfolio rule. The hard question is whether the portfolio captures the intended factor after constraints, turnover, and unintended exposures.',
    sources: [source('cfa_smart_beta_framework_2024', 'CFA Institute framework for smart beta and index based investment strategies', 'https://www.cfainstitute.org/about/press-room/2024/smart-beta-index-strategies-framework'), source('ftse_smart_beta_glossary', 'FTSE Russell glossary of equity index methodology terms', 'https://research.ftserussell.com/products/downloads/Glossary.pdf'), source('msci_factor_indexes', 'MSCI Factor Indexes', 'https://www.msci.com/indexes/factor-indexes/msci-factor-indexes')],
    mechanics: 'Define the factor, select the eligible universe, rank or score constituents, assign weights under explicit constraints, rebalance on a stated schedule, and evaluate realized exposure after costs and unintended concentration.',
    formula: { label: 'Rules based portfolio weight', lhsLatex: String.raw`w_i`, relationLatex: '=', rhsLatex: String.raw`f(\text{factor score}_i,\text{eligibility},\text{constraints})`, latex: String.raw`w_i = f(\text{factor score}_i,\text{eligibility},\text{constraints})`, sourceId: 'msci_factor_indexes' },
    terms: [['factor_exposure', 'Factor exposure', 'Portfolio construction', 'The portfolio’s systematic sensitivity to a defined source of common return or risk such as value, quality, momentum, size, yield, or low volatility.', 'It identifies the economic bet that the index is designed to deliver.', 'Assuming a factor label guarantees a stable exposure through time.'], ['factor_definition', 'Factor definition', 'Portfolio construction', 'The measurable signal or combination of signals used to classify securities for a targeted investment characteristic.', 'It determines what the strategy actually buys rather than what the marketing label suggests.', 'Ignoring the difference between a theoretical factor and its implementable proxy.'], ['weighting_scheme', 'Weighting scheme', 'Portfolio construction', 'The rule that converts eligibility and factor scores into portfolio weights subject to diversification and investability constraints.', 'It determines concentration, turnover, sector tilts, and the amount of factor exposure retained.', 'Treating equal weight and score weight as economically interchangeable.'], ['rebalancing', 'Rebalancing', 'Implementation', 'The scheduled process of updating constituents and weights so the portfolio continues to follow its stated methodology.', 'It is the mechanism through which the strategy maintains or loses its intended exposure.', 'Ignoring trading costs and stale signals between rebalances.'], ['tracking_error', 'Tracking error', 'Portfolio risk', 'The volatility of the return difference between a strategy and its parent benchmark.', 'It measures the implementation cost of departing from market capitalization weighting.', 'Calling positive active return proof of skill or factor persistence.']],
    governing: 'How does a rules based portfolio turn a factor hypothesis into an investable index, and which implementation choices determine whether the observed return is factor exposure or unintended risk?',
    paragraphs: { 'case-context': ['The CFA Institute framework and index provider methodologies make Smart Beta a structural topic. There is no single corporate event that defines it. The relevant artifact is the rulebook that turns a factor idea into a portfolio that can actually be bought, rebalanced, and compared.', 'The methodology is the product. Its definitions, constraints, rebalance schedule, and data choices determine the exposure investors receive.'], 'conceptual-foundation': ['Smart Beta departs from market capitalization weighting through transparent rules intended to capture a factor, reduce a risk, or improve diversification. It is passive in implementation only after active choices have defined the rule.', 'The factor is not the portfolio. The portfolio is the factor signal after eligibility screens, constraints, liquidity, sector limits, turnover controls, and rebalancing.', 'A strategy can carry the right name and the wrong exposure. Professional evaluation therefore examines realized characteristics, not the label alone.'], 'economic-logic': ['The economic claim is that a systematic characteristic explains a persistent return or risk pattern. That claim can fail when the factor is crowded, arbitraged, mismeasured, or overwhelmed by implementation costs.', 'Weighting choices create economic consequences. A score weighted portfolio can concentrate in a small number of securities, while a constrained portfolio can preserve diversification by weakening the pure factor exposure.', 'Rebalancing converts a static research signal into trading. Turnover, spreads, taxes, market impact, and capacity determine whether a backtested premium survives in practice.'], 'formula-construction': ['The weight function is deliberately abstract because different providers use different scoring, normalization, and constraint rules. The discipline lies in making every choice explicit.', 'A factor methodology must define its universe, data date, missing data treatment, eligibility rules, weighting, rebalance timing, and corporate action treatment.', 'The final output is not a score. It is an investable set of positions whose risk and return must be measured against the parent benchmark.'], eli5: ['Smart Beta is a shopping list for a portfolio. Instead of buying companies only because they are large, the list uses a rule such as cheaper, less volatile, higher quality, or stronger momentum.', 'The rule can still produce an expensive and risky shopping list if the selection and weighting choices are poor.'], 'comparative-framework': ['Market capitalization weighting follows market size. Smart Beta follows an explicit alternative rule. Active management allows discretion that can change security selection and weights outside a fixed methodology.', 'A factor index is transparent, but transparency does not guarantee that the factor premium exists, remains independent, or survives costs.', 'The correct comparison is the parent benchmark plus a risk decomposition. Return alone cannot show whether the strategy delivered the intended exposure.'], interpretation: ['Interpret Smart Beta as a portfolio construction decision. Ask which factor is targeted, how it is measured, how strongly it appears in the holdings, and what risks the constraints introduce.', 'A strategy can outperform because it captured the factor, because it took a sector tilt, because it carried more market risk, or because of a temporary regime. Attribution separates these explanations.', 'Tracking error is not a defect by itself. It is the price of departing from the parent benchmark and must be justified by the intended exposure.'], 'assumptions-limitations': ['Factor definitions are proxies. Book to price, earnings quality, volatility, and momentum can change meaning across markets and accounting regimes.', 'Backtests are vulnerable to look ahead bias, survivorship bias, data mining, and unrealistic turnover assumptions.', 'A transparent rule can become crowded. Capacity, liquidity, and trading costs can reduce realized return even when the academic signal remains valid.'], 'case-resolution': ['The governing methodologies show that Smart Beta is not a magic middle category between active and passive investing. It is a rules based implementation of active design choices.', 'For MBA finance analysis, the correct question is whether the rule delivers a compensated exposure after costs and unintended risks, not whether the index carries a fashionable label.'] },
    questions: [['Why is Smart Beta not purely passive in design?', 'The portfolio can be rules based and mechanically implemented, but the factor definition, universe, weighting, constraints, and rebalance schedule are active design choices. The implementation is systematic after those choices have been made.'], ['What is a factor?', 'A factor is a measurable source of common return or risk that the portfolio seeks to capture. The factor label is useful only when the methodology defines a consistent investable proxy and the realized holdings show the intended exposure.'], ['Why do weighting rules matter?', 'Weighting rules determine concentration, sector exposure, turnover, and how much factor signal survives diversification constraints. Two portfolios using the same factor can therefore have materially different risk and performance.'], ['How can Smart Beta generate tracking error?', 'Departing from market capitalization weights changes portfolio holdings and exposures. The resulting return difference against the parent benchmark is tracking error, which reflects both the intended factor bet and unintended deviations.'], ['Why is rebalancing economically important?', 'Rebalancing updates stale signals and restores the methodology, but it also creates trading costs, market impact, tax effects, and capacity constraints. The rebalance is therefore part of the strategy’s economics.'], ['How can a factor strategy be mistaken for active skill?', 'A strategy may outperform because it held a factor, a sector, a country, a size profile, or a market beta different from the benchmark. Attribution is required before the return can be called factor exposure or manager skill.'], ['What makes a Smart Beta backtest unreliable?', 'Look ahead bias, survivorship bias, data mining, unrealistic transaction costs, and unavailable historical data can make a backtest look stronger than a live implementation. The methodology and data history must be auditable.'], ['What is the central finance lesson?', 'Investment performance is produced by a chain of design and implementation choices. A factor hypothesis becomes an investment result only after it survives measurement, constraints, trading, and benchmark comparison.']],
  },
  deferred_tax_liability: {
    title: 'The tax bill can arrive in the accounts before it arrives in cash.',
    dek: 'Ind AS 12 records the future tax consequence of temporary differences, so current accounting profit cannot be read without understanding how carrying amounts will be recovered or settled.',
    sources: [source('icai_ind_as_12_material', 'ICAI Educational Material on Ind AS 12, Income Taxes', 'https://www.icai.org/post/educational-material-on-indas-12-income-taxes'), source('icai_ind_as_12_pdf', 'ICAI Educational Material on Ind AS 12, Income Taxes PDF', 'https://kb.icai.org/pdfs/PDFFile664ae4ef5c4c05.26743208.pdf')],
    mechanics: 'Identify taxable temporary differences between carrying amounts and tax bases, apply the expected tax rate on reversal, and trace when the future tax consequence becomes current tax.',
    formula: { label: 'Deferred tax liability', lhsLatex: String.raw`\text{DTL}`, relationLatex: '=', rhsLatex: String.raw`\text{taxable temporary difference} \times \text{applicable tax rate}`, latex: String.raw`\text{DTL} = \text{taxable temporary difference} \times \text{applicable tax rate}`, sourceId: 'icai_ind_as_12_material' },
    terms: [['taxable_difference', 'Taxable temporary difference', 'Tax accounting', 'A temporary difference that will create taxable amounts when the carrying amount of an asset or liability is recovered or settled.', 'It is the source of a future tax obligation even when no current tax is payable.', 'Treating the liability as a current cash claim.'], ['carrying_amount', 'Carrying amount', 'Financial reporting', 'The amount at which an asset or liability is recognized in the statement of financial position after applicable measurement adjustments.', 'It is compared with the tax base to identify temporary differences.', 'Using historical cost when the reported carrying amount has changed.'], ['tax_base', 'Tax base', 'Tax accounting', 'The amount attributed to an asset or liability for tax purposes that determines future taxable or deductible amounts.', 'It explains the timing mismatch between accounting recovery and tax recovery.', 'Assuming the tax base equals the accounting carrying amount.'], ['reversal', 'Reversal', 'Tax timing', 'The future period in which a temporary difference unwinds through recovery of an asset or settlement of a liability.', 'It connects deferred tax to future current tax and cash tax timing.', 'Recording a DTL without identifying how it reverses.'], ['enacted_rate', 'Applicable tax rate', 'Measurement', 'The tax rate expected to apply when the temporary difference reverses under enacted or substantively enacted tax law.', 'It determines the measured future tax consequence.', 'Using a headline rate that will not apply in the relevant jurisdiction or period.']],
    governing: 'Why can an entity report a tax liability before the related cash tax is payable, and how does the temporary difference reverse?',
    paragraphs: { 'case-context': ['Ind AS 12 begins with a balance sheet comparison. The carrying amount records accounting measurement, while the tax base records the tax consequence that will arise when the asset is recovered or the liability is settled.', 'A DTL is therefore a timing signal. It says that accounting recognition has moved ahead of tax recognition or that tax deductions will occur earlier than accounting expense.'], 'conceptual-foundation': ['A taxable temporary difference creates future taxable amounts. The DTL recognizes that future tax consequence in the period in which the underlying difference is created, rather than waiting for the cash tax payment.', 'The liability is not the same as an invoice from the tax authority. It is a measurement of future tax arising from the recovery or settlement of a reported balance.', 'The reversal pattern is essential. Without knowing how the carrying amount will be recovered, the tax rate and timing cannot be interpreted properly.'], 'economic-logic': ['DTLs can arise when accounting depreciation, fair value measurement, or business combination accounting differs from tax treatment. The accounting profit can therefore differ from taxable profit even when the underlying economics are sound.', 'The liability protects users from treating accounting profit as fully distributable when part of the future economic benefit carries a tax consequence.', 'A DTL can reverse through use, sale, settlement, or changes in tax law. The economic effect depends on the recovery path, not merely the existence of the balance.'], 'formula-construction': ['The measurement starts with the temporary difference and applies the rate expected at reversal. The calculation is mechanical only after the carrying amount, tax base, recovery mode, and applicable rate are established.', 'A taxable difference is not a current liability because the timing of payment can be later. The DTL brings the future consequence into the current balance sheet.', 'The balance is reassessed when forecasts, tax rates, business plans, or recovery assumptions change.'], eli5: ['Accounting and tax can measure the same asset differently. The difference is like a tax bill waiting in the future because the tax rules will catch up later.', 'The company records the future consequence now even though the cash payment happens later.'], 'comparative-framework': ['Current tax payable concerns the current period’s taxable profit. A DTL concerns future tax arising from a temporary difference.', 'A DTL differs from debt because it is not normally a negotiated financing claim, but it still represents a future reduction in cash available to the business.', 'The correct comparison is the carrying amount with the tax base and the recovery pattern, not a simple comparison of tax expense with tax paid.'], interpretation: ['A DTL often signals that accounting recognition and tax recognition occur in different periods. It is not automatically a warning sign, but it is a reminder that reported profit contains future tax consequences.', 'The best interpretation traces the reversal. If the asset is sold, the tax consequence may differ from recovery through use. If a business combination created the difference, the DTL may affect purchase price allocation and future earnings.', 'The finance question is when the liability becomes current tax and how much cash tax will then be paid.'], 'assumptions-limitations': ['Tax base, enacted rates, jurisdiction, and recovery mode determine measurement.', 'A DTL is not a forecast of all future tax payments. It captures specified temporary differences under the accounting standard.', 'Changes in tax law or intended recovery can change the measured amount without changing the underlying asset immediately.'], 'case-resolution': ['Ind AS 12 resolves the timing problem by recording the future tax consequence when the temporary difference arises and tracing its reversal.', 'For MBA finance analysis, the DTL is a bridge between reported accounting value and future cash tax. It should be analyzed through the recovery path.'] },
    questions: [['Why is a DTL recorded before cash tax is paid?', 'The DTL records the future tax consequence of a temporary difference when the accounting carrying amount and tax base diverge. Cash tax may be paid later, but the balance sheet already contains an economic claim that will create taxable amounts on recovery or settlement.'], ['What is a temporary difference?', 'It is the difference between the accounting carrying amount and the tax base of an asset or liability. It is temporary because it reverses in a later period and changes future taxable or deductible profit.'], ['How is a DTL measured?', 'The taxable temporary difference is multiplied by the tax rate expected to apply when it reverses. The measurement requires the recovery mode, jurisdiction, tax base, and enacted or substantively enacted rate to be identified correctly.'], ['Why does recovery mode matter?', 'Recovering an asset through use can produce a different tax consequence from recovering it through sale. The expected path affects the tax rate, timing, and amount of future taxable profit associated with the difference.'], ['Is a DTL a debt obligation?', 'A DTL is a future tax consequence rather than a financing contract, so it is not equivalent to debt. It nevertheless matters for cash flow analysis because reversal can reduce cash available after the underlying asset or liability is recovered or settled.'], ['Can a DTL increase while cash tax falls?', 'Yes. Accounting measurement can create a larger taxable temporary difference even while current taxable profit or cash tax declines. The DTL captures future reversal rather than the current tax payment alone.'], ['How should a DTL affect valuation?', 'The valuation treatment depends on the source, expected reversal, and whether the liability is likely to become a cash tax burden. It should not be added mechanically to debt without understanding its recovery path.'], ['What is the central finance lesson?', 'Accounting profit and taxable profit follow different measurement rules. Deferred tax makes the future consequence visible so that current reported value is not interpreted without its tax timing.']],
  },
  basel_iii: {
    title: 'Bank resilience is a system of constraints, not a single ratio.',
    dek: 'Basel III converts the fragility of banking into linked requirements for capital quality, risk weighted assets, leverage, liquidity, and loss absorption.',
    sources: [source('bis_basel_iii_framework', 'Basel III international regulatory framework for banks', 'https://www.bis.org/bcbs/basel3.htm'), source('rbi_basel_iii_2025', 'RBI Master Circular: Basel III Capital Regulations, 2025', 'https://www.rbi.org.in/Scripts/BS_ViewMasterCirculars.aspx?Id=12815')],
    mechanics: 'Map exposures into risk weighted assets, measure eligible capital by quality layer, test the leverage constraint, and evaluate liquidity and loss absorbency under the applicable regulatory framework.',
    formula: { label: 'Basel capital architecture', lhsLatex: String.raw`\text{Capital strength}`, relationLatex: '=', rhsLatex: String.raw`\text{capital quality} + \text{risk sensitivity} + \text{leverage discipline} + \text{liquidity resilience}`, latex: String.raw`\text{Capital strength} = \text{capital quality} + \text{risk sensitivity} + \text{leverage discipline} + \text{liquidity resilience}`, sourceId: 'bis_basel_iii_framework' },
    terms: [['cet1', 'Common Equity Tier 1', 'Bank capital', 'The highest quality form of bank capital, primarily common equity and retained earnings after regulatory adjustments.', 'It is the first layer available to absorb losses while the bank remains a going concern.', 'Treating all regulatory capital as equally loss absorbing.'], ['rwa', 'Risk weighted assets', 'Prudential measurement', 'Bank exposures adjusted by regulatory risk weights or approved models to represent the capital required for measured risk.', 'It links the capital requirement to the risk profile of assets rather than their accounting total alone.', 'Assuming a larger balance sheet always means proportionally larger RWA.'], ['leverage_ratio', 'Leverage ratio', 'Prudential constraint', 'A non risk weighted capital measure that compares qualifying capital with a broad exposure measure.', 'It limits balance sheet expansion when risk weights understate or fail to capture risk.', 'Treating a strong risk based ratio as proof that leverage is safe.'], ['lcr', 'Liquidity Coverage Ratio', 'Liquidity regulation', 'A liquidity requirement comparing high quality liquid assets with expected net cash outflows over the specified stress horizon.', 'It addresses funding survival rather than solvency alone.', 'Using capital adequacy as a substitute for liquidity analysis.'], ['nsfr', 'Net Stable Funding Ratio', 'Liquidity regulation', 'A structural funding measure comparing available stable funding with required stable funding over a longer horizon.', 'It limits maturity transformation financed by unstable funding.', 'Ignoring funding tenor because current liquidity appears adequate.']],
    governing: 'How does Basel III convert bank risk into capital, leverage, and liquidity constraints?',
    paragraphs: { 'case-context': ['Basel III is the governing architecture created for a banking system in which solvency, funding, and confidence can fail together. BIS sets the international framework and RBI implements the relevant prudential requirements for Indian banks.', 'The framework is intentionally multi dimensional. A bank can report strong accounting equity and still be vulnerable if its risk weighted assets, leverage, funding, or liquid asset buffer are misaligned.'], 'conceptual-foundation': ['Capital protects depositors and creditors by absorbing losses. Risk weights attempt to make the amount of capital responsive to the risk of exposures, while leverage limits the total balance sheet regardless of modeled risk.', 'Liquidity requirements address a different failure path. A solvent bank can fail if it cannot meet withdrawals, collateral calls, or maturing funding when confidence disappears.', 'Basel III is therefore a system of constraints. Its strength lies in the interaction between capital quality, risk measurement, leverage, liquidity, buffers, and supervisory judgment.'], 'economic-logic': ['Banks earn returns by transforming funding into credit and securities. That transformation creates maturity, credit, market, and concentration risk.', 'Higher capital reduces the probability that losses exhaust creditor protection, but it can also reduce return on equity if asset returns do not rise. Regulation therefore balances resilience with intermediation incentives.', 'Liquidity rules force banks to hold or fund assets in ways that remain resilient during stress. They do not make an institution immune to panic, but they increase the time available for corrective action.'], 'formula-construction': ['RWA is a prudential transformation, not an accounting total. The assigned risk depends on exposure class, collateral, counterparty, maturity, and the approved regulatory approach.', 'Capital ratios test eligible capital against RWA. The leverage ratio tests capital against a broader exposure measure, creating a backstop when risk weights are too optimistic.', 'Liquidity ratios test different horizons. Short stress survival and structural funding stability are related but not interchangeable.'], eli5: ['A bank uses borrowed money to make loans and buy assets. Basel III makes the bank keep a loss cushion, limits how much it can stretch the balance sheet, and requires enough liquid resources to survive withdrawals.', 'One cushion cannot solve every problem. Capital handles losses, while liquidity handles payment pressure.'], 'comparative-framework': ['Capital adequacy measures solvency capacity. The leverage ratio limits total exposure. LCR measures short horizon liquidity. NSFR measures structural funding stability.', 'Accounting equity and regulatory capital are not identical because regulators adjust capital for loss absorbency, deductions, and prudential treatment.', 'The correct benchmark is the applicable regulatory requirement plus management buffers, peer positioning, asset quality, and stress results.'], interpretation: ['A strong ratio is meaningful only after checking capital quality, RWA composition, leverage, funding concentration, encumbrance, and liquidity buffer quality.', 'The most useful question is which constraint binds first under stress. A bank can be above minimum capital and still face a liquidity event, or remain liquid while losses erode capital.', 'Basel III should therefore be read as a risk transmission framework rather than a compliance scorecard.'], 'assumptions-limitations': ['Risk weights are models or regulatory assignments, not perfect measures of economic risk.', 'High quality liquid assets can lose value or become encumbered, and funding assumptions can fail when confidence changes.', 'Minimum ratios are floors. Supervisory buffers, stress scenarios, governance, and market access determine practical resilience.'], 'case-resolution': ['Basel III resolves the post crisis problem by placing multiple constraints around the bank’s risk taking and funding model.', 'For MBA finance analysis, the durable lesson is that bank strength is a system property. Capital, leverage, liquidity, and asset quality must be read together.'] },
    questions: [['Why does Basel III use both risk based capital and a leverage ratio?', 'Risk based capital makes the requirement sensitive to the measured risk of exposures, while the leverage ratio provides a simpler backstop against excessive balance sheet expansion. Together they reduce reliance on any single risk measurement method.'], ['Why is capital quality important?', 'Capital quality determines how quickly and reliably a bank can absorb losses. Common equity is generally more loss absorbing than instruments that depend on conversion, coupons, or contractual features during stress.'], ['Why can a solvent bank fail?', 'Solvency does not guarantee immediate payment capacity. A bank can have assets exceeding liabilities but still fail when depositors or wholesale funders demand cash faster than assets can be sold or funded.'], ['What does RWA do?', 'RWA converts different exposures into a regulatory denominator that reflects prescribed or modeled risk. It makes the capital requirement responsive to credit, market, and operational risk rather than the accounting size of assets alone.'], ['How are LCR and NSFR different?', 'LCR addresses short horizon stress cash outflows using high quality liquid assets. NSFR addresses structural funding stability over a longer horizon. A bank can satisfy one and still have a weakness in the other.'], ['Why are minimum ratios not enough?', 'Minimum ratios are regulatory floors, not a complete forecast of resilience. Asset quality, concentration, governance, collateral, market confidence, encumbrance, and supervisory buffers influence the point at which stress becomes a failure.'], ['How does Basel III affect bank strategy?', 'Capital and liquidity have economic costs. They influence pricing, product selection, balance sheet growth, funding mix, risk appetite, and the return available to shareholders. Regulation therefore changes business strategy, not only reporting.'], ['What is the central finance lesson?', 'Bank risk is multidimensional. A serious assessment connects loss absorption, risk measurement, leverage, funding stability, and liquidity into one view of how stress can travel through the institution.']],
  },
  capital_adequacy_ratio: {
    title: 'A bank’s capital buffer is only as meaningful as the risk denominator beneath it.',
    dek: 'The Capital Adequacy Ratio compares eligible regulatory capital with risk weighted assets, making the denominator as important as the numerator.',
    sources: [source('rbi_basel_iii_2025', 'RBI Master Circular: Basel III Capital Regulations, 2025', 'https://www.rbi.org.in/Scripts/BS_ViewMasterCirculars.aspx?Id=12815'), source('bis_basel_iii_framework', 'Basel III international regulatory framework for banks', 'https://www.bis.org/bcbs/basel3.htm')],
    mechanics: 'Identify eligible regulatory capital, assign exposures their prescribed risk weights, calculate risk weighted assets, and divide capital by the resulting denominator before comparing the ratio with the applicable requirement.',
    formula: { label: 'Capital Adequacy Ratio', lhsLatex: String.raw`\text{CAR}`, relationLatex: '=', rhsLatex: String.raw`\frac{\text{eligible regulatory capital}}{\text{risk weighted assets}}`, latex: String.raw`\text{CAR} = \frac{\text{eligible regulatory capital}}{\text{risk weighted assets}}`, sourceId: 'rbi_basel_iii_2025' },
    terms: [['regulatory_capital', 'Regulatory capital', 'Bank capital', 'Capital instruments and retained earnings recognized by prudential rules as available to absorb losses.', 'It defines the numerator that protects depositors and creditors.', 'Using total equity without regulatory deductions or quality distinctions.'], ['risk_weighted_assets', 'Risk weighted assets', 'Prudential measurement', 'Exposure amounts adjusted for regulatory risk weights to estimate the capital required for measured risk.', 'It determines how much capital the bank needs for a given asset mix.', 'Assuming book assets and RWA are the same denominator.'], ['cet1_ratio', 'CET1 ratio', 'Capital quality', 'Common Equity Tier 1 capital divided by risk weighted assets after regulatory adjustments.', 'It focuses on the most loss absorbing capital layer.', 'Reading total CAR as if it showed the quality of the buffer.'], ['capital_buffer', 'Capital buffer', 'Prudential management', 'Capital held above the minimum requirement to absorb stress losses and preserve operating flexibility.', 'It indicates practical headroom rather than mere compliance.', 'Treating the regulatory minimum as a comfortable target.'], ['risk_weight', 'Risk weight', 'Prudential measurement', 'A regulatory percentage or modeled factor applied to an exposure to determine its contribution to risk weighted assets.', 'It converts exposure composition into a capital requirement.', 'Assuming a low risk weight means no economic risk.']],
    governing: 'How much loss absorbing capital does a bank hold relative to the risk embedded in its assets?',
    paragraphs: { 'case-context': ['RBI’s Basel III capital regulations make CAR a bank specific prudential measure. It is not a generic solvency ratio for operating companies because the banking balance sheet is built from leveraged financial exposures.', 'The ratio looks simple. Its economic content lies in the construction of eligible capital and risk weighted assets.'], 'conceptual-foundation': ['CAR asks how much recognized loss absorbing capital supports the risk weighted asset base. It is a relative measure, so both the numerator and denominator can change without a new rupee of capital being raised.', 'A bank can increase CAR by retaining earnings, issuing capital, reducing risky exposures, improving collateral, or changing the mix of assets. The ratio therefore reflects capital policy and portfolio construction.', 'The ratio does not measure liquidity. It addresses the capacity to absorb losses, not the ability to meet an immediate cash withdrawal.'], 'economic-logic': ['Capital protects creditors because bank losses are absorbed by equity before depositors bear the loss. A thin buffer leaves less room for asset quality deterioration and can force a bank to shrink lending at the worst point in the cycle.', 'Risk weights translate exposure composition into required capital. A loan, sovereign security, derivative, and off balance sheet commitment can contribute differently to RWA even when their accounting values are similar.', 'The economic question is not whether CAR exceeds a floor. It is whether capital remains sufficient after credit migration, concentration, collateral haircuts, market losses, and stress in the relevant portfolio.'], 'formula-construction': ['The numerator starts with eligible regulatory capital and applies required deductions and quality classifications. The denominator starts with exposures and applies the prescribed risk treatment.', 'A higher ratio can result from stronger capital or lower RWA. The two sources have different strategic meanings and different implications for future growth.', 'The ratio must be read with CET1, leverage, asset quality, provisioning, concentration, and stress capital because a single aggregate number can hide a weak component.'], eli5: ['A bank has a pile of risky promises and a loss cushion. CAR asks how big the cushion is compared with the risk adjusted pile.', 'A bigger number is usually safer, but only if the cushion is real and the risk adjustment is sensible.'], 'comparative-framework': ['CAR is risk weighted. The leverage ratio is not risk weighted and therefore provides a different constraint.', 'CET1 focuses on the highest quality capital, while total CAR can include additional capital layers with different loss absorbing features.', 'The correct comparison is against the applicable requirement, the bank’s internal buffer, peer banks with similar portfolios, and stressed capital consumption.'], interpretation: ['A high CAR can support growth and market confidence, but it is not automatically conservative. The analyst must inspect the capital composition and the risk weights supporting the denominator.', 'A falling CAR can result from losses, rapid asset growth, higher risk weights, or distributions. The cause matters because the remedial action differs.', 'The most useful decision is whether the bank can continue lending through stress without breaching constraints or raising capital at an unfavorable time.'], 'assumptions-limitations': ['Risk weights can understate tail risk, model risk, concentration, and correlation changes.', 'Regulatory capital is not identical to common equity or economic capital.', 'The ratio is point in time. It must be paired with stress testing and forward capital planning.'], 'case-resolution': ['The RBI framework makes the ratio meaningful by defining capital eligibility and RWA construction. Without those definitions, CAR is only a fraction without economic content.', 'For MBA finance analysis, the denominator deserves as much scrutiny as the capital buffer. Growth can improve earnings while consuming capital faster than the ratio suggests.'] },
    questions: [['What does CAR measure?', 'CAR measures eligible regulatory capital relative to risk weighted assets. It indicates the amount of recognized loss absorbing capital supporting the bank’s regulatory measure of risk, not the bank’s immediate liquidity or market value.'], ['Why is RWA not equal to total assets?', 'Different exposures have different regulatory risk treatments. RWA adjusts the accounting exposure base for prescribed or modeled risk, so two banks with similar asset totals can have different capital requirements.'], ['How can CAR rise without raising capital?', 'CAR can rise when the bank retains earnings, reduces risk weighted exposures, improves collateral treatment, or changes the portfolio mix. A higher ratio from shrinking assets has a different strategic meaning from a higher ratio created by fresh equity.'], ['Why is CET1 important when total CAR is strong?', 'Total CAR includes more than the highest quality common equity layer. CET1 indicates the capital most immediately available to absorb losses while the bank remains a going concern, so quality matters as well as quantity.'], ['Does a high CAR prove that a bank is safe?', 'No. Risk weights can miss concentration, model risk, correlations, and tail losses. A complete assessment adds leverage, liquidity, asset quality, provisioning, governance, and stress capital analysis.'], ['How does CAR affect lending growth?', 'New lending can increase RWA and consume capital. A bank with limited headroom may have to retain earnings, raise capital, reduce distributions, reprice risk, or slow asset growth to preserve the ratio.'], ['What can cause CAR to fall?', 'CAR can fall because losses reduce capital, assets grow faster than capital, exposures migrate to higher risk weights, provisions increase, or distributions reduce retained earnings. Diagnosis requires decomposing numerator and denominator movement.'], ['What is the central finance lesson?', 'CAR is a ratio of regulatory definitions, not a raw accounting fraction. The meaning of the output depends on capital quality, RWA construction, headroom, and the stress losses the bank must withstand.']],
  },
});

function makeFallbackSpec(topic) {
  const topicResearch = topic.research ?? topic;
  const capturedEvidence = evidenceCatalog[topic.topic_id];
  const evidenceRows = capturedEvidence?.rows ?? [];
  const evidenceDocument = capturedEvidence?.documentTitle ?? topicResearch.candidate_anchors?.[0]?.sources?.[0]?.title ?? 'the governing source';
  const evidenceSummary = evidenceRows.slice(0, 3).map((row) => `${row.item}: ${row.value}`).join(' ');
  let c = referenceConfigs[topic.topic_id];
  if (!c) {
    const research = topic.research ?? topic;
    const sourceList = research.sources ?? research.candidate_anchors?.[0]?.sources ?? [];
    const name = topic.canonical_name;
    const questionText = research.governing_question_draft ?? `What economic decision does ${name} improve, and which assumption determines whether its output is useful?`;
    const mechanics = research.mechanics_stub ?? `Define the inputs, apply the stated mechanics, interpret the output, and test the condition that could invalidate the conclusion.`;
    const domain = topicResearch.domain_guardrail ?? `The concept applies only within the economic setting described by its governing source.`;
    const primary = `${name} is a ${topic.format === 'Reference' ? 'regulated or formally defined finance measure' : 'finance construct'} used to answer a specific decision question. Its meaning comes from the economic relationship in the inputs, not from the name of the output.`;
    const terms = [
      ['definition', name, 'Core definition', `${name} is the finance concept defined by the governing question and mechanics for this lesson.`, 'It establishes the scope of the calculation or decision.', 'Confusing the concept with a related ratio, assumption, or output.'],
      ['primary_input', 'Primary input', 'Mechanics', 'The measured quantity that enters the concept and changes its result.', 'It identifies which economic fact the concept is designed to expose.', 'Using a convenient proxy without testing whether it preserves the intended meaning.'],
      ['comparison_input', 'Comparison input', 'Mechanics', 'The reference quantity, benchmark, or adjustment against which the primary input is interpreted.', 'It gives the output scale and direction.', 'Treating the comparison input as neutral when its construction drives the result.'],
      ['decision_signal', 'Decision signal', 'Interpretation', 'The decision-relevant information extracted after the mechanics are applied.', 'It converts a reported number into an action or follow-up question.', 'Reading the output as a conclusion rather than a signal conditioned on assumptions.'],
      ['validity_condition', 'Validity condition', 'Limitations', 'The factual or methodological condition that must hold for the concept to retain its intended meaning.', 'It defines when the result can be used and when it must be qualified.', 'Applying a valid concept outside its economic domain.'],
    ];
    const p = {
      'case-context': [`${name} is anchored to ${evidenceDocument}. The source record supplies the real regulatory, market, or company context in which the concept is used. ${evidenceSummary}`, `The governing question is ${questionText}`],
      'conceptual-foundation': [primary, domain, `${name} isolates the relationship that the governing question makes decision-relevant: ${mechanics}`],
      'economic-logic': [`${name} exists because the decision maker needs to distinguish ${topicResearch.governing_question_draft ?? questionText} from a broader headline number. The construct makes that distinction observable.`, `The mechanism is economically useful only when each input represents the risk, timing, funding, or accounting quantity that the decision is meant to evaluate. ${evidenceRows[0]?.value ?? ''}`, `The first substantive challenge is therefore classification. A movement in the output is meaningful only when the underlying input changed for an economic reason rather than because of a reporting, benchmark, or scope change.`],
      'formula-construction': [`Begin with the mechanics stated in the research record: ${mechanics}`, `The source evidence identifies the fields that populate the build. ${evidenceRows.map((row) => `${row.item} supplies ${row.value}`).join(' ')}`, `Preserve units, timing, scope, and regulatory definitions before interpreting the result. A mathematically correct calculation with an inapplicable input is still economically wrong.`],
      eli5: [`${name} is a tool for answering one specific money question: ${questionText}`, `It works by separating the important inputs from the rest of the financial information. ${mechanics}`, `The result is useful only when the inputs mean what the concept assumes they mean.`],
      'comparative-framework': [`Compare the result with the governing standard, the relevant peer set, and the entity's own history when those comparison sets are economically comparable.`, `No universal threshold should be invented when the concept is sector, regime, horizon, or portfolio dependent.`, `A related measure can be useful only when it answers a different question rather than repeating the same output.`],
      interpretation: [`Interpret ${name} by tracing the result back to the input that moved, the assumption that made the relationship valid, and the decision that would change if the result were different.`, `A strong output can coexist with weak economics when the denominator, benchmark, timing, or classification masks the risk the concept was meant to expose.`, `The most useful conclusion states what the result supports and what evidence is still required.`],
      'assumptions-limitations': [`The concept depends on the source definitions, measurement period, comparability of inputs, and economic domain for which it was designed.`, `The result loses meaning when those conditions change or when a proxy replaces the underlying economic quantity.`, `A limitation is not a disclaimer. It identifies the exact condition under which the decision signal becomes unreliable.`],
      'case-resolution': [`${evidenceDocument} supplies the factual boundary for ${name}. The transferable lesson is the mechanism: ${mechanics}`, `Return to the case by testing whether the cited fields support the input definitions, the comparison set, and the decision implication. The case is evidence for the concept, not a substitute for understanding it.`],
    };
    c = {
      title: `${name} reveals the assumption beneath the number.`,
      dek: `${name} is useful when it isolates a decision-relevant relationship that ordinary reported figures leave implicit.`,
      sourceList,
      mechanics,
      formula: { label: name, lhsLatex: String.raw`\text{${name.replace(/[^A-Za-z0-9 ]/g, '')}}`, relationLatex: String.raw`\longrightarrow`, rhsLatex: String.raw`\text{inputs}\;\longrightarrow\;\text{decision signal}`, latex: String.raw`\text{${name.replace(/[^A-Za-z0-9 ]/g, '')}}\;\longrightarrow\;\text{inputs}\;\longrightarrow\;\text{decision signal}`, sourceId: sourceList[0]?.id ?? 'topic_source' },
      knowledgeMap: { whyItExists: p['conceptual-foundation'][1], informationIsolated: p['conceptual-foundation'][2], decisionEnabled: p['economic-logic'][0], validityAssumptions: p['assumptions-limitations'][0], criticalQuestion: questionText },
      paragraphs: p,
      governing: questionText,
      terms,
      coverage: [coverage('definition and scope', 'Conceptual Foundation', ['definition', 'primary_input']), coverage('mechanics and interpretation', 'Formula Construction', ['comparison_input', 'decision_signal']), coverage('validity boundary', 'Assumptions and Limitations', ['validity_condition'])],
      questions: [
        question(`Why does ${name} exist?`, `It exists because the ordinary reported information combines economic features that have different consequences for value, risk, timing, or funding. The concept separates those features before a finance decision is made.`),
        question(`What information does ${name} isolate?`, `It isolates the relationship identified in the governing question. The reader should be able to name the numerator or primary input, the comparison base, the direction of movement, and the economic signal produced.`),
        question(`What decision does ${name} inform?`, `The output informs a bounded decision such as comparison, pricing, funding, recognition, valuation, or escalation. It should never be presented as a verdict without naming the decision standard and time horizon.`),
        question(`Which input drives the result?`, `Decompose the output into its material inputs and test which one changed. An aggregate movement can conceal offsetting effects, a denominator change, or a classification choice that has more importance than the headline result.`),
        question(`What assumption makes the concept valid?`, `The concept requires comparable definitions, an appropriate entity or sector, a consistent measurement horizon, and inputs that represent the intended economic quantities. If one condition fails, the conclusion requires qualification.`),
        question(`What is the most common misuse?`, `The common misuse is transporting a valid measure into a different setting and retaining the same interpretation. A ratio, model, or rule carries the assumptions of its construction and cannot be detached from them.`),
        question(`How should the result be benchmarked?`, `Use the comparison set that matches the decision: the applicable standard, comparable institutions, a same-industry cohort, a same-vintage group, or the entity's own history. A benchmark is useful only when the underlying economics are comparable.`),
        question(`What would a sophisticated MBA finance student question next?`, `The next question is what evidence would reverse the conclusion. Identify the weakest input, the assumption most likely to break under stress, and the downstream decision that would change if that input were restated.`),
      ],
    };
  }
  const glossary = Object.fromEntries(c.terms.map(([id, term, group, formalDefinition, whyItMatters, commonExaminationError]) => [id, { term, definition: formalDefinition, location: `${group} analysis.`, financialInterpretation: whyItMatters, commonExaminationTrap: commonExaminationError }]));
  const spec = {
    title: c.title, dek: c.dek, sourceList: c.sources ?? c.sourceList, mechanics: c.mechanics,
    formula: { ...c.formula, glossary }, knowledgeMap: {
      whyItExists: c.paragraphs['conceptual-foundation'][0], informationIsolated: c.paragraphs['conceptual-foundation'][1], decisionEnabled: c.paragraphs['economic-logic'][0], validityAssumptions: `${c.paragraphs['assumptions-limitations'][0]} These conditions must be tested before the output is used in a decision.`, criticalQuestion: `Before accepting the output, ask: ${topicResearch.governing_question_draft ?? c.governing} Then identify the evidence that would falsify the conclusion.`,
    }, sections: { ...c.paragraphs }, governing: c.governing,
    definitions: c.terms.map(([id, term, group, formalDefinition, whyItMatters, commonExaminationError]) => definition(id, term, group, formalDefinition, whyItMatters, commonExaminationError)),
    coverage: [coverage('core mechanism', 'Conceptual Foundation', c.terms.slice(0, 2).map(([id]) => id)), coverage('decision implications', 'Interpretation', c.terms.slice(2, 4).map(([id]) => id)), coverage('critical boundary', 'Assumptions and Limitations', c.terms.slice(4).map(([id]) => id))],
    questions: c.questions.map((item) => Array.isArray(item) ? question(item[0], item[1]) : item),
  };
  spec.sections['governing-question'] = [c.governing];
  spec.sections['formula-construction'] = [...spec.sections['formula-construction'], c.mechanics];
  return spec;
}

const marginSourceList = [
  source('sebi_margin_trading_discussion', 'SEBI Discussion Paper on Margin Trading and Securities Lending', 'https://www.sebi.gov.in/sebi_data/attachdocs/1293184262250.pdf'),
  source('sebi_derivative_margin_reporting', 'SEBI Daily Reports for Trading and Settlement of Derivative Trades', 'https://www.sebi.gov.in/legal/circulars/jun-2000/daily-reports-for-trading-and-settlement-of-derivative-trades_17700.html'),
  source('nse_margin_collection_faq', 'NSE FAQs on Margin Collection and Reporting', 'https://www.nseindia.com/static/trade/members-faqs-margin-collection-and-reporting'),
];

function makeMarginSpec(topic) {
  const name = topic.canonical_name;
  const isMaintenance = topic.topic_id === 'maintenance_margin';
  const isCall = topic.topic_id === 'margin_call';
  const governing = isMaintenance
    ? 'What minimum equity must remain in a leveraged position before the collateral no longer provides the lender with the required buffer?'
    : isCall
      ? 'How much additional collateral is required when a leveraged position falls below its maintenance requirement, and why can liquidation follow?'
      : 'How does daily mark to market convert a change in contract value into a collateral movement between counterparties?';
  const mechanics = isMaintenance
    ? 'Maintenance margin is the minimum equity requirement expressed as a percentage of collateral market value. Equity equals collateral value less margin debt, so the requirement tightens as collateral falls or debt rises.'
    : isCall
      ? 'A margin call is the shortfall between required maintenance equity and current equity. If the shortfall is not met, the lender or clearing member can reduce exposure by liquidating collateral or closing positions.'
      : 'Variation margin is the cash or eligible collateral transferred to settle mark to market gains and losses. It changes with the contract value and settlement price rather than setting the initial capacity to open the position.';
  const formula = isMaintenance
    ? { label: 'Maintenance margin', lhsLatex: String.raw`\text{Maintenance margin}`, relationLatex: '=', rhsLatex: String.raw`\frac{\text{Collateral market value} - \text{Margin debt}}{\text{Collateral market value}}`, latex: String.raw`\text{Maintenance margin} = \frac{\text{Collateral market value} - \text{Margin debt}}{\text{Collateral market value}}`, sourceId: 'sebi_margin_trading_discussion' }
    : isCall
      ? { label: 'Margin call', lhsLatex: String.raw`\text{Margin call}`, relationLatex: '=', rhsLatex: String.raw`\max\left(0,\;\text{Required maintenance equity} - \text{Current equity}\right)`, latex: String.raw`\text{Margin call} = \max\left(0,\;\text{Required maintenance equity} - \text{Current equity}\right)`, sourceId: 'sebi_margin_trading_discussion' }
      : { label: 'Variation margin', lhsLatex: String.raw`\text{Variation margin}`, relationLatex: '=', rhsLatex: String.raw`\text{Settlement value at current mark} - \text{Settlement value at prior mark}`, latex: String.raw`\text{Variation margin} = \text{Settlement value at current mark} - \text{Settlement value at prior mark}`, sourceId: 'sebi_derivative_margin_reporting' };
  formula.glossary = {
    collateral: { term: 'Collateral market value', definition: 'The current market value assigned to securities or other eligible collateral supporting a leveraged exposure.', location: 'Margin account or collateral register.', financialInterpretation: 'It is the asset base against which the lender measures the remaining equity buffer.', commonExaminationTrap: 'Using the original purchase price after the collateral has fallen.' },
    debt: { term: 'Margin debt', definition: 'The amount financed by the lender against the collateral position.', location: 'Margin account and financing ledger.', financialInterpretation: 'Debt does not fall automatically when collateral value falls, so leverage increases during a decline.', commonExaminationTrap: 'Treating collateral value as if it were the borrower equity contribution.' },
    equity: { term: 'Current equity', definition: 'Collateral market value less the debt secured against that collateral at the measurement time.', location: 'Margin account.', financialInterpretation: 'Equity is the first loss absorbing buffer available to the lender before collateral liquidation becomes necessary.', commonExaminationTrap: 'Comparing debt with the original collateral value instead of current equity.' },
    requirement: { term: 'Maintenance requirement', definition: 'The minimum equity or collateral level that must be maintained after a leveraged position has been established.', location: 'Margin agreement, exchange rulebook, or clearing report.', financialInterpretation: 'The requirement is a risk control that limits the lender or clearing system exposure as market values change.', commonExaminationTrap: 'Confusing the maintenance requirement with the initial margin posted to open the position.' },
  };
  const rows = isCall
    ? 'SEBI published example: purchase value Rs 100; initial margin 50%; maintenance margin 25%; collateral value after a 40% decline Rs 60; debt Rs 50; current equity Rs 10; required equity Rs 15; margin call Rs 5.'
    : 'The governing source defines the required field sequence and settlement rule. A transaction or contract specific value must be captured from the applicable broker, clearing corporation, or exchange record before a numeric conclusion is issued.';
  const paragraphs = {
    'case-context': [`${name} is a collateral control, not a generic solvency ratio. The governing source distinguishes the amount required to establish a position from the buffer that must remain while the position is open.`, `The source record is useful because it makes the loss transmission explicit: ${rows}`],
    'governing-question': [governing],
    'conceptual-foundation': [`${name} exists because a leveraged position can lose value faster than the lender can recover principal. The rule converts changing market value into a required collateral or cash response.`, mechanics, 'The conclusion applies to margin financed securities or centrally or bilaterally margined positions. It does not describe the liquidity of an operating company balance sheet.'],
    'economic-logic': ['Leverage makes the borrower equity buffer absorb the first loss. A decline in collateral value therefore increases the lender or clearing member exposure even when the debt balance has not changed.', `The rule changes behavior before the loss becomes final. A deficit requires more collateral, cash settlement, position reduction, or liquidation, which limits the time during which an unsecured shortfall can grow.`, 'The critical assumption is realizability. The collateral must be saleable at a value close enough to the mark used by the rule for the required buffer to protect the lender.'],
    'formula-construction': [isMaintenance ? 'Read the threshold as current equity divided by current collateral value. Current equity is collateral market value less margin debt.' : isCall ? 'The shortfall compares required maintenance equity with current equity. A positive difference is the amount that must be posted or cured under the agreement.' : 'The settlement amount compares the current mark with the prior mark. The direction and amount depend on the contract position and the settlement convention.', isCall ? 'In the published SEBI example, current equity is Rs 60 less Rs 50, or Rs 10. Required maintenance equity is 25% of Rs 60, or Rs 15. The shortfall is therefore Rs 5.' : 'The inputs must be measured at the same mark, date, unit, and contract scope. A formula can be arithmetically correct while the collateral price, settlement price, or debt balance is stale.', 'The formula is a control threshold. It is not a forecast of the final loss and does not prove that liquidation will occur at the marked value.'],
    eli5: ['A lender lets someone control a position with borrowed money. The lender therefore watches the value of the collateral and asks whether enough of the borrower own money is still there to absorb a fall.', `If the buffer gets too small, ${name} requires more collateral or a position reduction. The rule protects the lender before the loss becomes unrecoverable.`],
    'comparative-framework': ['Initial margin limits the leverage permitted when a position is opened. Maintenance margin tests whether enough equity remains after market movement. Variation margin settles the change in marked value between counterparties.', 'A margin call is the operational response to a shortfall. Liquidation is the enforcement response when the shortfall is not cured or the agreement permits immediate closeout.', 'The correct comparison is the applicable exchange, clearing, broker, or contract rule. There is no universal maintenance percentage across all products and jurisdictions.'],
    interpretation: [`A ${name} result indicates whether the position remains inside its collateral control boundary. A breach is a funding and risk event, not proof that the underlying asset is worthless.`, 'The decision is whether to post collateral, reduce the position, renegotiate financing, or allow closeout under the governing agreement.', 'The next question is whether the mark, eligible collateral haircut, settlement timing, and liquidation convention remain valid under the stress being evaluated.'],
    'assumptions-limitations': ['The measure depends on a reliable mark, enforceable collateral rights, eligible collateral definitions, haircuts, settlement timing, and the lender or clearing members ability to act when the threshold is breached.', 'Liquidity gaps and price gaps can make realized liquidation proceeds lower than the mark used to calculate the requirement. A satisfied threshold does not eliminate gap risk, concentration risk, or operational failure.', 'The rule is position specific. It does not measure the borrowers total solvency, the credit quality of the collateral issuer, or the funding stability of the operating business.'],
    'case-resolution': [`The source framework resolves ${name} by tying the required response to current collateral value and contractual settlement rules rather than to the borrowers original contribution.`, 'For MBA finance analysis, the durable lesson is that leverage creates a path dependent funding obligation. A modest market move can become a liquidity crisis when the borrower cannot meet the collateral response.'],
  };
  const questions = [
    question(`Why does ${name} exist?`, `${name} exists because a leveraged position can transfer losses to a lender or clearing system unless current collateral and equity are monitored continuously.`),
    question('How is initial margin different from maintenance margin?', 'Initial margin is the amount required to establish the position. Maintenance margin is the minimum buffer that must remain after the position is open and its market value changes.'),
    question('What causes a margin call?', 'A margin call occurs when current equity or eligible collateral falls below the applicable maintenance requirement. The shortfall is measured using the governing mark, debt balance, collateral haircuts, and contract scope.'),
    question('Why can liquidation happen even when the position has not defaulted?', 'The collateral rule is preventive. The lender can reduce exposure when the contractual buffer is breached, before a final payment default occurs, because waiting can allow a market decline to consume the remaining equity.'),
    question('What does variation margin settle?', 'Variation margin settles the marked change in value of a margined contract between the current and prior settlement marks. It transfers cash or collateral as the position gains or loses value.'),
    question('Why is the mark important?', 'The mark determines collateral value, current equity, and the settlement amount. A stale, illiquid, or disputed mark can make the apparent buffer differ from the amount actually recoverable in liquidation.'),
    question('What is the most common examination error?', 'The common error is treating a maintenance breach as the same thing as an insolvency conclusion. It is a collateral and funding control event whose consequence depends on the agreement, the cure period, the collateral rights, and the market liquidity.'),
    question('What should a finance professional ask next?', 'The next question is whether the position can meet the required collateral response under a realistic price gap, haircut, settlement, and concentration stress, and what contractual action follows if it cannot.'),
  ];
  return {
    title: `${name} is the line between leverage and forced action.`,
    dek: `Margin rules turn a change in collateral or contract value into a funding response. The important question is not the original trade, but the buffer that remains when the mark moves.`,
    anchorDescription: `${name} is anchored to SEBI and NSE margin trading and derivatives settlement material, where the concept governs collateral, equity buffers, and settlement obligations.`,
    sourceList: marginSourceList,
    mechanics,
    formula,
    knowledgeMap: { whyItExists: paragraphs['conceptual-foundation'][0], informationIsolated: paragraphs['conceptual-foundation'][1], decisionEnabled: paragraphs.interpretation[1], validityAssumptions: paragraphs['assumptions-limitations'][0], criticalQuestion: paragraphs.interpretation[2] },
    sections: paragraphs,
    governing,
    definitions: [
      definition('initial-margin', 'Initial margin', 'Margin architecture', 'The collateral or equity required before a leveraged position is opened.', 'It sets the initial leverage and loss buffer.', 'Confusing the opening requirement with the amount that must remain after market movement.'),
      definition('maintenance-margin', 'Maintenance margin', 'Margin architecture', 'The minimum equity or collateral level that must remain after a leveraged position is established.', 'It creates a preventive control against lender or clearing exposure.', 'Treating the percentage as a universal rule across products.'),
      definition('margin-call', 'Margin call', 'Margin architecture', 'A demand for additional collateral or cash when the current position falls below its required margin level.', 'It is the operational response to a collateral shortfall.', 'Assuming a margin call is a final default.'),
      definition('variation-margin', 'Variation margin', 'Settlement', 'Cash or eligible collateral transferred to settle the change in a contract value at the required mark.', 'It prevents marked losses from remaining unpaid between settlement dates.', 'Treating it as the same thing as initial margin.'),
      definition('current-equity', 'Current equity', 'Collateral measurement', 'The current market value of pledged collateral less the debt or secured obligation against it.', 'It measures the loss absorbing buffer at the current mark.', 'Using original purchase value instead of current value.'),
      definition('liquidation', 'Liquidation', 'Enforcement', 'The sale or closeout of a position to reduce exposure after a contractual collateral breach or default condition.', 'It limits further loss but may crystallize a loss at an adverse market price.', 'Assuming liquidation occurs at the mark used in the margin calculation.'),
    ],
    coverage: [
      coverage('opening and maintenance requirements', 'Conceptual Foundation', ['initial-margin', 'maintenance-margin']),
      coverage('shortfall and settlement response', 'Formula Construction', ['margin-call', 'variation-margin']),
      coverage('collateral measurement and enforcement', 'Economic Logic', ['current-equity', 'liquidation']),
    ],
    questions,
  };
}

function makeOperatingLeverageSpec() {
  const sourceList = [source('ril_retail_2024_25', 'Reliance Industries Integrated Annual Report 2024-25, Retail business performance', 'https://www.ril.com/ar2024-25/retail.html')];
  const formula = {
    label: 'Degree of operating leverage',
    lhsLatex: String.raw`\text{DOL}`,
    relationLatex: '=',
    rhsLatex: String.raw`\frac{\%\;\text{change in operating profit}}{\%\;\text{change in revenue}}`,
    latex: String.raw`\text{DOL} = \frac{\%\;\text{change in operating profit}}{\%\;\text{change in revenue}}`,
    sourceId: 'ril_retail_2024_25',
    glossary: {
      revenue: { term: 'Revenue', definition: 'Income from goods or services provided to customers during the reporting period.', location: 'Income statement.', financialInterpretation: 'Revenue measures the scale of activity against which operating profit sensitivity is evaluated.', commonExaminationTrap: 'Treating revenue growth as operating leverage without examining the corresponding profit movement.' },
      operatingProfit: { term: 'Operating profit', definition: 'Profit generated by the operating activities before financing and tax effects, measured consistently across the periods compared.', location: 'Income statement and segment reporting.', financialInterpretation: 'It is the profit pool that responds to volume, price, mix, and the fixed and variable cost structure.', commonExaminationTrap: 'Using EBITDA as if it were EBIT without stating the proxy and depreciation assumption.' },
      fixedCosts: { term: 'Fixed costs', definition: 'Operating costs that do not change proportionally with short term revenue under the specified activity range.', location: 'Cost note, segment reporting, or management operating analysis.', financialInterpretation: 'Fixed costs create profit sensitivity because incremental revenue can carry a higher contribution after the fixed base is covered.', commonExaminationTrap: 'Assuming a cost is permanently fixed outside the relevant volume range.' },
      contribution: { term: 'Contribution margin', definition: 'Revenue remaining after variable operating costs and available to cover fixed costs and operating profit.', location: 'Management accounting analysis and segment profitability bridge.', financialInterpretation: 'Contribution explains why a given revenue change produces a larger or smaller operating profit change.', commonExaminationTrap: 'Inferring contribution margin from EBITDA growth without reconciling cost classification.' },
    },
  };
  const governing = 'When does a change in revenue produce a larger change in operating profit, and what does that sensitivity reveal about the cost structure?';
  const mechanics = 'Degree of operating leverage compares the percentage change in operating profit with the percentage change in revenue. A value above one indicates that operating profit is moving faster than revenue over the observed range, subject to consistent definitions and a stable operating boundary.';
  const paragraphs = {
    'case-context': ['Reliance Retail reported revenue from operations of Rs 273,131 crore in FY 2023-24 and Rs 291,043 crore in FY 2024-25. EBITDA increased from Rs 23,108 crore to Rs 25,094 crore over the same periods.', 'The figures create a useful finance question. Revenue increased by 6.6%, while EBITDA increased by 8.6%. The difference is a signal about operating sensitivity, not proof of a permanent cost structure.'],
    'governing-question': [governing],
    'conceptual-foundation': ['Operating leverage describes how the cost structure transmits a change in revenue into operating profit. It becomes visible when a business has costs that do not move in direct proportion to short term sales.', mechanics, 'The concept is about sensitivity around an observed operating point. It does not claim that the same relationship holds after a major capacity, pricing, mix, or cost base change.'],
    'economic-logic': ['A business with a meaningful fixed operating base can keep more of incremental contribution after that base is covered. Revenue growth can therefore produce faster profit growth, but a revenue decline can reverse the effect with equal force.', 'Scale, capacity utilization, pricing, product mix, and procurement can all change operating leverage. A higher observed degree may reflect genuine fixed cost absorption, temporary margin conditions, or a change in segment composition.', 'The decision implication is asymmetric. Operating leverage supports upside when demand grows, but it increases earnings volatility and credit risk when revenue weakens.'],
    'formula-construction': ['The numerator measures the percentage change in operating profit and the denominator measures the percentage change in revenue across the same periods and scope.', 'For Reliance Retail, EBITDA growth of 8.6% divided by revenue growth of 6.6% gives approximately 1.30x. EBITDA is used as the reported operating profit proxy in this illustration because the cited segment disclosure reports EBITDA; depreciation and amortization must be examined before calling the result EBIT based DOL.', 'The calculation is a sensitivity estimate, not a causal decomposition. A defensible explanation still requires the contribution margin, fixed cost base, and changes in mix or capacity.'],
    eli5: ['If sales rise a little but operating profit rises more, some costs did not rise with sales. The business is using its existing operating base more efficiently.', 'The same structure works in reverse. If sales fall, the costs that remain can make profit fall faster than revenue.'],
    'comparative-framework': ['Operating leverage concerns the relationship between revenue and operating profit. Financial leverage concerns the relationship between operating profit and earnings available to equity after interest. Combined leverage transmits revenue changes through both operating and financing costs.', 'A margin measures profitability at a point in time. Degree of operating leverage measures sensitivity between periods or around an operating point.', 'A universal benchmark does not exist. Compare businesses with similar asset intensity, cost classification, segment scope, capacity stage, and revenue mix.'],
    interpretation: ['The observed 1.30x result says that EBITDA moved approximately 1.30 times as fast as revenue over the two reported periods. It does not prove that every additional rupee of revenue will produce the same EBITDA response.', 'The result is useful for forecasting, downside analysis, lender review, and valuation because it identifies how much earnings may move when demand changes.', 'The next question is whether the movement came from fixed cost absorption, price and mix, one time cost changes, or a change in the reported segment boundary.'],
    'assumptions-limitations': ['The comparison requires consistent segment scope, revenue recognition, operating profit definition, reporting period, and cost classification. EBITDA is not interchangeable with EBIT and excludes depreciation that may be economically material in an asset intensive business.', 'Two period changes cannot identify a structural fixed cost percentage by themselves. A price increase, acquisition, store opening, mix shift, or temporary margin event can produce the same observed sensitivity.', 'The measure is local. As capacity, staffing, technology, rent, distribution, and procurement commitments change, the relevant operating leverage changes with them.'],
    'case-resolution': ['Reliance Retail provides a real two period example in which EBITDA grew faster than revenue. The evidence supports an observed sensitivity calculation, while the limitation prevents it from becoming a permanent forecast assumption.', 'The durable lesson is that operating leverage is a mechanism for translating demand risk into earnings risk. The finance decision requires the cost bridge behind the ratio, not the ratio alone.'],
  };
  return {
    title: 'Revenue grew. Profit moved faster.',
    dek: 'Reliance Retail’s FY 2024-25 results show how a modest change in revenue can produce a larger change in operating profit when the business absorbs its operating base.',
    anchorDescription: 'Reliance Retail’s official FY 2024-25 segment disclosure supplies two comparable periods of revenue and EBITDA for teaching observed operating leverage.',
    sourceList,
    mechanics,
    formula,
    knowledgeMap: { whyItExists: paragraphs['conceptual-foundation'][0], informationIsolated: paragraphs['conceptual-foundation'][1], decisionEnabled: paragraphs.interpretation[1], validityAssumptions: paragraphs['assumptions-limitations'][0], criticalQuestion: paragraphs.interpretation[2] },
    sections: paragraphs,
    governing,
    definitions: [
      definition('operating-leverage', 'Operating leverage', 'Cost structure', 'The sensitivity of operating profit to a change in revenue created by the relationship between fixed and variable operating costs.', 'It shows how demand changes can be amplified in operating earnings.', 'Treating a single period margin as a measure of operating leverage.'),
      definition('degree-of-operating-leverage', 'Degree of operating leverage', 'Sensitivity measure', 'The percentage change in operating profit divided by the percentage change in revenue over a defined comparable range.', 'It quantifies observed operating earnings sensitivity.', 'Treating the result as a universal constant outside the observed range.'),
      definition('fixed-costs', 'Fixed costs', 'Cost structure', 'Operating costs that do not vary proportionally with revenue over the relevant short term activity range.', 'They create the earnings amplification that operating leverage measures.', 'Assuming costs remain fixed after capacity or staffing changes.'),
      definition('contribution-margin', 'Contribution margin', 'Profit mechanics', 'Revenue remaining after variable operating costs and available to cover fixed costs and operating profit.', 'It explains the economic transmission from sales to operating profit.', 'Calling EBITDA margin a contribution margin without a variable cost bridge.'),
      definition('financial-leverage', 'Financial leverage', 'Capital structure', 'The sensitivity of equity earnings to operating profit created by fixed financing obligations such as interest.', 'It distinguishes operating risk from financing risk.', 'Confusing operating leverage with debt leverage.'),
      definition('proxy-measure', 'Proxy measure', 'Measurement discipline', 'A reported quantity used as an approximation for a target quantity when the exact field is not disclosed, with the difference stated explicitly.', 'It permits a transparent calculation without disguising the measurement limitation.', 'Presenting EBITDA as EBIT without a depreciation qualification.'),
    ],
    coverage: [
      coverage('cost structure and mechanism', 'Conceptual Foundation', ['operating-leverage', 'fixed-costs']),
      coverage('formula and measurement', 'Formula Construction', ['degree-of-operating-leverage', 'proxy-measure']),
      coverage('profit transmission and adjacent leverage', 'Economic Logic', ['contribution-margin', 'financial-leverage']),
    ],
    questions: [
      question('Why can operating profit grow faster than revenue?', 'Operating profit can grow faster when incremental revenue generates contribution after the existing fixed operating base is covered. Price, mix, productivity, and cost classification can also contribute, so the cost bridge must be examined before attributing the result only to fixed costs.'),
      question('What does a degree of operating leverage above one mean?', 'It means operating profit changed by a larger percentage than revenue over the measured range. It is a local sensitivity observation, not a permanent law of the business.'),
      question('Why is operating leverage a downside risk?', 'The same fixed operating base that magnifies profit growth when revenue rises continues to require funding when revenue falls. Operating profit can therefore decline faster than revenue during a demand shock.'),
      question('How is operating leverage different from financial leverage?', 'Operating leverage arises from fixed operating costs. Financial leverage arises from fixed financing costs such as interest. The first transmits revenue changes into operating profit; the second transmits operating profit changes into equity earnings.'),
      question('Why is EBITDA not automatically EBIT?', 'EBITDA excludes depreciation and amortization, while EBIT includes them. EBITDA can be a useful reported segment proxy when EBIT is unavailable, but the result must be qualified because depreciation may represent a real economic cost.'),
      question('Why can a two period DOL calculation mislead?', 'A price change, mix shift, acquisition, capacity expansion, store opening, restructuring, or temporary cost event can change profit sensitivity without changing the underlying long term fixed cost structure.'),
      question('What benchmark should be used?', 'Use comparable businesses with similar asset intensity, segment scope, revenue mix, capacity stage, and cost classification. No universal DOL threshold is meaningful across sectors.'),
      question('What evidence would reverse the conclusion?', 'A segment reconciliation showing that the periods are not comparable, that EBITDA growth came from a one time item, or that revenue and EBITDA changed because of a scope or classification change would weaken the operating leverage inference.'),
    ],
  };
}

function makeStagflationSpec() {
  const sourceList = [source('rbi_seven_ages_monetary_policy', 'RBI, Seven Ages of India’s Monetary Policy', 'https://www.rbi.org.in/commonman/Upload/English/speeches/PDFs/EMC24012020.PDF')];
  const governing = 'How can an economy experience weak growth and high inflation at the same time, and what does that combination do to monetary policy?';
  const mechanics = 'Stagflation is diagnosed when economic slack or weak real growth coexists with persistently elevated inflation. The mechanism is usually a supply or cost shock, an adverse expectations response, or a policy constraint that prevents demand management from resolving both conditions at once.';
  const formula = {
    label: 'Stagflation diagnosis',
    lhsLatex: String.raw`\text{Stagflation}`,
    relationLatex: '\Longleftrightarrow',
    rhsLatex: String.raw`\text{weak real growth or slack} \;+\; \text{elevated inflation}`,
    latex: String.raw`\text{Stagflation} \Longleftrightarrow \text{weak real growth or slack} \;+\; \text{elevated inflation}`,
    sourceId: 'rbi_seven_ages_monetary_policy',
    glossary: {
      realGrowth: { term: 'Real growth', definition: 'The change in output after removing the effect of price changes.', location: 'National accounts and macroeconomic indicators.', financialInterpretation: 'It measures expansion in economic quantities rather than expansion caused only by higher prices.', commonExaminationTrap: 'Using nominal GDP growth as evidence that real economic activity is strong.' },
      inflation: { term: 'Inflation', definition: 'A sustained increase in the general price level that reduces the purchasing power of money.', location: 'CPI, WPI, GDP deflator, and other price indices.', financialInterpretation: 'The index and basket chosen determine which price pressure the measure captures.', commonExaminationTrap: 'Calling a single relative price increase economy wide inflation.' },
      supplyShock: { term: 'Supply shock', definition: 'A sudden change in production capacity, input cost, or availability that shifts aggregate supply.', location: 'Commodity, production, trade, and macroeconomic data.', financialInterpretation: 'A negative supply shock can raise prices while reducing output, creating the central stagflation tension.', commonExaminationTrap: 'Assuming all inflation is caused by excess demand.' },
      expectations: { term: 'Inflation expectations', definition: 'Beliefs held by households, firms, and markets about future price growth.', location: 'Surveys, market prices, wage negotiations, and policy analysis.', financialInterpretation: 'Expectations can make a temporary price shock persistent through wages, contracts, and pricing decisions.', commonExaminationTrap: 'Treating expectations as a forecast that has no causal effect on current behavior.' },
    },
  };
  const paragraphs = {
    'case-context': ['RBI’s monetary policy history records a period in which average growth hovered around 4.0% while WPI based inflation was around 8.8%. The figures make the policy problem concrete: output was not expanding strongly while prices were rising quickly.', 'The case is not a universal threshold. It is evidence of the joint condition that makes stagflation difficult to address.'],
    'governing-question': [governing],
    'conceptual-foundation': ['Stagflation is a macroeconomic state in which inflation and weak real activity coexist. It matters because policies that reduce inflation can further weaken demand while policies that support demand can intensify price pressure.', mechanics, 'The condition is about the interaction of output and prices, not about one number crossing a universal line.'],
    'economic-logic': ['A negative supply shock raises the cost of producing goods and services. Firms pass part of the shock into prices while reducing output, employment, or investment because the same production process has become less profitable.', 'Expectations can transmit a temporary shock into a persistent one. Workers seek compensation for expected price growth, firms adjust prices in anticipation of higher costs, and contracts embed the new inflation rate.', 'The central bank faces a tradeoff between stabilizing prices and protecting output. The credibility of the policy framework becomes part of the economic mechanism.'],
    'formula-construction': ['The expression is a diagnostic conjunction rather than a ratio. The analyst must establish the real activity measure, the price index, the period, and the persistence of the movement before using the term.', 'RBI’s cited historical figures pair average growth around 4.0% with WPI inflation around 8.8%. They demonstrate the joint condition but do not define a permanent cutoff for every economy.', 'A change in the price index, base period, or real growth measure can change the diagnosis. Measurement discipline comes before policy interpretation.'],
    eli5: ['An economy can have two problems at once: businesses and households are not seeing strong real growth, while the prices they pay are rising quickly.', 'That combination is hard because pushing demand up can worsen prices, while pushing prices down can weaken growth further.'],
    'comparative-framework': ['Demand inflation occurs when spending grows faster than productive capacity. Stagflation is different because weak activity and high inflation coexist, often after a supply shock or expectations shift.', 'Deflation is a sustained fall in the general price level. Recession is a contraction or pronounced slowdown in activity. Neither term alone implies high inflation.', 'No universal stagflation benchmark exists. Use the economy’s own history, the central bank’s framework, and a consistent real activity and price measure.'],
    interpretation: ['The RBI case demonstrates why a single inflation number cannot determine the policy stance. The authority must assess output, supply conditions, expectations, wages, financial conditions, and the persistence of the price shock.', 'The decision is whether the shock is transitory, becoming embedded, or being amplified by demand and expectations. Each diagnosis implies a different policy risk.', 'A sophisticated reader should ask which component of inflation is broadening and whether real activity weakness is supply driven or demand driven.'],
    'assumptions-limitations': ['The diagnosis depends on the selected price index, real growth measure, time horizon, and evidence that weak activity and high inflation are persistent rather than one month anomalies.', 'A country can experience sector specific price pressure without economy wide stagflation. Broadness and persistence must be established.', 'Monetary policy cannot directly create energy, food, or production capacity. It can influence demand and expectations, while fiscal, supply, and structural policy address other parts of the shock.'],
    'case-resolution': ['The RBI record provides a real historical illustration of the joint condition, while the policy conclusion remains conditional on the source of the inflation and the persistence of weak activity.', 'The durable lesson is that macroeconomic diagnosis is a mechanism problem. The same inflation number can require different action when the output, supply, and expectations context changes.'],
  };
  return {
    title: 'Prices rose while growth lost its footing.',
    dek: 'RBI’s monetary policy history shows why inflation and weak real activity can coexist, forcing policymakers to manage a conflict that ordinary demand analysis misses.',
    anchorDescription: 'RBI monetary policy history supplies a macroeconomic case in which average growth around 4.0% coincided with WPI inflation around 8.8%.',
    sourceList,
    mechanics,
    formula,
    knowledgeMap: { whyItExists: paragraphs['conceptual-foundation'][0], informationIsolated: paragraphs['conceptual-foundation'][1], decisionEnabled: paragraphs.interpretation[1], validityAssumptions: paragraphs['assumptions-limitations'][0], criticalQuestion: paragraphs.interpretation[2] },
    sections: paragraphs,
    governing,
    definitions: [
      definition('stagflation', 'Stagflation', 'Macroeconomic condition', 'A period in which elevated inflation coexists with weak real growth, economic slack, or stagnating output.', 'It identifies a policy conflict that cannot be diagnosed from inflation or growth alone.', 'Using the term for any temporary price increase.'),
      definition('real-growth', 'Real growth', 'Macroeconomic measurement', 'Growth in output after removing the effect of price changes.', 'It distinguishes genuine expansion from nominal growth caused by inflation.', 'Using nominal GDP growth without adjusting for prices.'),
      definition('supply-shock', 'Supply shock', 'Macroeconomic mechanism', 'A sudden change in production capacity or input costs that shifts the economy’s aggregate supply.', 'It explains how prices can rise while output weakens.', 'Attributing a supply driven inflation episode only to excess demand.'),
      definition('inflation-expectations', 'Inflation expectations', 'Policy transmission', 'Beliefs about future price growth that influence current wages, contracts, pricing, spending, and investment.', 'Expectations can determine whether a supply shock remains temporary or becomes persistent.', 'Treating expectations as passive forecasts rather than behavior affecting current inflation.'),
      definition('policy-credibility', 'Policy credibility', 'Policy transmission', 'The extent to which households, firms, and markets believe a policy authority will maintain its stated inflation and economic objectives.', 'Credibility influences expectations, wage setting, pricing, and the cost of restoring price stability.', 'Assuming a policy announcement changes expectations without examining the authority’s record and operating framework.'),
    ],
    coverage: [
      coverage('condition and measurement', 'Conceptual Foundation', ['stagflation', 'real-growth']),
      coverage('supply mechanism and policy conflict', 'Economic Logic', ['supply-shock']),
      coverage('persistence and expectations', 'Interpretation', ['inflation-expectations', 'policy-credibility']),
    ],
    questions: [
      question('What is stagflation?', 'Stagflation is the coexistence of elevated inflation and weak real growth or economic slack. It is difficult because policy that reduces demand can weaken output while policy that supports demand can intensify price pressure.'),
      question('Why can a supply shock create stagflation?', 'A negative supply shock raises production costs and reduces feasible output. Firms may raise prices while cutting production, employment, or investment, creating inflation and weaker real activity together.'),
      question('How are inflation expectations involved?', 'Expectations affect wage demands, contract pricing, inventory decisions, and markups. If a temporary shock changes expected future inflation, current behavior can make the price increase persist.'),
      question('Why is nominal GDP growth insufficient?', 'Nominal GDP combines quantity growth with price growth. An economy can show strong nominal growth while real output is weak if inflation accounts for much of the increase.'),
      question('Does every high inflation episode equal stagflation?', 'No. The diagnosis requires evidence of weak real activity or slack as well as elevated inflation, with attention to breadth, persistence, and measurement definitions.'),
      question('What policy conflict does stagflation create?', 'Tightening demand can reduce inflation but worsen output and employment, while easing demand can support activity but entrench prices. The appropriate response depends on the shock, expectations, and policy credibility.'),
      question('What benchmark should be used?', 'Use the country’s own historical data, a consistent real activity measure, the relevant price index, and the central bank’s policy framework. No universal inflation or growth cutoff defines stagflation in every economy.'),
      question('What should a finance student ask next?', 'Ask whether inflation is broad and persistent, whether output weakness is demand or supply driven, whether expectations are becoming unanchored, and which policy instrument can address the actual mechanism.'),
    ],
  };
}

function makeIpoSpec(topic) {
  const sourceList = [
    source('zomato_ipo_prospectus', 'Zomato Limited Prospectus dated July 19, 2021', 'https://www.sebi.gov.in/sebi_data/attachdocs/jul-2021/1626944616560.pdf'),
    source('zomato_basis_of_allotment', 'Zomato Limited Basis of Allotment public announcement', 'https://www.bseindia.com/corporates/download/363156/ipo_T5/D%204%20BoA_20210722161711.pdf'),
    source('zomato_bse_annual_report', 'Zomato Limited Annual Report 2021-22, IPO proceeds and listing', 'https://www.bseindia.com/bseplus/AnnualReport/543320/74160543320.pdf'),
    source('zomato_listing_report', 'Zomato IPO listing report, July 23, 2021', 'https://www.moneycontrol.com/news/business/ipo/zomato-ipo-listing-food-delivery-giant-crosses-rs-1-lakh-crore-m-cap-after-stellar-debut-with-nearly-53-premium-7210471.html', 2),
  ];
  const glossary = {
    freshShares: { term: 'Fresh issue', definition: 'New equity shares issued by the company, with the proceeds received by the issuer after issue expenses.', location: 'Prospectus offer summary and share capital note.', financialInterpretation: 'A fresh issue increases paid-in equity and supplies capital to the company.', commonExaminationTrap: 'Treating an offer for sale as company financing.' },
    offerForSale: { term: 'Offer for sale', definition: 'Existing shares sold by current shareholders to public investors without new cash entering the issuer.', location: 'Prospectus offer summary and selling shareholder disclosure.', financialInterpretation: 'An offer for sale changes ownership distribution and provides liquidity to selling holders, but it does not fund the issuer.', commonExaminationTrap: 'Adding offer for sale proceeds to the company cash balance.' },
    offerPrice: { term: 'Offer price', definition: 'The price per share paid by successful investors in the primary offering.', location: 'Prospectus cover page, price band, and basis of allotment.', financialInterpretation: 'It is the negotiated primary-market valuation reference before secondary-market trading begins.', commonExaminationTrap: 'Assuming the offer price is the company’s intrinsic value.' },
    freshProceeds: { term: 'Fresh issue proceeds', definition: 'Gross cash raised by the issuer through the sale of newly issued shares before offer expenses.', location: 'Prospectus objects of the issue and subsequent proceeds utilisation report.', financialInterpretation: 'The proceeds can fund stated growth, repayment, or general corporate purposes.', commonExaminationTrap: 'Using total offer size when the decision concerns issuer cash.' },
    bookBuilding: { term: 'Book building', definition: 'A price discovery process in which investors submit bids across a disclosed price range and the issuer and book running lead managers determine the final offer price.', location: 'Prospectus offer procedure and basis for offer price.', financialInterpretation: 'It aggregates demand information before the shares begin trading publicly.', commonExaminationTrap: 'Confusing high subscription with proof that the final price was economically correct.' },
    leadManager: { term: 'Book running lead manager', definition: 'An investment bank appointed to coordinate the offering, advise on price discovery, manage distribution, and support execution.', location: 'Prospectus intermediary and offer management section.', financialInterpretation: 'The mandate determines who controls key parts of the primary-market execution process.', commonExaminationTrap: 'Selecting a bank on headline valuation advice alone while ignoring distribution and execution capacity.' },
    underpricing: { term: 'IPO underpricing', definition: 'The positive return available at the start of secondary-market trading relative to the final offer price.', location: 'Offer document and exchange price record.', financialInterpretation: 'It indicates that the primary-market price was below the first observable secondary-market price, although the gap also reflects market conditions and measurement choice.', commonExaminationTrap: 'Calling any first-day gain a pure transfer from the issuer without checking the reference price and timing.' },
    firstMarketPrice: { term: 'First market price', definition: 'The first observable secondary-market price used as the comparison point after listing.', location: 'Exchange trading record or verified market report.', financialInterpretation: 'It is a market outcome formed after a broader set of investors can trade the security.', commonExaminationTrap: 'Using the closing price when the question concerns the opening or first traded price.' },
  };
  const definitionFor = (id) => {
    const item = glossary[id];
    return definition(id, item.term, 'Initial public offerings', item.definition, item.financialInterpretation, item.commonExaminationTrap);
  };
  const base = {
    initial_public_offering: {
      title: 'Zomato sold new capital and old ownership in the same offer.',
      dek: 'The July 2021 prospectus separates the cash that entered Zomato from the shares that changed hands between existing owners and public investors.',
      governing: 'How does an initial public offering convert private ownership into public capital, and which part of the offer actually finances the company?',
      mechanics: 'An initial public offering can combine a fresh issue of new shares with an offer for sale of existing shares. The fresh issue supplies gross proceeds to the issuer. The offer for sale transfers ownership and supplies liquidity to selling shareholders.',
      formula: { label: 'Fresh issue proceeds', lhsLatex: String.raw`\text{Fresh issue proceeds}`, relationLatex: '=', rhsLatex: String.raw`\text{New shares issued}\;\times\;\text{Offer price}`, latex: String.raw`\text{Fresh issue proceeds} = \text{New shares issued}\;\times\;\text{Offer price}`, sourceId: 'zomato_ipo_prospectus', glossary },
      eli5: ['An IPO has two different money paths. New shares send cash into the company. Existing shares send cash to the shareholder who sells them.', 'The offer price is the starting public price, not a guarantee that the stock is worth that amount after listing.'],
      sections: {
        'case-context': ['Zomato’s July 19, 2021 prospectus described an offer of 1,233,552,631 equity shares at ₹76 per share, aggregating to ₹93,750 million. It separated a fresh issue of 1,184,210,526 shares aggregating to ₹90,000 million from an offer for sale of 49,342,105 shares aggregating to ₹3,750 million.', 'That split is the finance problem. The headline offer size does not equal the cash available to Zomato because part of the offer monetized an existing shareholder position.'],
        'conceptual-foundation': ['An IPO is a primary-market financing and ownership event. The issuer creates a public security, sells it to new investors, and becomes subject to public disclosure, governance, and market pricing requirements.', 'The accounting and capital-markets distinction is fresh issue versus offer for sale. The first changes the issuer’s equity base and cash resources. The second changes the shareholder register without creating new issuer cash.', 'The concept therefore answers two separate questions: how much capital the company raises and how much ownership existing holders transfer.'],
        'economic-logic': ['A private company may seek public capital to fund growth, repay obligations, or establish a liquid ownership currency. Existing shareholders may use the same event to achieve liquidity or diversify their holdings.', 'The two motives can coexist, but they do not have the same effect on corporate resources. A high offer size can conceal a modest issuer cash inflow when the offer for sale is large.', 'The public market also imposes a new price discovery mechanism. Investors can revise the valuation immediately after listing as information, demand, and market conditions change.'],
        'formula-construction': ['Fresh issue proceeds begin with the number of new shares and the final offer price. Offer for sale proceeds require a separate calculation because the cash belongs to the selling shareholder.', 'For Zomato, the prospectus provides both the share counts and the offer amounts. The gross fresh issue amount was ₹90,000 million, while the offer for sale amount was ₹3,750 million. These are not interchangeable inputs.', 'Net issuer proceeds require the deduction of offer expenses and any other disclosed adjustments. The decision must therefore use the proceeds utilisation statement, not only the prospectus headline.'],
        'comparative-framework': ['A rights issue raises capital from existing shareholders with pre-emptive participation. A follow-on public offer raises additional public capital after listing. An IPO is the first public issuance by the company.', 'An offer for sale is not a separate financing instrument for the issuer. It is a secondary transfer embedded within the public offer.', 'The correct comparison is the issuer’s capital need, dilution tolerance, shareholder liquidity objective, and governance readiness. No universal fresh issue percentage is optimal.'],
        interpretation: ['Interpret an IPO by separating issuer proceeds, shareholder proceeds, dilution, public float, use of funds, and the valuation implied by the offer price.', 'A large IPO can strengthen the balance sheet, provide liquidity to existing owners, or do both. The conclusion depends on the allocation between fresh issue and offer for sale.', 'The next question is whether the stated use of fresh proceeds creates operating capacity or only changes the capital structure.'],
        'assumptions-limitations': ['The offer price is a primary-market price formed under disclosed procedures. It is not a complete valuation conclusion and does not remove execution, governance, or post-listing market risk.', 'Gross proceeds overstate usable corporate cash when issue expenses are material or when the offer includes a secondary sale.', 'Public investors must assess dilution, use of funds, related-party exposure, loss history, lock-ins, and the difference between accounting performance and market expectations.'],
        'case-resolution': ['Zomato’s prospectus resolves the capital-flow question by separating ₹90,000 million of fresh issue proceeds from ₹3,750 million of offer for sale proceeds. The issuer’s financing came from the fresh issue, while Info Edge received the offer for sale proceeds.', 'The case returns to the concept cleanly: an IPO is not one pool of money. It is a public financing structure whose economic effect depends on which shares are new and which shares are transferred.'],
      },
      definitions: ['freshShares', 'offerForSale', 'offerPrice', 'freshProceeds', 'bookBuilding'].map(definitionFor),
      coverage: [coverage('offer structure and capital flow', 'Conceptual Foundation', ['freshShares', 'offerForSale']), coverage('proceeds and pricing', 'Formula Construction', ['offerPrice', 'freshProceeds']), coverage('public-market transition', 'Economic Logic', ['bookBuilding'])],
      questions: [
        question('What is an IPO?', 'An initial public offering is a company’s first public issuance of shares to investors. It raises public capital, establishes a tradable security, and subjects the issuer to public disclosure and market pricing.'),
        question('What is the difference between a fresh issue and an offer for sale?', 'A fresh issue creates new shares and sends gross proceeds to the issuer. An offer for sale transfers existing shares and sends proceeds to the selling shareholder.'),
        question('Why does the fresh issue versus offer for sale split matter?', 'It determines how much cash enters the company, how much ownership is transferred, and whether the offering primarily funds corporate purposes or provides liquidity to existing holders.'),
        question('What does the offer price tell you?', 'It is the final primary-market price established through the offering process. It provides a valuation reference, but it is not proof of intrinsic value or future trading performance.'),
        question('Why can a company raise capital and still report no improvement in operations?', 'The proceeds may be used for a balance-sheet transaction, repayment, or general corporate purposes. An IPO changes financing capacity, but it does not guarantee profitable deployment of capital.'),
        question('What is dilution?', 'Dilution is the reduction in an existing owner’s percentage claim when new shares increase the total share count. It must be assessed alongside the capital and growth the new shares finance.'),
        question('Why is an IPO not only a financing decision?', 'It also changes disclosure obligations, governance, ownership liquidity, price discovery, investor composition, and management’s exposure to public-market expectations.'),
        question('What should an MBA finance student inspect first in an IPO?', 'Separate fresh and secondary shares, reconcile gross and net proceeds, read the objects of the issue, assess dilution, and compare the offer price with the issuer’s operating economics and risk disclosures.'),
      ],
    },
    ipo_bake_off: {
      title: 'Zomato’s public debut began with a private contest for control of execution.',
      dek: 'The prospectus names the banks responsible for taking Zomato from a private issuer to a priced, distributed, and listed security.',
      governing: 'How should a company choose lead managers when price advice, investor distribution, execution certainty, and conflicts point in different directions?',
      mechanics: 'An IPO bake-off is a mandate-selection process in which investment banks compete to lead the offering. The issuer evaluates valuation work, distribution reach, sector credibility, execution capability, research strategy, fees, and conflicts before appointing the book running lead managers.',
      formula: { label: 'Mandate evaluation', lhsLatex: String.raw`\text{Mandate quality}`, relationLatex: '=', rhsLatex: String.raw`\text{Price discovery}\;+\;\text{Distribution}\;+\;\text{Execution certainty}\;-\;\text{Conflicts}`, latex: String.raw`\text{Mandate quality} = \text{Price discovery}\;+\;\text{Distribution}\;+\;\text{Execution certainty}\;-\;\text{Conflicts}`, sourceId: 'zomato_ipo_prospectus', glossary },
      eli5: ['Before a company sells shares to the public, it chooses the banks that will help make the sale work.', 'The cheapest bank is not automatically the best choice. The company needs credible valuation, access to investors, and reliable execution under pressure.'],
      sections: {
        'case-context': ['Zomato’s prospectus identified Kotak Mahindra Capital, Morgan Stanley India, and Credit Suisse Securities India among the global coordinators and book running lead managers for the offer.', 'The named mandate is the visible outcome of an earlier selection problem. The issuer had to choose institutions that could coordinate pricing, distribution, regulatory execution, and the transition to public trading.'],
        'conceptual-foundation': ['An IPO bake-off is a competitive mandate process, not a valuation contest alone. Investment banks present a view on price, demand, investor targeting, timetable, structure, risks, and execution responsibilities.', 'The issuer is buying a probability of successful execution. A credible price with weak distribution can fail. Strong distribution with weak valuation discipline can create a first-day price gap and damage the issuer’s capital-raising outcome.', 'The decision is therefore multi-dimensional. Fees matter, but they are only one component of the mandate economics.'],
        'economic-logic': ['The lead manager sits between the issuer and the investor base. It translates company information into a marketable equity story, tests demand through investor education, builds an order book, and manages the price discovery process.', 'The issuer must distinguish genuine demand from conditional or momentum-driven demand. A bank that promises the highest valuation may be less useful if its investor base will not support the price when market conditions change.', 'Conflicts must also be evaluated. The bank’s incentives can affect pricing advice, allocation, research coverage, and the balance between issuer proceeds and aftermarket performance.'],
        'formula-construction': ['A mandate scorecard should separate the variables rather than collapse them into a single headline fee. Price discovery asks whether the bank can test valuation. Distribution asks whether it can reach suitable investors. Execution certainty asks whether the process can close on time and within regulatory requirements.', 'The conflict adjustment is not a generic penalty. It requires a specific assessment of underwriting exposure, research incentives, allocation pressure, and relationships with selling shareholders.', 'The framework is a decision tool, not a universal arithmetic law. The issuer must document the weights and the evidence supporting each assessment.'],
        'comparative-framework': ['A book running lead manager coordinates the order book and pricing process. A syndicate member distributes the offer but may not carry the same coordination mandate.', 'A corporate finance adviser may provide strategic advice without underwriting or book running responsibility. The roles should not be treated as interchangeable.', 'The correct comparison is the issuer’s risk, sector, investor base, timing, valuation complexity, and need for execution support.'],
        interpretation: ['A strong bake-off proposal explains how the bank will convert uncertain investor demand into a defensible price and a completed transaction.', 'The winning bank should be judged by both execution and outcome. A high headline valuation is weak evidence if the book does not hold, the allocation is unstable, or the issuer receives poor aftermarket support.', 'The next question is whether the proposed investor demand is supported by identified accounts, valuation work, and a credible path from indications to funded orders.'],
        'assumptions-limitations': ['Pitch materials are forecasts of execution capacity, not evidence that the IPO will price successfully. Market conditions, regulation, investor risk appetite, and company disclosure can change after appointment.', 'The issuer may not observe the bank’s true distribution effort or investor feedback perfectly. References and process evidence must supplement the pitch.', 'Fee comparisons can mislead when a lower fee comes with weaker distribution, greater execution risk, or hidden economics elsewhere in the transaction.'],
        'case-resolution': ['Zomato’s prospectus provides the real mandate record: the appointed banks were responsible for coordinating a ₹93,750 million public offer and taking it through price discovery and listing.', 'The transferable lesson is that an IPO bake-off selects an execution system. The best proposal is the one that connects valuation, investor demand, regulatory timing, allocation, and aftermarket credibility into one defensible plan.'],
      },
      definitions: ['bookBuilding', 'leadManager', 'offerPrice', 'underpricing', 'firstMarketPrice'].map(definitionFor),
      coverage: [coverage('mandate selection', 'Conceptual Foundation', ['leadManager', 'bookBuilding']), coverage('pricing and distribution', 'Economic Logic', ['offerPrice', 'firstMarketPrice']), coverage('conflicts and execution', 'Assumptions and Limitations', ['underpricing'])],
      questions: [
        question('What is an IPO bake-off?', 'It is the competitive pitch process through which an issuer evaluates investment banks for the lead manager mandate. Banks present their valuation, investor access, transaction structure, timetable, execution plan, and economics.'),
        question('Why is the highest valuation proposal not automatically the best?', 'A high proposed valuation can fail if investor demand is not durable. A successful mandate must connect price, distribution, execution certainty, and the issuer’s disclosure quality.'),
        question('What does a book running lead manager do?', 'It coordinates the offering, advises on price discovery, manages investor distribution, builds the order book, supports regulatory execution, and helps determine the final offer price.'),
        question('What should be included in a bank scorecard?', 'The scorecard should cover valuation evidence, sector expertise, institutional and retail distribution, execution record, research capability, fees, conflicts, and the resources committed to the transaction.'),
        question('How can the bank’s incentives create a conflict?', 'A bank may face pressure to win the mandate, protect issuer relationships, place shares with preferred investors, or support aftermarket performance. The issuer must assess whether the incentives affect pricing or allocation.'),
        question('Why does distribution capacity matter?', 'An IPO needs funded demand from investors whose investment horizon and risk tolerance match the issuer. Distribution capacity affects both the probability of completion and the quality of the shareholder base.'),
        question('How is a bake-off different from book building?', 'The bake-off selects the banks and transaction approach before the offering. Book building aggregates investor bids after the banks have been appointed and the offer process is underway.'),
        question('What evidence should reverse a mandate recommendation?', 'A recommendation should change if references reveal weak execution, investor indications are not credible, conflicts are not manageable, or the proposed valuation cannot be supported by comparable companies and operating fundamentals.'),
      ],
    },
    ipo_underpricing: {
      title: 'Zomato’s first market price was far above the price offered to investors.',
      dek: 'Zomato’s ₹76 offer price and its ₹115 BSE opening price show why the IPO pop is evidence about price discovery, not a complete verdict on value.',
      governing: 'What does the gap between an IPO offer price and the first secondary-market price reveal about price discovery, and who captures the difference?',
      mechanics: 'IPO underpricing measures the positive return available at the first chosen secondary-market price relative to the final offer price. The gap can reflect information asymmetry, deliberate allocation strategy, demand uncertainty, market conditions, or a price that was set below the clearing level.',
      formula: { label: 'IPO underpricing', lhsLatex: String.raw`\text{IPO underpricing}`, relationLatex: '=', rhsLatex: String.raw`\frac{\text{First market price} - \text{Offer price}}{\text{Offer price}}`, latex: String.raw`\text{IPO underpricing} = \frac{\text{First market price} - \text{Offer price}}{\text{Offer price}}`, sourceId: 'zomato_listing_report', glossary },
      eli5: ['The company sells shares at one price. After listing, public trading may begin at a higher price.', 'That gap tells you the two markets disagreed about price at that moment. It does not tell you by itself whether the company is a good investment.'],
      sections: {
        'case-context': ['Zomato’s prospectus set the final offer price at ₹76 per share. On July 23, 2021, the stock opened at ₹115 on BSE, according to the contemporaneous listing report.', 'The opening price was 51.32% above the offer price. The gap created an immediate return for investors who received an allocation, while the issuer had already sold the shares at the lower primary-market price.'],
        'conceptual-foundation': ['IPO underpricing is the difference between the primary-market price and a defined early secondary-market price, scaled by the offer price. It measures the value left between allocation and public trading.', 'The construct isolates a price discovery gap. It does not isolate one cause. Information asymmetry, investor demand, deliberate risk sharing, market sentiment, allocation incentives, and issuer bargaining power can all influence the result.', 'The reference price must be stated precisely. Opening price, first trade, first-day close, and first-week average answer different questions.'],
        'economic-logic': ['An issuer wants to raise capital at the highest price that the market will fund. Underwriters also want the deal to close, investors to receive an allocation, and the shares to trade without an immediate collapse.', 'A discount can compensate investors for uncertainty and encourage participation. But a large gap transfers value from the issuer and selling shareholders to the investors who receive shares at the offer price.', 'The aftermarket price contains information from a broader trading population, but it is also exposed to short-term demand, market microstructure, scarcity, and sentiment.'],
        'formula-construction': ['The numerator is the selected early market price less the final offer price. The denominator is the offer price because the question concerns the return available relative to the investor’s primary-market cost.', 'Zomato’s BSE opening price of ₹115 less the ₹76 offer price gives a ₹39 difference. Dividing ₹39 by ₹76 produces approximately 51.32%.', 'The result changes if the reference price changes. A first-day closing price measures a different outcome from the opening price and must not be substituted silently.'],
        'comparative-framework': ['Underpricing differs from total shareholder return because it measures a defined early interval rather than the investor’s full holding-period return.', 'It also differs from oversubscription. Oversubscription measures demand relative to available shares. Underpricing measures the subsequent price gap. High subscription can coexist with either a small or a large price gap.', 'The correct benchmark is a comparable cohort by market regime, sector, issue size, investor composition, and measurement convention. No universal underpricing threshold determines whether an IPO was correctly priced.'],
        interpretation: ['Zomato’s 51.32% opening premium is evidence that the market clearing price at the open exceeded the final offer price. It is not proof that the issuer mispriced the company intentionally.', 'The distributional question matters. Investors who received allocation captured the gap. The company and selling shareholder did not receive the higher opening price on those shares.', 'The next question is whether the gap reflected prudent risk sharing or avoidable value transfer. That requires examining demand quality, price-band decisions, comparable valuations, market conditions, and allocation outcomes.'],
        'assumptions-limitations': ['The calculation depends on a reliable offer price and a clearly defined market reference. Opening prices can be affected by limited early liquidity, order imbalance, and exchange microstructure.', 'A first-day premium can reverse quickly. It should not be interpreted as evidence of sustainable intrinsic value without operating and valuation analysis.', 'A high gap can be rational when uncertainty is high, but repeated high gaps across a bank, sector, or market regime may indicate systematic pricing incentives or weak issuer bargaining power.'],
        'case-resolution': ['Zomato provides a clean numerical bridge: ₹76 offer price, ₹115 BSE opening price, and a 51.32% opening premium. The evidence shows the price discovery gap without pretending that one day determines long-run value.', 'The durable lesson is that an IPO price is a negotiated primary-market outcome. Underpricing measures the distance between that outcome and early public trading, then forces the finance student to ask who benefited and why.'],
      },
      definitions: ['underpricing', 'offerPrice', 'firstMarketPrice', 'bookBuilding', 'leadManager'].map(definitionFor),
      coverage: [coverage('definition and measurement', 'Conceptual Foundation', ['underpricing', 'offerPrice', 'firstMarketPrice']), coverage('price discovery mechanism', 'Economic Logic', ['bookBuilding']), coverage('interpretation and causality', 'Interpretation', ['leadManager'])],
      questions: [
        question('What is IPO underpricing?', 'IPO underpricing is the positive return between a defined early secondary-market price and the final offer price, divided by the offer price.'),
        question('Why might an issuer underprice an IPO?', 'A lower price can compensate investors for uncertainty, improve the probability of completion, create aftermarket stability, and encourage demand. It can also transfer value away from the issuer if the discount is excessive.'),
        question('Who captures the IPO pop?', 'Investors who receive shares at the offer price capture the increase if they sell at the early market price. The issuer does not receive the higher aftermarket price on the shares already sold.'),
        question('Why does the reference price matter?', 'Opening price, first trade, first-day close, and first-week average capture different market conditions and liquidity. The metric is not interpretable until the reference convention is named.'),
        question('How is underpricing different from oversubscription?', 'Oversubscription measures bids relative to shares available. Underpricing measures the subsequent market price gap. Oversubscription may create evidence about demand, but it is not the same outcome.'),
        question('Does a large IPO pop prove the issuer made a mistake?', 'No. The gap may compensate investors for information risk, market volatility, or execution uncertainty. It may also reflect weak pricing discipline. The cause requires evidence beyond the percentage.'),
        question('Why can the first market price be unreliable?', 'The opening price may reflect order imbalance, limited liquidity, short-term sentiment, and allocation scarcity. It is a market observation, not a complete valuation estimate.'),
        question('What should a finance student ask after calculating underpricing?', 'Ask whether the price gap was consistent with the issue’s risk, market regime, demand quality, comparable valuations, allocation strategy, and the issuer’s capital need.'),
      ],
    },
  };
  const selected = base[topic.topic_id];
  return {
    ...selected,
    anchorDescription: `Zomato’s July 2021 public offering and listing provide a real source-backed anchor for ${topic.canonical_name}.`,
    sourceList,
    mechanics: selected.mechanics,
    formula: selected.formula,
    knowledgeMap: { whyItExists: selected.sections['conceptual-foundation'][0], informationIsolated: selected.sections['conceptual-foundation'][1], decisionEnabled: selected.sections.interpretation[1], validityAssumptions: selected.sections['assumptions-limitations'][0], criticalQuestion: selected.sections.interpretation[2] },
    governing: selected.governing,
    sections: selected.sections,
    definitions: selected.definitions,
    coverage: selected.coverage,
    questions: selected.questions,
    eli5: selected.eli5,
  };
}

function makeLiquidityRatioSpec(topic) {
  const sourceList = [source('walmart_2024_annual_report', 'Walmart Inc. Annual Report 2024, Consolidated Balance Sheets', 'https://stock.walmart.com/_assets/_46796feebc5ddf6d2adbeabac9558ae9/walmart/db/950/9651/annual_report/Walmart_2024-AR-10K_Searchable.pdf')];
  const names = { cash_ratio: 'Cash Ratio', current_ratio: 'Current Ratio', quick_ratio: 'Quick Ratio' };
  const name = names[topic.topic_id];
  const formulaByTopic = {
    cash_ratio: { label: 'Cash ratio', lhsLatex: String.raw`\text{Cash ratio}`, relationLatex: '=', rhsLatex: String.raw`\frac{\text{Cash and cash equivalents}}{\text{Current liabilities}}`, latex: String.raw`\text{Cash ratio} = \frac{\text{Cash and cash equivalents}}{\text{Current liabilities}}` },
    current_ratio: { label: 'Current ratio', lhsLatex: String.raw`\text{Current ratio}`, relationLatex: '=', rhsLatex: String.raw`\frac{\text{Current assets}}{\text{Current liabilities}}`, latex: String.raw`\text{Current ratio} = \frac{\text{Current assets}}{\text{Current liabilities}}` },
    quick_ratio: { label: 'Quick ratio', lhsLatex: String.raw`\text{Quick ratio}`, relationLatex: '=', rhsLatex: String.raw`\frac{\text{Cash}\;+\;\text{Receivables}\;+\;\text{Eligible short-term investments}}{\text{Current liabilities}}`, latex: String.raw`\text{Quick ratio} = \frac{\text{Cash}\;+\;\text{Receivables}\;+\;\text{Eligible short-term investments}}{\text{Current liabilities}}` },
  };
  const glossary = {
    cash: { term: 'Cash and cash equivalents', definition: 'Cash on hand and highly liquid investments that can be converted to known amounts of cash with insignificant risk of changes in value.', location: 'Balance sheet, current assets.', financialInterpretation: 'It is the most immediate source of payment capacity.', commonExaminationTrap: 'Treating restricted cash as freely available cash without reading the disclosure.' },
    receivables: { term: 'Receivables', definition: 'Amounts due from customers or other counterparties that the company expects to collect.', location: 'Balance sheet, current assets and receivables note.', financialInterpretation: 'Receivables are liquid only to the extent that collection is timely and realizable without material loss.', commonExaminationTrap: 'Treating every receivable as cash equivalent regardless of aging, disputes, or concentration.' },
    inventory: { term: 'Inventory', definition: 'Goods held for sale or inputs to be consumed in production or service delivery.', location: 'Balance sheet, current assets and inventory note.', financialInterpretation: 'Inventory may support future sales but requires demand, conversion time, and realizable pricing before it becomes cash.', commonExaminationTrap: 'Assuming a reported inventory balance can discharge a liability immediately.' },
    currentAssets: { term: 'Current assets', definition: 'Assets expected to be realized, sold, or consumed in the normal operating cycle or within the applicable short-term horizon.', location: 'Balance sheet, current assets section.', financialInterpretation: 'The total captures the broad resources available against near-term obligations, including assets with different conversion certainty.', commonExaminationTrap: 'Reading current assets as one homogeneous pool of liquidity.' },
    currentLiabilities: { term: 'Current liabilities', definition: 'Obligations due for settlement within the applicable short-term horizon or within the normal operating cycle.', location: 'Balance sheet, current liabilities section.', financialInterpretation: 'They define the timing and scale of claims the liquidity measure must address.', commonExaminationTrap: 'Comparing current assets with liabilities that have a materially different maturity profile without further analysis.' },
    prepaids: { term: 'Prepaid expenses and other current assets', definition: 'Current assets that may not be immediately convertible to cash because they represent future services, deposits, or other operating rights.', location: 'Balance sheet, current assets section and supporting notes.', financialInterpretation: 'Their inclusion in current assets can make broad liquidity look stronger than immediate payment capacity.', commonExaminationTrap: 'Including every current asset in a quick measure without testing convertibility.' },
  };
  const definitionFor = (id) => {
    const item = glossary[id];
    return definition(id, item.term, 'Liquidity analysis', item.definition, item.financialInterpretation, item.commonExaminationTrap);
  };
  const observed = {
    cash_ratio: { value: '0.11x', numerator: 'Cash and cash equivalents of $9,867 million', formulaText: '$9,867 million / $92,415 million = 0.11x', information: 'immediate cash coverage', title: 'Walmart held cash. Its near-term claims were larger.', decision: 'whether immediate cash alone can meet near-term claims' },
    current_ratio: { value: '0.83x', numerator: 'Total current assets of $76,877 million', formulaText: '$76,877 million / $92,415 million = 0.83x', information: 'broad short-term resource coverage', title: 'Walmart’s current assets did not cover its current liabilities.', decision: 'whether the full current-asset base appears sufficient before testing asset quality' },
    quick_ratio: { value: '0.20x', numerator: 'Cash of $9,867 million plus receivables of $8,796 million', formulaText: '($9,867 million + $8,796 million) / $92,415 million = 0.20x', information: 'short-term coverage without inventory and prepaids', title: 'Walmart’s inventory was large. It was not immediate liquidity.', decision: 'whether near-term claims can be met without selling inventory' },
  }[topic.topic_id];
  const formula = { ...formulaByTopic[topic.topic_id], sourceId: 'walmart_2024_annual_report', glossary };
  const governing = topic.topic_id === 'current_ratio'
    ? 'How much of the company’s short-term asset base stands behind obligations due in the short term, and what does that broad measure conceal about conversion certainty?'
    : topic.topic_id === 'quick_ratio'
      ? 'Can near-term obligations be met without selling inventory, and what does excluding inventory reveal about immediate liquidity?'
      : 'How much of the company’s near-term obligations could be paid from cash and cash equivalents alone?';
  const mechanics = topic.topic_id === 'current_ratio'
    ? 'Current Ratio compares all current assets with current liabilities. It tests broad balance-sheet coverage, but it treats cash, receivables, inventory, and prepaids as members of one denominator-matched pool even though their conversion paths differ.'
    : topic.topic_id === 'quick_ratio'
      ? 'Quick Ratio compares cash, receivables, and eligible short-term investments with current liabilities. It removes inventory and other assets whose conversion requires sale, collection, or operating execution.'
      : 'Cash Ratio compares cash and cash equivalents with current liabilities. It isolates the payment capacity that exists without collecting receivables, selling inventory, or refinancing.';
  const sections = {
    'case-context': [
      `Walmart reported cash and cash equivalents of $9,867 million, receivables of $8,796 million, inventories of $54,892 million, total current assets of $76,877 million, and current liabilities of $92,415 million as of January 31, 2024.`,
      `${name} matters because the same balance sheet produces different conclusions depending on which current assets are treated as available for payment.`,
    ],
    'governing-question': [governing],
    'conceptual-foundation': [
      `${name} exists because the current-assets total combines resources with different conversion certainty. The measure selects a narrower or broader asset set to answer a specific payment question.`,
      mechanics,
      'The denominator is not an abstract comparison base. It represents obligations whose timing can force the company to convert assets, preserve cash, draw committed facilities, or negotiate with suppliers and lenders.',
    ],
    'economic-logic': [
      topic.topic_id === 'current_ratio'
        ? 'Broad current-asset coverage can be useful when the operating cycle reliably converts inventory and receivables into cash before obligations mature. It becomes weak when inventory is slow moving, heavily discounted, or needed to keep the business operating.'
        : topic.topic_id === 'quick_ratio'
          ? 'Excluding inventory makes the conversion test harsher. The measure asks whether the company can meet near-term claims without depending on a sale process whose timing, demand, and margin are uncertain.'
          : 'Cash-only coverage is conservative because it ignores collection and sale. It is most informative when the question concerns immediate stress, lender protection, or the capacity to absorb an interruption in operating inflows.',
      'The ratio is a timing measure, not a solvency conclusion. A company can show weak immediate coverage and still have dependable cash generation or committed financing. It can also show adequate coverage while facing concentrated maturities or restricted cash.',
      'Walmart’s balance sheet makes the tradeoff visible. Inventory was the largest current asset, while cash and receivables were much smaller. Asset classification therefore changes the liquidity conclusion materially.',
    ],
    'formula-construction': [
      topic.topic_id === 'current_ratio'
        ? 'The numerator includes the current assets reported within the applicable accounting classification. That includes assets with different realization paths, so the calculation is broad by design.'
        : topic.topic_id === 'quick_ratio'
          ? 'The numerator includes cash and receivables and excludes inventory and prepaids. Each included balance must be tested for availability, collection risk, and short-term timing.'
          : 'The numerator includes cash and cash equivalents only. Restricted cash must be removed when the company cannot use it to meet the liabilities in the denominator.',
      `Walmart’s reported fields produce ${observed.formulaText}. The calculation is meaningful because the numerator and denominator refer to the same reporting date and consolidated scope.`,
      'A higher ratio is not automatically safer. The result matters only relative to the maturity schedule, operating cycle, cash burn, supplier terms, and committed liquidity available to the company.',
    ],
    eli5: [
      topic.topic_id === 'current_ratio' ? 'This measure counts the company’s short-term assets and compares them with its short-term bills.' : topic.topic_id === 'quick_ratio' ? 'This measure asks what is available before the company sells its stock of goods.' : 'This measure asks what the company can pay with cash already in hand.',
      `For Walmart, the reported balance sheet gives ${observed.value}. The number is a starting point for asking whether the assets can become cash before the bills arrive.`,
    ],
    'comparative-framework': [
      topic.topic_id === 'current_ratio' ? 'Current Ratio is broader than Quick Ratio because it includes inventory and other current assets. Cash Ratio is narrower because it includes only cash and cash equivalents.' : topic.topic_id === 'quick_ratio' ? 'Quick Ratio sits between Current Ratio and Cash Ratio. It excludes inventory but still assumes that included receivables are collectible and available.' : 'Cash Ratio is the strictest of the three measures. It does not give credit for receivables, inventory, or undrawn financing capacity.',
      'The correct benchmark is the same company over time, comparable retailers with similar operating cycles, and the actual maturity profile. No universal liquidity threshold has the same meaning across sectors.',
      'Retailers can operate with low ratio values because supplier credit, inventory turns, cash receipts, and scale economics shape their financing model. The result must be interpreted with that operating structure.',
    ],
    interpretation: [
      `Walmart’s ${name} result is ${observed.value}. The result indicates ${observed.information}, not the probability of bankruptcy.`,
      `The decision is ${observed.decision}. The answer requires the ratio plus the timing of cash inflows, liabilities, inventory realization, and committed financing.`,
      'The next question is which balance could fail first under stress. A weak conclusion usually comes from assuming that the numerator is liquid without testing the underlying conversion process.',
    ],
    'assumptions-limitations': [
      'The ratio assumes that the accounting classification, reporting date, and consolidated scope are comparable. It also assumes that the included assets can be realized within the liability horizon.',
      'Inventory can require markdowns and continued operating expenditure before sale. Receivables can be delayed, disputed, concentrated, or offset by customer returns and allowances.',
      'The ratio ignores cash-flow timing, debt maturities, undrawn facilities, supplier behavior, seasonality, and the possibility that cash is restricted. It is a screening measure, not a liquidity forecast.',
    ],
    'case-resolution': [
      `Walmart’s balance sheet resolves the teaching question through the asset ladder. Cash was $9,867 million, receivables were $8,796 million, inventory was $54,892 million, and current liabilities were $92,415 million. The asset set changes the conclusion because conversion certainty changes.`,
      `The durable lesson is that ${name} is a deliberately incomplete view of liquidity. Its value comes from isolating one payment condition and forcing the reader to test the asset and liability timing behind the number.`,
    ],
  };
  return {
    title: observed.title,
    dek: `Walmart’s 2024 balance sheet shows why ${name} is a liquidity screen, not a conclusion about solvency.`,
    anchorDescription: `Walmart’s January 31, 2024 consolidated balance sheet supplies real cash, receivables, inventory, current asset, and current liability fields for ${name}.`,
    sourceList,
    mechanics,
    formula,
    knowledgeMap: { whyItExists: sections['conceptual-foundation'][0], informationIsolated: sections['conceptual-foundation'][1], decisionEnabled: sections.interpretation[1], validityAssumptions: sections['assumptions-limitations'][0], criticalQuestion: sections.interpretation[2] },
    sections,
    governing,
    eli5: sections.eli5,
    definitions: ['cash', 'receivables', 'inventory', 'currentAssets', 'currentLiabilities', 'prepaids'].map(definitionFor),
    coverage: [coverage('asset classification and timing', 'Conceptual Foundation', ['cash', 'inventory', 'currentAssets']), coverage('formula inputs', 'Formula Construction', ['receivables', 'currentLiabilities', 'prepaids']), coverage('interpretation and benchmarking', 'Interpretation', ['cash', 'currentLiabilities'])],
    questions: [
      question(`What does ${name} measure?`, `${mechanics} It provides evidence about a defined payment condition, not a complete solvency conclusion.`),
      question('Why does inventory matter?', 'Inventory may require demand, time, markdowns, and continued operating expenditure before it becomes cash. Excluding it tests a more immediate liquidity condition.'),
      question('Why are receivables not equivalent to cash?', 'Receivables depend on collection timing, customer credit quality, disputes, returns, and concentration. Their inclusion requires an assessment of realizability.'),
      question('What does a low result mean?', 'It means the selected asset set is small relative to current liabilities at the reporting date. The finance student must then inspect cash generation, maturity timing, supplier terms, and committed financing.'),
      question('Why can a retailer operate with a low liquidity ratio?', 'Retailers may receive cash from customers before paying suppliers and may turn inventory rapidly. The ratio must be reconciled to the operating cycle and liability timing.'),
      question('What is the difference between Current Ratio and Quick Ratio?', 'Current Ratio includes the broad current-asset base. Quick Ratio excludes inventory and less readily convertible current assets to focus on assets closer to cash.'),
      question('What is the difference between Quick Ratio and Cash Ratio?', 'Quick Ratio includes qualifying receivables and short-term investments. Cash Ratio gives credit only to cash and cash equivalents.'),
      question('What benchmark should be used?', 'Use the company’s own history, comparable businesses with similar operating cycles, and the actual maturity schedule. No universal threshold applies to every sector.'),
      question('What would reverse the conclusion?', 'A revised classification, restricted cash disclosure, receivables aging problem, inventory markdown, unexpected maturity, or committed financing facility could change the practical liquidity conclusion.'),
    ],
  };
}

function makeProfitabilitySpec(topic) {
  const sourceList = [source('walmart_2024_annual_report', 'Walmart Inc. Annual Report 2024, financial statements and company performance metrics', 'https://stock.walmart.com/_assets/_46796feebc5ddf6d2adbeabac9558ae9/walmart/db/950/9651/annual_report/Walmart_2024-AR-10K_Searchable.pdf')];
  const names = {
    gross_margin: 'Gross Margin',
    operating_margin: 'Operating Margin',
    return_on_assets: 'Return on Assets',
    return_on_equity: 'Return on Equity',
    return_on_invested_capital: 'Return on Invested Capital',
    return_on_capital_employed: 'Return on Capital Employed',
  };
  const name = names[topic.topic_id];
  const data = {
    netSales: '$642,637 million',
    operatingIncome: '$27,012 million',
    consolidatedNetIncome: '$16,270 million',
    attributableNetIncome: '$15,511 million',
    averageAssets: '$247,798 million',
    averageInvestedCapital: '$277,522 million',
    averageShareholdersEquity: '$80,277 million, calculated from $83,861 million and $76,693 million',
    averageCapitalEmployed: '$155,492 million, calculated from total assets less current liabilities for 2024 and 2023',
    taxRate: '25.5%',
  };
  const outcomes = {
    gross_margin: { value: '23.7%', title: 'Walmart expanded the gross profit rate while keeping prices competitive.', question: 'How much of each dollar of net sales remains after the direct cost of merchandise, and what changed that spread?', mechanics: 'Gross margin divides gross profit by net sales. Walmart reported a gross profit rate of 23.7% for fiscal 2024, up from 23.5% in fiscal 2023.', signal: 'pricing power, merchandise mix, markdowns, supplier cost, and supply-chain economics before operating overhead', decision: 'whether a change in profitability began in the product economics or arose later in operating expenses', formula: String.raw`\text{Gross margin} = \frac{\text{Gross profit}}{\text{Net sales}}`, eli5: 'Walmart sold goods and kept 23.7 cents from each dollar of net sales after the direct cost of the goods. The rest still had to pay for stores, people, technology, financing, and tax.', focus: 'Gross margin is a product and procurement signal. It does not measure the whole company’s ability to turn sales into earnings.' },
    operating_margin: { value: '4.2%', title: 'Revenue grew. The operating line grew faster.', question: 'How much operating profit remains after the full operating cost base, and is the business converting scale into operating leverage?', mechanics: 'Operating margin divides operating income by net sales. Walmart reported operating income of $27,012 million and operating income of 4.2% of net sales for fiscal 2024, compared with 3.4% in fiscal 2023.', signal: 'the combined effect of gross profitability, labor, stores, fulfillment, technology, overhead, and operating leverage', decision: 'whether revenue growth is reaching the operating line or being absorbed by the cost structure', formula: String.raw`\text{Operating margin} = \frac{\text{Operating income}}{\text{Net sales}}`, eli5: 'After paying the costs of running the business, Walmart kept about 4.2 cents of operating profit for every dollar of net sales.', focus: 'Operating margin shows the economics of the operating platform after overhead. It excludes financing and tax, so it is not net profitability.' },
    return_on_assets: { value: '6.6%', title: 'Walmart’s return rose because the asset base produced more earnings.', question: 'What earnings return did Walmart generate on the assets committed to the business, and is the return coming from margins, asset turnover, or both?', mechanics: 'Return on Assets divides consolidated net income by average total assets. Walmart disclosed consolidated net income of $16,270 million, average total assets of $247,798 million, and ROA of 6.6% for fiscal 2024.', signal: 'how effectively the full asset base is producing accounting earnings, after operating costs, financing effects, and tax', decision: 'whether growth is earning an adequate return on the assets required to support it', formula: String.raw`\text{ROA} = \frac{\text{Consolidated net income}}{\text{Average total assets}}`, eli5: 'Take the profit Walmart made and compare it with the average value of everything the company owned and used. That produced a 6.6% return.', focus: 'ROA is a whole-company return measure. It is affected by leverage, tax, leases, goodwill, and the accounting value of assets.' },
    return_on_equity: { value: '19.3%', title: 'The shareholder return depends on more than operating performance.', question: 'What return accrued to Walmart shareholders, and how much of that return reflects operations versus the financing structure?', mechanics: 'Return on Equity divides profit attributable to Walmart shareholders by average Walmart shareholders’ equity. Using $15,511 million of attributable net income and average equity of $80,277 million gives approximately 19.3%.', signal: 'the return earned on the owners’ accounting capital, including the effects of asset productivity, margins, financing leverage, and noncontrolling interests', decision: 'whether shareholder returns are improving because the business is stronger or because the equity base is smaller relative to the assets and debt supporting the business', formula: String.raw`\text{ROE} = \frac{\text{Net income attributable to common shareholders}}{\text{Average common equity}}`, eli5: 'Walmart earned about 19.3 cents for every dollar of average equity belonging to its shareholders. That result also reflects how the business is financed.', focus: 'ROE can rise when operating performance improves, but it can also rise when leverage or share repurchases reduce the equity base.' },
    return_on_invested_capital: { value: '7.3%', title: 'The return on operating capital is the test that financing labels cannot answer.', question: 'Does Walmart earn an operating return on invested capital after tax, and how does that compare with the capital’s opportunity cost?', mechanics: 'This lesson uses NOPAT divided by average invested capital. Operating income of $27,012 million taxed at Walmart’s 25.5% effective rate produces NOPAT of approximately $20,124 million; divided by Walmart’s disclosed average invested capital of $277,522 million, the result is approximately 7.3%.', signal: 'whether the operating business creates value before the financing decision is layered on top', decision: 'whether additional operating capital is likely to earn more than its opportunity cost and whether growth is value creating', formula: String.raw`\text{ROIC} = \frac{\text{NOPAT}}{\text{Average invested capital}}`, eli5: 'First remove the tax on operating profit. Then compare what is left with the capital tied up in the business. Walmart’s result is about 7.3% under this stated convention.', focus: 'ROIC is definition-sensitive. The result changes when invested capital, tax rate, leases, goodwill, or operating versus nonoperating assets are classified differently.' },
    return_on_capital_employed: { value: '17.4%', title: 'Capital employed reveals the operating return behind the balance sheet.', question: 'How much operating profit does Walmart generate from the long-term capital committed to the business, and what does the denominator include?', mechanics: 'Return on Capital Employed divides operating income by average capital employed. Using total assets less current liabilities for 2024 and 2023 gives average capital employed of approximately $155,492 million; $27,012 million of operating income produces approximately 17.4%.', signal: 'the operating return on long-term capital after short-term operating liabilities are netted from the asset base', decision: 'whether expansion, stores, technology, and infrastructure are producing enough operating profit relative to the capital tied up in them', formula: String.raw`\text{ROCE} = \frac{\text{Operating income}}{\text{Average capital employed}}`, eli5: 'Subtract the short-term bills from the assets, then compare what remains with operating profit. Walmart produced about a 17.4% return on that capital under this convention.', focus: 'ROCE is not a single universally defined ratio. The capital-employed convention must be stated before comparing companies or periods.' },
  }[topic.topic_id];
  const glossary = {
    revenue: { term: 'Net sales', definition: 'Revenue from the sale of goods and services after the company’s stated deductions and classifications.', location: 'Income statement.', financialInterpretation: 'It is the scale against which profit and return measures are expressed.', commonExaminationTrap: 'Mixing net sales with total revenues when the company includes membership or other income in total revenues.' },
    grossProfit: { term: 'Gross profit', definition: 'Net sales less the direct costs assigned to the goods or services sold.', location: 'Income statement or operating metrics disclosure.', financialInterpretation: 'It isolates the economics of pricing, procurement, production, and merchandise mix before operating overhead.', commonExaminationTrap: 'Comparing gross profit across companies without checking what each company assigns to cost of sales.' },
    operatingIncome: { term: 'Operating income', definition: 'Profit from the operating activities of the business before financing and income tax effects.', location: 'Income statement.', financialInterpretation: 'It shows how the operating platform converts revenue into profit after operating expenses.', commonExaminationTrap: 'Treating operating income as cash flow or ignoring unusual operating charges.' },
    netIncome: { term: 'Consolidated net income', definition: 'Profit after operating costs, financing items, other gains and losses, and income tax for the consolidated group.', location: 'Income statement.', financialInterpretation: 'It is the earnings numerator for a whole-company return measure such as ROA.', commonExaminationTrap: 'Using attributable net income when the denominator includes noncontrolling interests, or reversing that choice without explanation.' },
    assets: { term: 'Average total assets', definition: 'The average of total assets at the beginning and end of the measurement period.', location: 'Balance sheet and return reconciliation.', financialInterpretation: 'It approximates the asset base deployed during the period rather than relying only on the closing balance.', commonExaminationTrap: 'Using ending assets for a full-year return when the asset base changed materially during the year.' },
    equity: { term: 'Common equity', definition: 'The accounting claim attributable to common shareholders after liabilities and other equity claims.', location: 'Balance sheet and shareholders’ equity statement.', financialInterpretation: 'It is the capital base against which the common shareholders’ return is measured.', commonExaminationTrap: 'Ignoring noncontrolling interests, preferred claims, or share repurchases when selecting the denominator.' },
    investedCapital: { term: 'Invested capital', definition: 'Capital committed to operating assets after nonoperating resources and operating liabilities are classified consistently under a stated convention.', location: 'Derived from the balance sheet and operating disclosures.', financialInterpretation: 'It allows the operating return to be compared with the capital’s opportunity cost.', commonExaminationTrap: 'Treating invested capital as one universally defined balance-sheet line.' },
    nopat: { term: 'NOPAT', definition: 'Net Operating Profit After Tax, calculated by applying a stated tax convention to operating profit.', location: 'Derived from operating income and tax disclosures.', financialInterpretation: 'It measures after-tax operating earnings before the effect of financing choices.', commonExaminationTrap: 'Using reported net income as NOPAT even though net income includes interest, nonoperating items, and financing structure.' },
  };
  const definitionFor = (id) => { const item = glossary[id]; return definition(id, item.term, 'Profitability analysis', item.definition, item.financialInterpretation, item.commonExaminationTrap); };
  const sections = {
    'case-context': [
      `Walmart reported net sales of ${data.netSales}, operating income of ${data.operatingIncome}, consolidated net income of ${data.consolidatedNetIncome}, total assets of $252,399 million at January 31, 2024, and total equity of $90,349 million at the same date.`,
      `${name} matters because a profit figure by itself does not show which economic resource produced it. Profitability analysis changes the denominator to expose product economics, operating efficiency, asset productivity, or the return to capital providers.`,
    ],
    'governing-question': [outcomes.question],
    'conceptual-foundation': [
      `${name} exists to solve a denominator problem. The same earnings amount can represent a strong or weak outcome depending on the revenue base, asset base, equity base, or invested capital required to produce it.`,
      `The information isolated here is ${outcomes.signal}. The ratio is useful because it converts an absolute accounting result into an efficiency or spread question.`,
      outcomes.focus,
    ],
    'economic-logic': [
      'Profitability is an economic result produced by price, volume, cost, capital intensity, financing, tax, and accounting classification. A change in the ratio is therefore a starting point for decomposition, not an explanation by itself.',
      topic.topic_id === 'gross_margin' ? 'A wider gross margin can arise from price increases, lower input cost, favorable mix, lower markdowns, or a reclassification of costs. The finance professional must separate these mechanisms because only some are durable.' : topic.topic_id === 'operating_margin' ? 'Operating margin captures the point at which scale becomes leverage. If revenue rises faster than operating expenses, fixed and semi-fixed costs are absorbed across a larger base; if expenses rise faster, growth destroys operating leverage.' : 'A return ratio combines an earnings numerator with a capital denominator. The return can change because earnings moved, capital moved, or the accounting definition changed. That is why return analysis must inspect both sides of the fraction.',
      `Walmart’s disclosure makes the mechanism visible. The company reported a gross profit rate of 23.7% and operating income of 4.2% of net sales for fiscal 2024, while also explaining that pricing, mix, markdowns, operating expenses, and prior-period legal and restructuring charges affected the comparison.`,
    ],
    'formula-construction': [
      outcomes.mechanics,
      topic.topic_id === 'return_on_invested_capital' ? `The calculation uses NOPAT of approximately $20,124 million, derived from ${data.operatingIncome} and the disclosed ${data.taxRate} effective tax rate, divided by ${data.averageInvestedCapital}. The convention is explicit because ROIC is not a reported Walmart GAAP line.` : topic.topic_id === 'return_on_equity' ? `The numerator is ${data.attributableNetIncome}. The denominator is ${data.averageShareholdersEquity}. Using attributable earnings with Walmart shareholders’ equity keeps the ownership claims aligned.` : topic.topic_id === 'return_on_capital_employed' ? `The numerator is ${data.operatingIncome}. The denominator is ${data.averageCapitalEmployed}. This convention treats total assets less current liabilities as capital employed and must be held constant when comparing periods.` : `The calculation uses the reported numerator and denominator convention for ${name}. The measurement is valid only when the period, entity scope, accounting classification, and denominator definition remain comparable.`,
      `The result is ${outcomes.value}. The number becomes decision-useful only after it is decomposed into price, volume, costs, asset turnover, leverage, tax, capital intensity, and one-off items where those drivers are relevant.`,
    ],
    eli5: [outcomes.eli5, `The formula does not tell you why the number changed. To understand that, inspect the numerator, denominator, and the economic process that moved each one.`, `The number is a lens, not a verdict. It answers one return question and leaves other questions for the related margins, cash flows, leverage, and capital measures.`],
    'comparative-framework': [
      topic.topic_id === 'gross_margin' ? 'Gross margin sits closest to the product or service transaction. Operating margin subtracts the broader operating cost base. Net margin then includes financing, tax, and nonoperating items.' : topic.topic_id === 'operating_margin' ? 'Operating margin is narrower than gross margin in the numerator because it deducts operating expenses, but broader than net margin because it excludes financing and tax.' : topic.topic_id === 'return_on_assets' ? 'ROA relates earnings to the full asset base. ROE relates attributable earnings to common equity. ROIC and ROCE attempt to isolate the return on operating capital and therefore require more judgment about financing and nonoperating balances.' : 'Margin measures relate profit to revenue. Return measures relate profit to assets or capital. A company can improve margin while reducing return if it becomes more capital intensive.',
      'No universal profitability benchmark exists across industries. Compare Walmart with retailers that have similar merchandise mix, operating model, lease structure, and accounting classification, then compare the company with its own historical trend.',
      'The right comparison is not the highest ratio. It is the ratio whose numerator and denominator answer the same economic question under comparable accounting definitions.',
    ],
    interpretation: [
      `Walmart’s ${name} result is ${outcomes.value}. It indicates ${outcomes.signal}.`,
      `The decision is ${outcomes.question.toLowerCase()} The ratio does not answer that question alone; it directs the next analysis toward the driver that moved the numerator or denominator.`,
      'A sophisticated reading asks whether the result is recurring, whether capital intensity changed, whether the accounting denominator is comparable, and whether the return exceeds the opportunity cost of the capital committed.',
    ],
    'assumptions-limitations': [
      'The ratio assumes consistent accounting definitions, comparable periods, a denominator that represents the resources actually deployed during the period, and a business model for which the chosen measure has economic meaning.',
      topic.topic_id === 'gross_margin' ? 'Gross margin is sensitive to cost classification. Distribution, fulfillment, advertising, and membership economics may be assigned differently across companies, making a reported percentage less comparable than it appears.' : topic.topic_id === 'return_on_equity' ? 'ROE is sensitive to leverage, share repurchases, accumulated losses, and noncontrolling interests. A higher ROE can reflect a smaller equity base rather than a stronger operating business.' : 'Return measures are sensitive to asset age, goodwill, leases, acquisitions, inflation, depreciation policy, tax rates, and the treatment of nonoperating assets. A ratio can improve mechanically without an improvement in underlying economics.',
      `Walmart itself distinguishes ROA from its non-GAAP ROI measure. The company states that ROI adjusts operating income and invested capital, which is why the two percentages answer different questions.`,
    ],
    'case-resolution': [
      `Walmart’s FY2024 disclosures resolve the lesson through a stack of denominators: net sales of ${data.netSales}, operating income of ${data.operatingIncome}, average total assets of ${data.averageAssets}, average invested capital of ${data.averageInvestedCapital}, and total Walmart shareholders’ equity of $83,861 million at year end.`,
      `The durable lesson is that profitability is not one number. ${name} is useful because it isolates one relationship, while the rest of the stack tests whether that relationship comes from pricing, cost control, operating leverage, asset productivity, financing, or capital allocation.`,
    ],
  };
  const topicQuestions = {
    gross_margin: ['What does gross margin isolate?', 'What can increase gross margin without improving the business?', 'Why can two companies with the same gross margin have different operating economics?', 'How do price, volume, input cost, product mix, and markdowns move gross margin?', 'Why is gross margin not a cash flow measure?', 'What accounting classifications reduce comparability?', 'How would you investigate a one-year margin expansion?', 'Why did Walmart’s gross profit rate change in fiscal 2024?', 'What is the difference between gross margin and operating margin?', 'What evidence would make you reject a conclusion based only on gross margin?'],
    operating_margin: ['What does operating margin isolate?', 'How is operating margin different from gross margin and net margin?', 'What is operating leverage and how can it change operating margin?', 'Why can revenue growth fail to improve operating margin?', 'How do fixed and variable costs affect the ratio?', 'Which one-off charges can distort an operating-margin comparison?', 'Why does operating margin exclude financing and tax?', 'What did Walmart’s fiscal 2024 operating-margin change reflect?', 'How would you bridge a change in operating margin?', 'What would make a higher operating margin economically weak?'],
    return_on_assets: ['What does ROA measure?', 'Why is average total assets used?', 'How does DuPont analysis decompose ROA?', 'How can ROA rise while operating margin falls?', 'How do acquisitions and goodwill affect ROA?', 'Why is ROA not the same as ROIC?', 'Why can lease accounting affect asset returns?', 'What did Walmart’s disclosed 6.6% ROA mean?', 'When is ROA a poor comparison metric?', 'What evidence would show that a higher ROA is not sustainable?'],
    return_on_equity: ['What does ROE measure?', 'Why must the numerator match common shareholders’ equity?', 'How does financial leverage affect ROE?', 'How can share repurchases mechanically increase ROE?', 'How does DuPont analysis decompose ROE?', 'Why can a high ROE coexist with weak solvency?', 'How do noncontrolling interests affect the calculation?', 'What is the difference between ROE and ROIC?', 'How would you determine whether ROE improved operationally?', 'What would reverse a positive ROE conclusion?'],
    return_on_invested_capital: ['What does ROIC measure?', 'Why is NOPAT used instead of net income?', 'What belongs in invested capital?', 'Why must the tax convention be stated?', 'How does ROIC connect to value creation?', 'Why can ROIC differ from a company’s reported ROI?', 'How do goodwill, leases, and excess cash affect invested capital?', 'What does Walmart’s 7.3% convention-based result show?', 'How should ROIC be compared with cost of capital?', 'What evidence would show that a high ROIC is temporary?'],
    return_on_capital_employed: ['What does ROCE measure?', 'Why must capital employed be defined?', 'How is ROCE different from ROA and ROIC?', 'How do capital projects affect ROCE before they generate earnings?', 'Why can an older asset base mechanically raise ROCE?', 'How do current liabilities affect the denominator?', 'What did Walmart’s 17.4% result mean under the stated convention?', 'How would you bridge a ROCE decline?', 'When is ROCE a poor comparison metric?', 'What evidence would show that the ratio is improving for the wrong reason?'],
  }[topic.topic_id];
  const answers = topicQuestions.map((q, index) => question(q, [
    `It converts ${outcomes.signal} into a comparable return or margin by matching the chosen earnings measure with the denominator that represents the economic resource under examination.`,
    'The ratio is a diagnostic relationship, not a self-executing explanation. Separate the movement in the numerator from the movement in the denominator and trace each to an economic driver.',
    'The comparison fails when accounting classifications, business mix, capital intensity, or denominator definitions differ. A numerical comparison is only meaningful after those conditions are aligned.',
    'Decompose the change into price, volume, cost, mix, operating expense, asset turnover, leverage, tax, and one-off effects as relevant to the specific metric.',
    'It is an accrual-based measure. It does not show collection timing, capital expenditure, working-capital investment, debt service, or the cash available to distribute.',
    'A classification change, acquisition, lease policy, goodwill balance, restructuring charge, or non-GAAP adjustment can move the ratio without changing the underlying operating economics.',
    'Reconcile the reported fields to the filing, compare the prior period, identify the largest numerical driver, and test whether management’s explanation is supported by volume, price, cost, and cash evidence.',
    'The filing’s explanation must be read with the reported fields. The lesson uses the company’s stated metric and preserves the difference between a reported result and a convention defined for this comparison.',
    'The related metric answers a different denominator or numerator question. Use the stack rather than replacing one measure with another.',
    'A recurring, cash-supported, comparable-period improvement that earns an adequate return on the required capital is stronger evidence than a single-period ratio increase.',
  ][index]));
  const formula = { label: name, lhsLatex: String.raw`\text{${name}}`, relationLatex: '=', rhsLatex: outcomes.formula.replace(String.raw`\text{${name}} = `, ''), latex: outcomes.formula, sourceId: 'walmart_2024_annual_report', glossary };
  return {
    title: outcomes.title,
    dek: `Walmart’s FY2024 filing shows why ${name} is a decision lens, not a definition to memorize.`,
    anchorDescription: `Walmart’s FY2024 annual report provides real income statement, balance sheet, and return-reconciliation fields for ${name}.`,
    sourceList,
    mechanics: outcomes.mechanics,
    formula,
    knowledgeMap: { whyItExists: sections['conceptual-foundation'][0], informationIsolated: sections['conceptual-foundation'][1], decisionEnabled: sections.interpretation[1], validityAssumptions: sections['assumptions-limitations'][0], criticalQuestion: sections.interpretation[2] },
    sections,
    governing: outcomes.question,
    eli5: sections.eli5,
    definitions: ['revenue', 'grossProfit', 'operatingIncome', 'netIncome', 'assets', 'equity', 'investedCapital', 'nopat'].map(definitionFor),
    coverage: [coverage('numerator and denominator logic', 'Conceptual Foundation', ['revenue', 'assets', 'equity']), coverage('economic drivers', 'Economic Logic', ['grossProfit', 'operatingIncome']), coverage('return conventions and limits', 'Formula Construction', ['netIncome', 'investedCapital', 'nopat'])],
    questions: answers,
  };
}

function makeYieldCurveSpec(topic) {
  const sourceList = [
    source('treasury_yield_curve_jan_2022', 'U.S. Treasury Daily Treasury Par Yield Curve Rates, January 2022', 'https://home.treasury.gov/resource-center/data-chart-center/interest-rates/TextView?field_tdr_date_value_month=202201&type=daily_treasury_yield_curve'),
    source('treasury_yield_curve_dec_2023', 'U.S. Treasury Daily Treasury Par Yield Curve Rates, December 2023', 'https://home.treasury.gov/resource-center/data-chart-center/interest-rates/TextView?field_tdr_date_value=202312&type=daily_treasury_yield_curve'),
  ];
  const names = { yield_curve: 'Yield Curve', normal_yield_curve: 'Normal Yield Curve', inverted_yield_curve: 'Inverted Yield Curve' };
  const name = names[topic.topic_id];
  const normal = { date: 'January 3, 2022', short: '0.78%', long: '1.63%', slope: '+0.85 percentage points' };
  const inverted = { date: 'December 1, 2023', short: '4.73%', long: '4.22%', slope: '-0.51 percentage points' };
  const focus = topic.topic_id === 'normal_yield_curve'
    ? { title: 'The long end carried the higher yield.', question: 'Why can longer maturity require a higher yield than shorter maturity, and what does that upward slope price?', mechanics: 'A normal curve places longer-maturity yields above shorter-maturity yields. On January 3, 2022, the 10-year Treasury yield was 1.63% and the 2-year yield was 0.78%, producing a positive 0.85 percentage-point slope.', signal: 'term premium, expected inflation, expected short rates, and compensation for duration risk', decision: 'how to finance across maturities and how to distinguish a higher long rate from a forecast of stronger growth', formula: String.raw`\text{10Y minus 2Y slope} = y_{10Y} - y_{2Y}`, eli5: 'On January 3, 2022, investors demanded more yield to lend for ten years than for two years. The longer loan carried more time and uncertainty.', limit: 'An upward slope does not prove that growth will accelerate. It can also reflect inflation risk, term premium, or supply and demand for duration.' }
    : topic.topic_id === 'inverted_yield_curve'
      ? { title: 'The two-year yield rose above the ten-year yield.', question: 'Why can short-term yields exceed long-term yields, and what does that inversion reveal about expected policy and future conditions?', mechanics: 'An inverted curve places shorter-maturity yields above longer-maturity yields. On December 1, 2023, the 2-year Treasury yield was 4.73% and the 10-year yield was 4.22%, producing a negative 0.51 percentage-point slope.', signal: 'expected future short rates, policy restraint, inflation expectations, term premium, and demand for long-duration safety', decision: 'how to interpret market expectations without treating inversion as a deterministic recession signal', formula: String.raw`\text{10Y minus 2Y slope} = y_{10Y} - y_{2Y}`, eli5: 'On December 1, 2023, investors demanded more yield for lending two years than ten years. That pattern said the market viewed near-term policy as unusually tight relative to the longer horizon.', limit: 'An inversion is a market-pricing condition, not a calendar forecast. It can persist, flatten, or reverse before the economy turns.' }
      : { title: 'The curve changed shape because the time horizon changed the question.', question: 'What does the pattern of yields across maturities reveal about the market’s pricing of time, inflation, policy, growth, and duration risk?', mechanics: 'A yield curve maps yields across maturities. The 10-year minus 2-year slope was +0.85 percentage points on January 3, 2022 and -0.51 percentage points on December 1, 2023, so the same comparison moved from upward sloping to inverted.', signal: 'the market’s term structure of interest rates and the expectations and risk premia embedded in each maturity', decision: 'how to price debt, value fixed-income cash flows, assess duration exposure, and interpret the policy cycle', formula: String.raw`\text{10Y minus 2Y slope} = y_{10Y} - y_{2Y}`, eli5: 'A yield curve is a list of interest rates for different lending periods. Put the rates on a graph and the shape shows how the market prices short and long time horizons.', limit: 'The curve is not a pure survey of expected rates. It combines expected future short rates with term premium, liquidity, convexity, supply, demand, and technical positioning.' };
  const glossary = {
    maturity: { term: 'Maturity', definition: 'The date on which a debt instrument’s principal is contractually repaid.', location: 'Bond terms and fixed-income market data.', financialInterpretation: 'It identifies the time horizon over which the investor carries rate, inflation, reinvestment, and credit exposure.', commonExaminationTrap: 'Treating maturity as the same thing as duration.' },
    yield: { term: 'Yield', definition: 'The annualized return implied by a security’s price, cash flows, and maturity under a stated convention.', location: 'Bond price and yield quotation.', financialInterpretation: 'It is the market price of lending over the instrument’s horizon, not a guaranteed realized return in every holding-period scenario.', commonExaminationTrap: 'Comparing yields without aligning compounding, credit quality, liquidity, and maturity.' },
    termStructure: { term: 'Term structure of interest rates', definition: 'The relationship between yields and maturities for otherwise comparable fixed-income instruments.', location: 'Yield-curve data and fixed-income valuation.', financialInterpretation: 'It organizes the market’s pricing of time, expected short rates, and maturity risk.', commonExaminationTrap: 'Assuming the entire curve is explained by expected future short rates alone.' },
    slope: { term: 'Yield-curve slope', definition: 'The difference between yields at two maturities, stated with the order of subtraction.', location: 'Derived from the yield curve.', financialInterpretation: 'It summarizes whether the curve rises or falls between the selected points.', commonExaminationTrap: 'Calling a curve inverted without stating the maturities or the sign convention.' },
    termPremium: { term: 'Term premium', definition: 'The compensation investors require for holding a longer-maturity bond rather than rolling shorter-maturity investments with equivalent expected returns.', location: 'Derived fixed-income interpretation.', financialInterpretation: 'It can steepen or flatten the curve independently of expected future short rates.', commonExaminationTrap: 'Treating a long-term yield as a direct forecast of the average future policy rate.' },
    duration: { term: 'Duration', definition: 'A measure of a bond price’s sensitivity to a change in yield, adjusted for the timing of cash flows.', location: 'Bond valuation and risk analysis.', financialInterpretation: 'Longer duration makes a security more sensitive to changes in the relevant yield curve.', commonExaminationTrap: 'Using maturity alone to estimate price sensitivity.' },
  };
  const definitionFor = (id) => { const item = glossary[id]; return definition(id, item.term, 'Fixed income', item.definition, item.financialInterpretation, item.commonExaminationTrap); };
  const sections = {
    'case-context': [`The U.S. Treasury reported a 2-year yield of ${normal.short} and a 10-year yield of ${normal.long} on ${normal.date}. On ${inverted.date}, it reported ${inverted.short} for 2 years and ${inverted.long} for 10 years.`, `${name} matters because the rate changes with the maturity horizon. The shape is information about how the market prices time, policy, inflation, growth, and duration risk.`],
    'governing-question': [focus.question],
    'conceptual-foundation': [`${name} exists because one interest rate cannot describe the cost of money across every maturity. The curve places comparable yields on a time axis so the relationship between horizons becomes visible.`, focus.mechanics, `The signal is ${focus.signal}. The curve therefore provides a market-implied framework for comparing funding cost, reinvestment risk, valuation sensitivity, and expectations across time.`],
    'economic-logic': ['A longer maturity exposes the investor to more uncertainty about inflation, policy, reinvestment, liquidity, and the future price of risk. The required yield therefore includes more than a simple forecast of the central bank’s next move.', topic.topic_id === 'inverted_yield_curve' ? 'An inversion can arise when current policy is restrictive and investors expect future short rates to be lower, when long-duration assets attract safety demand, or when the term premium is unusually low. The shape identifies a pricing relationship; it does not identify one cause without decomposition.' : topic.topic_id === 'normal_yield_curve' ? 'An upward slope can reflect expected increases in future short rates, positive term premium, inflation uncertainty, or a supply and demand imbalance in long-duration securities. The slope is therefore a bundle of prices, not a single forecast.' : 'The curve combines expected future short rates with term premium and market technicals. A change in shape can come from the front end, the long end, or both, and the economic interpretation depends on which segment moved.', 'Treasury’s own methodology states that its par yields are interpolated from indicative bid-side quotations and read at fixed maturities. The data is a market measure with a defined construction process, not a direct observation of every borrower’s funding cost.'],
    'formula-construction': [`Using the dated Treasury fields, the selected curve type is identified by comparing the 10-year and 2-year maturities. ${focus.mechanics}`, 'The slope convention must be stated. This lesson uses the 10-year yield minus the 2-year yield. A positive result means the 10-year yield is higher; a negative result means the 2-year yield is higher.', `The observed slopes are ${normal.slope} on ${normal.date} and ${inverted.slope} on ${inverted.date}. The subtraction shows the direction of the relationship; the explanation requires expected rates, term premium, inflation, liquidity, supply, and demand.`],
    eli5: [focus.eli5, 'The line’s direction is a clue about how investors price time. It is not a complete prediction of the economy.', 'That distinction is why the curve is a diagnostic input to a forecast, not the forecast itself.'],
    'comparative-framework': ['A normal curve rises with maturity. A flat curve shows little difference between selected maturities. An inverted curve falls with maturity. These labels describe shape, not a complete macroeconomic diagnosis.', 'No universal slope threshold has the same meaning in every rate regime. Compare the same maturity pair across time, inspect the whole curve, and separate nominal yields from real yields and inflation expectations.', 'The 2-year versus 10-year slope is useful because it is widely followed, but it is not the whole curve. The front end, belly, and long end can send different signals.'],
    interpretation: [`The ${name} reading is the dated relationship captured by the Treasury data: ${focus.mechanics}`, `The decision is ${focus.decision}. The curve should change a financing, valuation, hedging, or macro assumption only after the investor identifies which maturities moved and why.`, 'A sophisticated reading asks whether the move came from expected short rates, term premium, inflation compensation, liquidity, technical demand, or a change in the policy path.'],
    'assumptions-limitations': ['The comparison assumes the two rates are measured on the same date, use the same Treasury par-yield methodology, and represent comparable risk-free nominal instruments.', focus.limit, 'The curve does not directly measure corporate credit spreads, bank funding costs, mortgage rates, or the realized path of future rates. Those decisions require adding credit, liquidity, optionality, and instrument-specific risk.'],
    'case-resolution': [`The Treasury observations resolve the lesson without a manufactured example. On ${normal.date}, the 10-year yield exceeded the 2-year yield by ${normal.slope}. On ${inverted.date}, the 10-year yield was below the 2-year yield by ${inverted.slope}.`, `The durable lesson is that ${name} is a relationship across maturities. The shape matters because it changes how a finance professional reads policy expectations, duration exposure, funding cost, and valuation risk.`],
  };
  const questions = [
    question('What does a yield curve show?', 'It shows the relationship between yields and maturities for comparable fixed-income instruments. The shape summarizes how the market prices time, expected short rates, and maturity risk.'),
    question('What is the difference between a normal and inverted curve?', 'A normal curve has longer-maturity yields above shorter-maturity yields. An inverted curve has shorter-maturity yields above longer-maturity yields. The sign must be tied to the maturities being compared.'),
    question('What does the 10-year minus 2-year slope measure?', 'It measures the yield difference between the 10-year and 2-year maturities. A positive result means the long rate is higher; a negative result means the short rate is higher.'),
    question('Why is an inverted curve not a recession forecast by itself?', 'The curve combines expected future short rates with term premium, liquidity, inflation compensation, supply, demand, and technical positioning. Inversion can be informative without determining timing or causation.'),
    question('What is term premium?', 'Term premium is compensation for holding longer maturity rather than rolling short instruments with the same expected return. It can move the long end independently of expected policy rates.'),
    question('Why does duration matter when reading the curve?', 'Duration measures price sensitivity to yield changes. Two securities with similar maturity can have different duration because their coupon and cash-flow timing differ.'),
    question('What happened in the two Treasury observations used here?', `The slope moved from ${normal.slope} on ${normal.date} to ${inverted.slope} on ${inverted.date}. The relationship changed from upward sloping to inverted.`),
    question('What should a finance student inspect after observing inversion?', 'Inspect the entire curve, the expected policy path, inflation compensation, term premium, credit spreads, lending standards, and the cash-flow sensitivity of the specific asset or liability.'),
    question('Why are Treasury par yields not identical to every bond’s yield?', 'Treasury par yields are interpolated curve points from indicative bid-side quotations at fixed maturities. A specific bond’s yield also reflects coupon, exact maturity, liquidity, and other security-specific features.'),
    question('How can a curve affect a company’s financing decision?', 'It changes the relative cost and risk of borrowing at different maturities. The company must weigh current coupon, refinancing risk, duration exposure, liquidity, and the probability that future rates differ from current prices.'),
  ];
  const formula = { label: '10-year minus 2-year slope', lhsLatex: String.raw`\text{10Y minus 2Y slope}`, relationLatex: '=', rhsLatex: String.raw`y_{10Y} - y_{2Y}`, latex: focus.formula, sourceId: 'treasury_yield_curve_dec_2023', glossary };
  return { title: focus.title, dek: `Two official Treasury observations show how the shape of the curve changes the question finance professionals ask.`, anchorDescription: `Official U.S. Treasury par-yield tables provide dated maturity points for ${name}.`, sourceList, mechanics: focus.mechanics, formula, knowledgeMap: { whyItExists: sections['conceptual-foundation'][0], informationIsolated: sections['conceptual-foundation'][2], decisionEnabled: sections.interpretation[1], validityAssumptions: sections['assumptions-limitations'][0], criticalQuestion: sections.interpretation[2] }, sections, governing: focus.question, eli5: sections.eli5, definitions: ['maturity', 'yield', 'termStructure', 'slope', 'termPremium', 'duration'].map(definitionFor), coverage: [coverage('term structure and slope', 'Conceptual Foundation', ['maturity', 'termStructure', 'slope']), coverage('market pricing mechanism', 'Economic Logic', ['yield', 'termPremium']), coverage('duration and decisions', 'Interpretation', ['duration'])], questions };
}

function makeWorkingCapitalSpec(topic) {
  const sourceList = [source('walmart_2024_annual_report', 'Walmart Inc. Annual Report 2024, statements of income, balance sheets, and cash flows', 'https://stock.walmart.com/_assets/_46796feebc5ddf6d2adbeabac9558ae9/walmart/db/950/9651/annual_report/Walmart_2024-AR-10K_Searchable.pdf')];
  const name = { cash_conversion_cycle: 'Cash Conversion Cycle', net_working_capital: 'Net Working Capital', working_capital: 'Working Capital' }[topic.topic_id];
  const d = { currentAssets: '$76,877 million', currentLiabilities: '$92,415 million', priorCurrentAssets: '$75,655 million', priorCurrentLiabilities: '$92,198 million', inventory: '$54,892 million', priorInventory: '$56,576 million', receivables: '$8,796 million', priorReceivables: '$7,933 million', payables: '$56,812 million', priorPayables: '$53,742 million', costOfSales: '$490,142 million', priorCostOfSales: '$463,721 million', netSales: '$642,637 million', priorNetSales: '$605,881 million' };
  const values = { averageInventory: '$55,734 million', averageReceivables: '$8,365 million', averagePayables: '$55,277 million', averageCostOfSales: '$476,932 million', averageNetSales: '$624,259 million', dio: '42.7 days', dso: '4.9 days', dpo: '42.3 days', ccc: '5.2 days', workingCapital: '-$15,538 million', priorWorkingCapital: '-$16,543 million' };
  const focus = topic.topic_id === 'cash_conversion_cycle'
    ? { title: 'The retailer received cash before every operating obligation was settled.', question: 'How long is cash tied up between paying suppliers and collecting from customers, and which operating process controls that interval?', mechanics: `Cash Conversion Cycle combines three timings. Walmart’s FY2024 fields produce ${values.dio} of inventory days plus ${values.dso} of receivable days minus ${values.dpo} of payable days, or ${values.ccc}.`, signal: 'inventory residence, customer collection, and supplier financing', decision: 'whether growth is consuming cash or being funded by operating-cycle efficiency', formula: String.raw`\text{CCC} = \text{DIO} + \text{DSO} - \text{DPO}`, eli5: `Walmart’s cash was tied up for about ${values.ccc} days after allowing for the time suppliers financed the business.`, limit: 'A short cycle does not guarantee liquidity. Seasonal purchases, restricted cash, debt maturities, and supplier withdrawal can overwhelm a favorable average.' }
    : topic.topic_id === 'net_working_capital'
      ? { title: 'A negative working-capital balance funded the operating cycle.', question: 'What operating capital is tied up in the business, and when does a negative balance strengthen liquidity rather than signal distress?', mechanics: `Net Working Capital under the stated broad convention equals current assets less current liabilities. Walmart reported ${d.currentAssets} of current assets and ${d.currentLiabilities} of current liabilities, producing ${values.workingCapital}.`, signal: 'the short-term funding gap between operating resources and near-term operating claims', decision: 'whether the business needs external funding or is receiving supplier and customer financing through its operating model', formula: String.raw`\text{Net working capital} = \text{Current assets} - \text{Current liabilities}`, eli5: `Walmart’s short-term bills were larger than its short-term assets by ${values.workingCapital.replace('-', '')}. That can work when customers pay quickly and suppliers are paid later.`, limit: 'The total is not a cash balance. Its meaning depends on asset quality, liability timing, inventory turnover, receivable collection, and supplier terms.' }
      : { title: 'Walmart’s current liabilities exceeded its current assets.', question: 'How does the current-asset and current-liability structure fund day-to-day operations, and what would make the same balance either efficient or dangerous?', mechanics: `Working Capital under the broad balance-sheet convention equals current assets less current liabilities. Walmart reported ${d.currentAssets} and ${d.currentLiabilities}, producing ${values.workingCapital}; management describes the retailer as generally operating with a working-capital deficit.`, signal: 'the short-term balance-sheet structure supporting the operating cycle', decision: 'whether the deficit reflects efficient supplier and customer timing or a deteriorating ability to meet claims', formula: String.raw`\text{Working capital} = \text{Current assets} - \text{Current liabilities}`, eli5: `Walmart had more short-term bills than short-term assets on the reporting date. The important question is when cash arrives and when each bill must be paid.`, limit: 'The total working-capital figure combines cash, receivables, inventory, prepaids, accounts payable, leases, taxes, and other claims with different timing and certainty.' };
  const glossary = {
    currentAssets: { term: 'Current assets', definition: 'Assets expected to be realized, sold, or consumed in the normal operating cycle or within the applicable short-term horizon.', location: 'Balance sheet.', financialInterpretation: 'They are the resource side of a short-term operating-funding comparison, but they do not share the same conversion certainty.', commonExaminationTrap: 'Treating every current asset as immediately available cash.' },
    currentLiabilities: { term: 'Current liabilities', definition: 'Obligations due for settlement within the applicable short-term horizon or normal operating cycle.', location: 'Balance sheet.', financialInterpretation: 'They establish the claims that operating assets, operating cash flow, supplier credit, or external funding must meet.', commonExaminationTrap: 'Ignoring the maturity and rollover pattern inside the current-liability total.' },
    inventory: { term: 'Inventory', definition: 'Goods held for sale or inputs held for production and service delivery.', location: 'Balance sheet and inventory note.', financialInterpretation: 'It can generate revenue but consumes cash until sold and collected.', commonExaminationTrap: 'Calling inventory liquid without testing demand, markdown, and conversion time.' },
    receivables: { term: 'Receivables', definition: 'Amounts due from customers or counterparties that the company expects to collect.', location: 'Balance sheet and receivables note.', financialInterpretation: 'They represent a claim on future cash and depend on collection timing, credit quality, and disputes.', commonExaminationTrap: 'Using revenue instead of receivables when measuring collection timing.' },
    payables: { term: 'Accounts payable', definition: 'Amounts owed to suppliers for goods and services already received.', location: 'Balance sheet and cash-flow statement.', financialInterpretation: 'They provide supplier financing until settlement and reduce the cash required to fund inventory.', commonExaminationTrap: 'Treating a longer payable period as free value without checking supplier terms and relationship risk.' },
    dio: { term: 'Days Inventory Outstanding', definition: 'Average inventory expressed as the number of days of cost of sales represented by that balance.', location: 'Derived from inventory and cost of sales.', financialInterpretation: 'It measures how long cash remains invested in inventory before sale.', commonExaminationTrap: 'Using revenue rather than cost of sales in the denominator.' },
    dso: { term: 'Days Sales Outstanding', definition: 'Average receivables expressed as the number of days of sales represented by that balance.', location: 'Derived from receivables and net sales.', financialInterpretation: 'It measures the collection interval after a sale is recognized.', commonExaminationTrap: 'Interpreting a lower DSO as better without checking credit terms, mix, and write-offs.' },
    dpo: { term: 'Days Payables Outstanding', definition: 'Average accounts payable expressed as the number of days of cost of sales represented by that balance.', location: 'Derived from accounts payable and cost of sales.', financialInterpretation: 'It measures supplier financing and the time between receiving goods and paying for them.', commonExaminationTrap: 'Assuming a higher DPO is sustainable without reading supplier terms or payment-program disclosures.' },
  };
  const definitionFor = (id) => { const item = glossary[id]; return definition(id, item.term, 'Working-capital analysis', item.definition, item.financialInterpretation, item.commonExaminationTrap); };
  const sections = {
    'case-context': [`Walmart reported ${d.currentAssets} of current assets, ${d.currentLiabilities} of current liabilities, ${d.inventory} of inventory, ${d.receivables} of receivables, and ${d.payables} of accounts payable at January 31, 2024.`, `${name} matters because operating growth changes the timing of cash receipts and payments before it changes reported profit.`],
    'governing-question': [focus.question],
    'conceptual-foundation': [`${name} exists because a balance sheet total hides the timing of the operating cycle. Cash leaves when inventory is purchased or suppliers are paid and returns only when customers pay.`, focus.mechanics, `The signal is ${focus.signal}. The measure is useful only when the underlying balances are connected to the company’s operating model.`],
    'economic-logic': ['Working capital is a timing system. Inventory and receivables consume cash before collection, while payables defer cash payment and can finance part of the operating cycle.', topic.topic_id === 'cash_conversion_cycle' ? 'The cash conversion cycle improves when inventory sells faster, customers pay sooner, or suppliers provide longer terms. Each improvement has a cost: lower inventory can reduce availability, tighter credit can reduce sales, and longer supplier terms can damage access or pricing.' : 'A negative working-capital balance can be efficient when customers pay at or near the point of sale and suppliers are paid later. It becomes dangerous when the deficit is funded by overdue obligations, shrinking inventory quality, weak collections, or forced refinancing.', 'Walmart’s filing states that the company generally operates with a working-capital deficit because of operating efficiency, access to capital markets, and shareholder returns. That explanation is a hypothesis to test against the cash-flow statement, not a substitute for the numbers.'],
    'formula-construction': [`Using the Walmart fields, the selected measure is calculated from the balance or timing relationship stated here. ${focus.mechanics}`, topic.topic_id === 'cash_conversion_cycle' ? `The inputs use average inventory of ${values.averageInventory}, average receivables of ${values.averageReceivables}, average payables of ${values.averagePayables}, average cost of sales of ${values.averageCostOfSales}, and average net sales of ${values.averageNetSales}.` : `The balance changed from ${values.priorWorkingCapital} in fiscal 2023 to ${values.workingCapital} in fiscal 2024. The calculation is a stock measure at the reporting date; the cash-flow statement explains the movement during the period.`, 'The denominator must match the economic flow. Inventory and payable days use cost of sales; receivable days use net sales. Mixing denominators creates a number with no coherent timing meaning.'],
    eli5: [focus.eli5, 'The balance sheet gives the position on one date. The cash-flow statement and operating-cycle measures show how that position moved and whether the business can repeat it.', 'That is why the number must be read with the operating process, not treated as a standalone liquidity verdict.'],
    'comparative-framework': [topic.topic_id === 'cash_conversion_cycle' ? 'Cash Conversion Cycle is a timing measure. Working Capital is a balance-sheet position. Neither replaces a cash-flow forecast, liquidity ratio, or debt-maturity analysis.' : 'Working Capital and Net Working Capital are often used as synonyms, but the finance professional must state whether the measure includes all current assets and liabilities or only operating balances.', 'No universal working-capital benchmark exists. Compare the company with businesses that share its inventory turn, customer payment model, supplier terms, seasonality, and channel mix.', 'The correct comparison is the company’s own trend plus the operating cycle behind the balance. A negative total can be healthy for one retailer and a warning for a manufacturer with slow collections.'],
    interpretation: [`Walmart’s ${name} result is ${topic.topic_id === 'cash_conversion_cycle' ? values.ccc : values.workingCapital}. It indicates ${focus.signal}.`, `The decision is ${focus.decision}. The result must be reconciled to inventory turns, receivables aging, supplier terms, cash flow, seasonality, and financing access.`, 'The sophisticated question is whether the observed timing is structural and repeatable or whether it is temporarily supported by delayed payments, inventory reduction, unusual demand, or a reporting-date effect.'],
    'assumptions-limitations': ['The measure assumes comparable periods, consistent accounting classifications, representative average balances, and annual flows that match the balance-sheet scope.', focus.limit, 'Working-capital measures ignore debt maturities, undrawn facilities, restricted cash, supplier concentration, customer defaults, and the funding cost of the operating cycle.'],
    'case-resolution': [`Walmart’s filing supplies the complete teaching chain. The company reported a working-capital deficit of ${values.workingCapital}, while the underlying balances produced ${values.dio} of inventory days, ${values.dso} of receivable days, and ${values.dpo} of payable days.`, `The durable lesson is that ${name} is a timing lens. Its meaning comes from the operating process that turns inventory into sales, sales into receivables, receivables into cash, and supplier obligations into payments.`],
  };
  const qs = [
    ['What does this measure isolate?', 'It isolates the timing or balance-sheet relationship specified by the formula. It does not replace a cash-flow forecast or a maturity analysis.'],
    ['Why is inventory not cash?', 'Inventory requires demand, sale, collection, and often continued operating expenditure. Its reported balance is therefore not equal to immediate payment capacity.'],
    ['Why do receivables use sales while inventory and payables use cost of sales?', 'Receivables arise from sales, while inventory consumption and supplier obligations are linked more closely to cost of sales. Matching each balance to its economic flow preserves timing meaning.'],
    ['Why can negative working capital be efficient?', 'Customer cash can arrive before supplier settlement, allowing the operating cycle to finance itself. The conclusion is valid only when the timing is stable and the claims remain payable.'],
    ['What makes a working-capital deficit dangerous?', 'Slow collections, obsolete inventory, supplier withdrawal, overdue payables, seasonal cash needs, or debt maturities can turn a timing advantage into a liquidity shortfall.'],
    ['What is the difference between a balance measure and a timing measure?', 'Working capital measures a position at a date. Cash Conversion Cycle measures the average timing of inventory, collection, and supplier settlement during a period.'],
    ['Why should average balances be used?', 'A year-end balance can be unusually high or low because of seasonality, purchasing timing, or reporting-date management. Average balances better approximate the resources deployed during the period.'],
    ['What did Walmart’s filing reveal?', `It reported ${values.workingCapital} of working capital under the broad convention and a cash conversion cycle of about ${values.ccc} days under the stated flow and average-balance convention.`],
    ['How would you test whether the result is sustainable?', 'Review monthly or quarterly trends, inventory aging, receivables aging, supplier terms, cash conversion, payment-program disclosures, seasonality, and the availability of committed financing.'],
    ['What is the most common examination error?', 'Treating a low or negative balance as automatically bad, or treating a short cycle as automatically safe without examining the quality and timing of the underlying cash flows.'],
  ].map(([q, a]) => question(q, a));
  const formula = { label: name, lhsLatex: String.raw`\text{${name}}`, relationLatex: '=', rhsLatex: focus.formula.replace(String.raw`\text{${name}} = `, ''), latex: focus.formula, sourceId: 'walmart_2024_annual_report', glossary };
  return { title: focus.title, dek: `Walmart’s FY2024 filing shows how operating timing can matter more than a headline balance-sheet total.`, anchorDescription: `Walmart’s FY2024 annual report provides the real balance-sheet and cash-flow fields used to teach ${name}.`, sourceList, mechanics: focus.mechanics, formula, knowledgeMap: { whyItExists: sections['conceptual-foundation'][0], informationIsolated: sections['conceptual-foundation'][2], decisionEnabled: sections.interpretation[1], validityAssumptions: sections['assumptions-limitations'][0], criticalQuestion: sections.interpretation[2] }, sections, governing: focus.question, eli5: sections.eli5, definitions: ['currentAssets', 'currentLiabilities', 'inventory', 'receivables', 'payables', 'dio', 'dso', 'dpo'].map(definitionFor), coverage: [coverage('operating balances', 'Conceptual Foundation', ['currentAssets', 'currentLiabilities', 'inventory']), coverage('cash timing', 'Economic Logic', ['receivables', 'payables']), coverage('days and interpretation', 'Formula Construction', ['dio', 'dso', 'dpo'])], questions: qs };
}

function makeLeverageSpec(topic) {
  const sourceList = [source('walmart_2024_annual_report', 'Walmart Inc. Annual Report 2024, statements of income, balance sheets, and cash flows', 'https://stock.walmart.com/_assets/_46796feebc5ddf6d2adbeabac9558ae9/walmart/db/950/9651/annual_report/Walmart_2024-AR-10K_Searchable.pdf')];
  const name = { asset_coverage_ratio: 'Asset Coverage Ratio', debt_service_coverage_ratio: 'Debt Service Coverage Ratio', debt_to_equity_ratio: 'Debt to Equity Ratio', fixed_charge_coverage_ratio: 'Fixed Charge Coverage Ratio', ffo_to_debt: 'FFO to Debt', interest_coverage_ratio: 'Interest Coverage Ratio', net_leverage_ratio: 'Net Leverage Ratio', total_leverage_ratio: 'Total Leverage Ratio' }[topic.topic_id];
  const d = { debt: '$40,457 million, excluding lease obligations', cash: '$9,867 million', currentDebt: '$4,325 million', longDebt: '$36,132 million', interest: '$2,683 million including debt interest of $2,259 million and finance-lease interest of $424 million', operatingIncome: '$27,012 million', da: '$11,853 million', ebitda: '$38,865 million, calculated as operating income plus depreciation and amortisation', assets: '$252,399 million', goodwill: '$28,113 million', equity: '$90,349 million', cfo: '$35,726 million', principal: '$4,217 million', cashInterest: '$2,519 million' };
  const focus = { asset_coverage_ratio: { title: 'The balance sheet carried more than one layer of recovery value.', question: 'How much asset value stands behind debt after removing less tangible assets, and how much cushion remains under a stressed recovery?', mechanics: `Using tangible assets as total assets less goodwill, Walmart’s coverage is approximately 5.5x: (${d.assets} − ${d.goodwill}) / ${d.debt}.`, signal: 'asset cushion available to creditors after removing goodwill under the stated convention', decision: 'whether collateral value provides a meaningful recovery buffer if earnings and cash flow fail', formula: String.raw`\text{Asset coverage} = \frac{\text{Total assets} - \text{Intangible assets}}{\text{Debt}}`, eli5: 'Remove goodwill from the assets, then compare what remains with debt. The result is about 5.5 times debt under this convention.', limit: 'Book assets are not liquidation values. Recovery depends on market value, seniority, liens, execution costs, and the distinction between operating assets and collateral.' },
    debt_service_coverage_ratio: { title: 'Operating cash flow covered the payments debt required.', question: 'Can operating cash flow cover the interest and principal payments that must be made during the period?', mechanics: `Using cash flow from operations divided by cash interest paid plus principal repayments, Walmart’s coverage is approximately 5.3x: ${d.cfo} / (${d.cashInterest} + ${d.principal}).`, signal: 'cash repayment capacity after the operating cycle has produced cash', decision: 'whether current operations can service debt without relying on asset sales or refinancing', formula: String.raw`\text{DSCR} = \frac{\text{Cash flow from operations}}{\text{Cash interest} + \text{Principal repayments}}`, eli5: 'Walmart generated about $35.7 billion from operations and had about $6.7 billion of interest and principal payments, giving roughly 5.3 times coverage.', limit: 'A single year of operating cash flow may be inflated by working-capital timing and does not prove that every future maturity can be paid.' },
    debt_to_equity_ratio: { title: 'Debt was only one part of Walmart’s capital structure.', question: 'How much interest-bearing debt supports each dollar of total equity, and what does that financing mix imply for risk?', mechanics: `Walmart’s debt to equity is approximately 0.45x: ${d.debt} / ${d.equity}. The debt scope excludes lease obligations and is stated so the comparison is reproducible.`, signal: 'the contractual debt claim relative to the accounting equity cushion', decision: 'whether leverage is increasing the sensitivity of equity value and earnings to operating volatility', formula: String.raw`\text{Debt to equity} = \frac{\text{Interest-bearing debt}}{\text{Total equity}}`, eli5: 'Walmart had about 45 cents of interest-bearing debt for each dollar of total equity under the stated debt definition.', limit: 'Equity is an accounting residual and can be reduced by buybacks, losses, or accumulated other comprehensive income without a matching change in debt risk.' },
    fixed_charge_coverage_ratio: { title: 'Operating profit had to cover both financing and fixed operating charges.', question: 'How much operating profit is available after adding back fixed operating charges to cover interest and those fixed charges?', mechanics: `Using operating income plus rent divided by interest plus rent, Walmart’s fixed-charge coverage is approximately 5.9x: ($27,012m + $2,277m) / ($2,683m + $2,277m).`, signal: 'the ability of the operating platform to cover financing cost and a recurring fixed operating charge', decision: 'whether fixed commitments leave enough operating margin for a downturn', formula: String.raw`\text{Fixed charge coverage} = \frac{\text{EBIT} + \text{Fixed charges}}{\text{Interest} + \text{Fixed charges}}`, eli5: 'Add rent back to operating profit, then ask how many times that total covers rent and interest. The stated result is about 5.9 times.', limit: 'Rent, interest, and fixed charges require consistent definitions. The ratio can overstate safety if the fixed charge is understated or if operating profit contains temporary gains.' },
    ffo_to_debt: { title: 'The operating cash engine supported most of the debt balance.', question: 'What proportion of debt is supported by recurring funds generated before working-capital timing effects?', mechanics: `Under the stated pre-working-capital convention, FFO is approximately $33,783 million: ${d.cfo} less net working-capital movements of approximately $1,943 million. FFO to debt is therefore approximately 83.5%: $33,783m / ${d.debt}.`, signal: 'recurring operating funds relative to the debt claim before short-term working-capital timing', decision: 'whether debt is supported by repeatable internal funds rather than a temporary cash release', formula: String.raw`\text{FFO to debt} = \frac{\text{Funds from operations}}{\text{Debt}}`, eli5: 'Remove the temporary working-capital timing from operating cash flow, then compare the remaining funds with debt. The result is about 83.5% under this convention.', limit: 'FFO is not a single GAAP line. The result depends on which cash-flow adjustments are treated as temporary and must not be called a rating-agency measure without adopting that agency’s methodology.' },
    interest_coverage_ratio: { title: 'The interest line was small relative to operating income, but not irrelevant.', question: 'How many times does operating income cover the interest expense that debt creates?', mechanics: `Using operating income divided by debt interest plus finance-lease interest, Walmart’s interest coverage is approximately 10.1x: ${d.operatingIncome} / ${d.interest}.`, signal: 'the operating earnings buffer above contractual interest expense', decision: 'whether a fall in operating earnings could threaten interest payment capacity before principal becomes due', formula: String.raw`\text{Interest coverage} = \frac{\text{EBIT}}{\text{Interest expense}}`, eli5: 'Walmart’s operating income was about ten times its interest expense under the stated scope.', limit: 'Interest coverage ignores principal maturities, cash taxes, capital expenditure, leases outside the chosen scope, and the possibility that EBIT falls sharply.' },
    net_leverage_ratio: { title: 'Cash reduced the debt burden, but did not erase it.', question: 'How much debt remains after cash is netted against it relative to operating earnings?', mechanics: `Walmart’s net leverage is approximately 0.79x: (${d.debt} − ${d.cash}) / ${d.ebitda}.`, signal: 'the debt claim that remains after immediately available cash is considered relative to EBITDA', decision: 'whether operating earnings and cash together provide flexibility under a credit stress', formula: String.raw`\text{Net leverage} = \frac{\text{Debt} - \text{Cash}}{\text{EBITDA}}`, eli5: 'Subtract cash from debt, then compare what remains with operating earnings before depreciation. Walmart’s result is about 0.8 times.', limit: 'Cash may be restricted, trapped, operationally required, or needed for working capital. EBITDA is an accrual proxy, not cash available for debt repayment.' },
    total_leverage_ratio: { title: 'The debt burden was measured against earnings before noncash depreciation.', question: 'How large is total interest-bearing debt relative to operating earnings before depreciation and amortisation?', mechanics: `Walmart’s total leverage is approximately 1.04x: ${d.debt} / ${d.ebitda}.`, signal: 'the debt claim relative to a pre-depreciation operating earnings proxy', decision: 'whether the company’s operating scale can support its debt before considering cash, tax, capital expenditure, and working capital', formula: String.raw`\text{Total leverage} = \frac{\text{Debt}}{\text{EBITDA}}`, eli5: 'Compare debt with operating earnings before depreciation. Walmart’s debt was about one year of that earnings measure under the stated convention.', limit: 'EBITDA excludes cash taxes, interest, capital expenditure, working-capital investment, and lease economics. It must not be treated as free cash flow.' },
  }[topic.topic_id];
  const glossary = {
    debt: { term: 'Interest-bearing debt', definition: 'Borrowed principal that creates contractual interest or financing obligations, measured under the stated inclusion convention.', location: 'Balance sheet and debt notes.', financialInterpretation: 'It is the contractual claim that leverage and coverage ratios test against earnings, cash flow, assets, or equity.', commonExaminationTrap: 'Mixing leases, pensions, trade payables, and debt without stating the scope.' },
    ebit: { term: 'EBIT', definition: 'Earnings before interest and income tax, used as an operating earnings measure before financing and tax.', location: 'Income statement or derived from operating income.', financialInterpretation: 'It tests operating earnings capacity against interest and fixed claims.', commonExaminationTrap: 'Calling EBIT cash flow or treating operating income and EBIT as identical when nonoperating items are included.' },
    ebitda: { term: 'EBITDA', definition: 'Earnings before interest, income tax, depreciation, and amortisation under a stated reconciliation.', location: 'Income statement and non-GAAP reconciliation.', financialInterpretation: 'It approximates pre-depreciation operating earnings but does not represent cash available for debt service.', commonExaminationTrap: 'Using EBITDA as a substitute for cash flow without deducting taxes, capital expenditure, and working capital.' },
    cashFlow: { term: 'Cash flow from operations', definition: 'Cash generated or consumed by operating activities during the reporting period under the cash-flow statement classification.', location: 'Statement of cash flows.', financialInterpretation: 'It is the cash source used in a cash-coverage test, subject to working-capital timing and other adjustments.', commonExaminationTrap: 'Assuming one year of operating cash flow is recurring free cash flow.' },
    equity: { term: 'Total equity', definition: 'The residual accounting claim after liabilities, including the applicable parent and noncontrolling interests.', location: 'Balance sheet.', financialInterpretation: 'It is the accounting capital base against which debt can be compared, not a liquidation cushion equal to market value.', commonExaminationTrap: 'Using total equity with a numerator that excludes noncontrolling interests without explaining the mismatch.' },
    fixedCharges: { term: 'Fixed charges', definition: 'Recurring contractual or operating charges that must be paid or incurred with limited short-term flexibility, such as rent under the stated convention.', location: 'Income statement, lease notes, and derived coverage analysis.', financialInterpretation: 'They compete with interest for operating cash and reduce flexibility in a downturn.', commonExaminationTrap: 'Assuming all fixed charges are captured by one universal formula.' },
    ffo: { term: 'Funds from operations', definition: 'A defined measure of recurring funds generated by operations before selected working-capital or noncash adjustments, with the methodology stated explicitly.', location: 'Derived from cash-flow data and rating methodology where applicable.', financialInterpretation: 'It tests recurring internal support for debt rather than a temporary balance-sheet cash release.', commonExaminationTrap: 'Presenting a lesson-defined FFO measure as if it were a standardized GAAP line.' },
    tangibleAssets: { term: 'Tangible assets', definition: 'Assets remaining after removing intangible assets under the stated coverage convention.', location: 'Balance sheet and asset-coverage analysis.', financialInterpretation: 'They are used as a rough book-value proxy for recovery support, subject to market-value and seniority limits.', commonExaminationTrap: 'Treating book tangible assets as cash proceeds in liquidation.' },
  };
  const definitionFor = (id) => { const item = glossary[id]; return definition(id, item.term, 'Corporate credit analysis', item.definition, item.financialInterpretation, item.commonExaminationTrap); };
  const sections = {
    'case-context': [`Walmart reported total assets of ${d.assets}, goodwill of ${d.goodwill}, total equity of ${d.equity}, cash of ${d.cash}, operating income of ${d.operatingIncome}, and cash flow from operations of ${d.cfo} for or at January 31, 2024.`, `${name} matters because debt risk is not visible in the debt balance alone. Credit analysis asks what resource, earnings stream, or cash flow supports the claim and under what stress that support fails.`],
    'governing-question': [focus.question],
    'conceptual-foundation': [`${name} exists to connect a debt claim with the resource that must support it. The numerator and denominator are not interchangeable: assets test recovery, earnings test coverage, cash flow tests payment, and equity tests the financing mix.`, focus.mechanics, `The signal is ${focus.signal}. That signal becomes useful only after the debt scope and accounting convention are made explicit.`],
    'economic-logic': ['Leverage creates fixed claims against a business whose operating earnings and cash flow can vary. The more fixed the claim, the more important the buffer between operating performance and required payment.', topic.topic_id === 'debt_to_equity_ratio' ? 'Debt to equity describes financing mix, not repayment capacity. A company can have low debt to equity and weak cash flow, or higher debt to equity with stable recurring cash generation.' : topic.topic_id === 'asset_coverage_ratio' ? 'Asset coverage is a recovery lens. It matters most when the enterprise cannot be valued only through going-concern earnings and creditors need to know what remains after a forced realization.' : 'Coverage and leverage ratios answer different questions. EBITDA leverage describes scale of debt relative to earnings, while debt service coverage asks whether actual operating cash paid the required interest and principal.', 'The same number can be safe or dangerous depending on earnings volatility, maturity concentration, refinancing access, capital expenditure, working-capital intensity, and creditor priority.'],
    'formula-construction': [`The calculation below makes the debt scope and support convention visible. ${focus.mechanics}`, 'The ratio is only reproducible when the numerator and denominator use the same reporting date, entity scope, debt scope, and accounting convention. Every adjustment must be shown rather than hidden inside an apparently precise output.', `The result is the stated convention for ${name}. It is a diagnostic input to a credit judgment, not a standalone rating or default probability.`],
    eli5: [focus.eli5, 'A coverage ratio asks whether the resource that pays the claim is large enough and repeatable enough. A leverage ratio asks how large the claim is relative to the chosen earnings or capital base.', 'The number is useful only when the debt definition and the resource that supports it are clearly matched.'],
    'comparative-framework': ['Asset coverage, debt to equity, leverage, interest coverage, debt service coverage, and FFO to debt are related but not substitutes. Each selects a different support mechanism and therefore fails under a different stress.', 'No universal credit threshold applies across sectors, currencies, lease structures, business models, and rating methodologies. Compare the company with its own history, peers with similar cash-flow risk, and the maturity schedule.', 'A lender or ratings committee should read the ratio with cash-flow volatility, secured versus unsecured debt, covenants, liquidity sources, refinancing needs, and recovery priority.'],
    interpretation: [`Walmart’s ${name} result is embedded in the stated convention: ${focus.mechanics}`, `The decision is ${focus.decision}. A strong result reduces one form of concern, but it does not remove refinancing, liquidity, collateral, or business-risk questions.`, 'The sophisticated question is what changes first under stress: earnings, cash, asset value, equity, or access to refinancing. The ratio is valuable because it identifies the first support mechanism to test.'],
    'assumptions-limitations': ['The ratio assumes the debt scope, earnings measure, cash availability, asset value, and accounting period are comparable and economically aligned.', focus.limit, 'The result is not a rating. It does not predict default without a broader analysis of business risk, liquidity, maturity, covenants, recovery, and management response.'],
    'case-resolution': [`Walmart’s filing supplies the real credit bridge. The relevant fields include ${d.debt} of debt, ${d.operatingIncome} of operating income, ${d.ebitda} of EBITDA, ${d.cfo} of operating cash flow, and ${d.cash} of cash.`, `The durable lesson is that ${name} is a deliberately partial credit lens. A sound conclusion follows the support chain from reported accounting numbers to payment capacity, asset recovery, capital structure, and stress behavior.`],
  };
  const qs = [
    ['What does this ratio measure?', 'It measures the relationship specified by the stated convention between debt and the supporting asset, earnings, cash-flow, or equity base. It is not a complete credit conclusion.'],
    ['Why must the debt scope be stated?', 'Including or excluding lease obligations, current maturities, restricted cash, or trade liabilities can materially change the result. A ratio without scope cannot be compared reliably.'],
    ['How is leverage different from coverage?', 'Leverage compares debt with a capital or earnings base. Coverage compares earnings or cash flow with a required payment. Leverage describes burden; coverage describes capacity.'],
    ['Why is EBITDA not free cash flow?', 'EBITDA excludes cash taxes, interest, capital expenditure, working-capital investment, and other cash requirements. It is a pre-depreciation earnings proxy, not distributable cash.'],
    ['Why can asset coverage overstate recovery?', 'Book assets may sell below carrying value, may be operationally interdependent, may be pledged to other creditors, and may incur costs during liquidation.'],
    ['Why can debt service coverage change without new debt?', 'Operating cash flow can move because of earnings, inventory, receivables, payables, taxes, and timing. The denominator can also move when principal or interest payments change.'],
    ['What did Walmart’s filing make visible?', `It disclosed ${d.debt} of debt, ${d.cash} of cash, ${d.operatingIncome} of operating income, and ${d.cfo} of operating cash flow, allowing the lesson’s support chain to be calculated from primary fields.`],
    ['What would make the conclusion weaker?', 'A fall in operating income, a working-capital cash release reversing, restricted cash, higher refinancing needs, asset impairment, covenant pressure, or a change in debt priority would weaken the conclusion.'],
    ['How should a finance professional compare this ratio?', 'Use consistent conventions across time and peers, then add maturity, volatility, liquidity, covenants, secured debt, recovery value, and the cost of refinancing.'],
    ['What is the most common examination error?', 'Treating a single ratio as a rating, hiding the convention, or using a reported earnings proxy as though it were cash available to repay debt.'],
  ].map(([q, a]) => question(q, a));
  const formula = { label: name, lhsLatex: String.raw`\text{${name}}`, relationLatex: '=', rhsLatex: focus.formula.replace(String.raw`\text{${name}} = `, ''), latex: focus.formula, sourceId: 'walmart_2024_annual_report', glossary };
  return { title: focus.title, dek: `Walmart’s FY2024 filing shows how corporate credit ratios connect debt with the resource that must support it.`, anchorDescription: `Walmart’s FY2024 annual report provides real debt, cash, earnings, asset, equity, and cash-flow fields for ${name}.`, sourceList, mechanics: focus.mechanics, formula, knowledgeMap: { whyItExists: sections['conceptual-foundation'][0], informationIsolated: sections['conceptual-foundation'][2], decisionEnabled: sections.interpretation[1], validityAssumptions: sections['assumptions-limitations'][0], criticalQuestion: sections.interpretation[2] }, sections, governing: focus.question, eli5: sections.eli5, definitions: ['debt', 'ebit', 'ebitda', 'cashFlow', 'equity', 'fixedCharges', 'ffo', 'tangibleAssets'].map(definitionFor), coverage: [coverage('debt and support base', 'Conceptual Foundation', ['debt', 'equity', 'tangibleAssets']), coverage('earnings and cash capacity', 'Economic Logic', ['ebit', 'ebitda', 'cashFlow']), coverage('credit conventions and limits', 'Formula Construction', ['fixedCharges', 'ffo'])], questions: qs };
}

function makeMnaSpec(topic) {
  const sourceList = [
    source('microsoft_activision_8k', 'Microsoft Form 8-K announcing the Activision Blizzard transaction', 'https://www.sec.gov/Archives/edgar/data/789019/000119312522010667/d301984d8k.htm'),
    source('activision_merger_proxy', 'Activision Blizzard definitive merger proxy statement', 'https://www.sec.gov/Archives/edgar/data/718877/000110465922025210/tm225196-3_prem14a.htm'),
    source('microsoft_2024_10k', 'Microsoft Form 10-K 2024, Activision Blizzard business combination', 'https://www.sec.gov/Archives/edgar/data/789019/000095017024087843/msft-20240630.htm'),
  ];
  const glossary = {
    acquirer: { term: 'Acquirer', definition: 'The entity that obtains control of the target in a business combination.', location: 'Merger agreement and consolidated financial statements.', financialInterpretation: 'The acquirer determines the transaction funding, accounting, integration mandate, and post-close reporting boundary.', commonExaminationTrap: 'Confusing legal merger form with which entity controls the combined business.' },
    target: { term: 'Target', definition: 'The business or entity whose control is obtained by the acquirer.', location: 'Merger agreement, proxy statement, and target financial statements.', financialInterpretation: 'The target supplies the operations, assets, liabilities, and risks that must be valued and integrated.', commonExaminationTrap: 'Treating the target’s standalone market price as the full purchase price.' },
    consideration: { term: 'Purchase consideration', definition: 'The value transferred by the acquirer to obtain control of the target, including cash, shares, contingent consideration, or other instruments.', location: 'Merger agreement and acquisition accounting note.', financialInterpretation: 'It establishes the economic cost that must be funded and allocated in acquisition accounting.', commonExaminationTrap: 'Using the announcement value without checking closing adjustments and the accounting purchase price.' },
    cashConsideration: { term: 'Cash consideration', definition: 'The cash component transferred to target shareholders or other selling parties at closing.', location: 'Merger agreement and financing disclosures.', financialInterpretation: 'It creates funding needs and transfers value without issuing new acquirer equity.', commonExaminationTrap: 'Calling an all-cash deal debt free when the acquirer may borrow to fund it.' },
    exchangeRatio: { term: 'Exchange ratio', definition: 'The number of acquirer shares received for each target share in a stock-based merger.', location: 'Merger agreement consideration section.', financialInterpretation: 'It determines dilution, relative ownership, and how transaction value moves with the acquirer’s share price.', commonExaminationTrap: 'Applying an exchange ratio to an all-cash transaction.' },
    goodwill: { term: 'Goodwill', definition: 'The residual amount recognized when purchase consideration exceeds the fair value of identifiable net assets acquired and assumed liabilities.', location: 'Acquisition accounting note and balance sheet.', financialInterpretation: 'It captures purchased economic benefits that do not qualify as separately identifiable assets, but it is subject to impairment risk.', commonExaminationTrap: 'Treating goodwill as a cash-generating asset that can be amortized like acquired technology.' },
    identifiableIntangibles: { term: 'Identifiable intangible assets', definition: 'Nonphysical assets acquired in a business combination that are separable or arise from contractual or legal rights and can be valued separately from goodwill.', location: 'Acquisition accounting note and intangible asset note.', financialInterpretation: 'Their allocation affects amortization, future earnings, tax effects, and the residual goodwill balance.', commonExaminationTrap: 'Putting every expected synergy into identifiable intangibles.' },
    control: { term: 'Control', definition: 'The power to direct the relevant activities of another entity and obtain its variable returns, normally through ownership or contractual rights.', location: 'Merger agreement and consolidation accounting policy.', financialInterpretation: 'Control determines when the target enters the acquirer’s consolidated financial statements.', commonExaminationTrap: 'Treating announcement or economic influence as the same as accounting control.' },
  };
  const definitionFor = (id) => { const item = glossary[id]; return definition(id, item.term, 'Mergers and acquisitions', item.definition, item.financialInterpretation, item.commonExaminationTrap); };
  const commonFormulaGlossary = glossary;
  const configs = {
    mergers_and_acquisitions: {
      title: 'Microsoft bought Activision before it could consolidate the business.',
      dek: 'The transaction shows that an acquisition is a control decision, a financing decision, and an accounting event at the same time.',
      governing: 'How does an acquisition transfer control, determine the price paid, and change the acquirer’s financial statements?',
      mechanics: 'A merger or acquisition transfers control of a target to an acquirer. The finance work links strategic rationale, valuation, consideration, financing, regulatory conditions, execution risk, and post-close accounting.',
      formula: { label: 'Enterprise purchase value', lhsLatex: String.raw`\text{Enterprise purchase value}`, relationLatex: '=', rhsLatex: String.raw`\text{Equity consideration}\;+\;\text{Debt assumed}\;-\;\text{Cash acquired}`, latex: String.raw`\text{Enterprise purchase value} = \text{Equity consideration}\;+\;\text{Debt assumed}\;-\;\text{Cash acquired}`, glossary: commonFormulaGlossary },
      eli5: ['An acquisition means one company takes control of another company.', 'The buyer must decide what to pay, how to fund it, what risks it is taking, and what the purchase changes in the financial statements.'],
      sections: {
        'case-context': ['On January 18, 2022, Microsoft announced an agreement to acquire Activision Blizzard for $95 per share in an all-cash transaction valued at $68.7 billion, inclusive of Activision Blizzard’s net cash. Microsoft completed the acquisition on October 13, 2023.', 'The time between announcement and closing matters. The transaction had to survive regulatory review, preserve the target business, and remain economically justified while both companies continued to operate independently.'],
        'conceptual-foundation': ['An acquisition is the purchase of control over a business. The headline price is only the beginning of the analysis because control brings operating assets, liabilities, intangible assets, employees, legal exposure, and integration obligations.', 'The transaction must be evaluated from three linked perspectives. Strategy asks what capability or market position is being bought. Valuation asks whether the expected benefits justify the consideration. Accounting asks how the acquired assets, liabilities, goodwill, and post-close earnings will be recognized.', 'The acquirer’s announcement date and accounting acquisition date can differ. The latter determines when the target enters the consolidated statements.'],
        'economic-logic': ['Microsoft described the strategic rationale as accelerating its gaming business across mobile, PC, console, and cloud. The economic question is whether those benefits are incremental, durable, and achievable after integration costs and regulatory constraints.', 'All-cash consideration gives target shareholders a fixed contractual amount and leaves acquirer shareholders exposed to the full financing and integration risk. Stock consideration would share more future value risk with target holders through the exchange ratio.', 'The deal also changes competitive structure. A transaction can be financially attractive and still face regulatory intervention if control over content, distribution, or platform access changes market power.'],
        'formula-construction': ['The purchase price analysis starts with the equity consideration and then reconciles debt assumed and cash acquired to the enterprise value relevant to operating assets.', 'Microsoft’s announced $68.7 billion value was inclusive of Activision Blizzard’s net cash. The final accounting purchase price reported by Microsoft was $75.4 billion, reflecting the closing transaction and accounting measurement basis.', 'A student must not compare the announcement headline with the final accounting amount without identifying the scope and date of each figure.'],
        'comparative-framework': ['A merger can be structured as a stock purchase, asset purchase, statutory merger, or combination of methods. Legal form affects execution, tax, liabilities, and accounting consequences.', 'Organic investment creates capacity inside the existing company. An acquisition buys an existing capability but adds integration and valuation risk.', 'The correct benchmark is the target’s standalone value, comparable transaction multiples, expected synergies, financing capacity, and regulatory risk. There is no universal acquisition premium that defines a good deal.'],
        interpretation: ['The transaction should be judged by the value of incremental cash flows after integration, financing cost, execution risk, and regulatory constraints, not by the strategic narrative alone.', 'The decision is whether the acquirer can create more value from the target than the consideration and risk-adjusted integration burden consume.', 'The next question is which assumption would destroy value first: revenue growth, cost synergy, regulatory remedy, retention, capital intensity, or financing cost.'],
        'assumptions-limitations': ['Acquisition models depend on forecasts of demand, retention, synergies, integration cost, regulation, tax, and financing. The target’s historical results do not automatically forecast the combined company.', 'Announcement value, equity value, enterprise value, and accounting purchase price can differ because they answer different questions and occur at different dates.', 'Goodwill is not evidence that synergies will be realized. It is an accounting residual that can later be impaired when expected benefits fail to materialize.'],
        'case-resolution': ['Microsoft’s transaction returned to the same finance architecture at closing. It acquired control of Activision Blizzard, recorded the target in consolidated reporting from October 13, 2023, and allocated the purchase price across acquired assets, liabilities, identifiable intangibles, and goodwill.', 'The durable lesson is that an acquisition is not completed when the press release is issued. Value is created only when the control transfer, financing, integration, accounting, and strategic thesis survive contact with the operating business.'],
      },
      definitions: ['acquirer', 'target', 'consideration', 'cashConsideration', 'control', 'goodwill'].map(definitionFor),
      coverage: [coverage('control and transaction structure', 'Conceptual Foundation', ['acquirer', 'target', 'control']), coverage('price and financing', 'Formula Construction', ['consideration', 'cashConsideration']), coverage('accounting and value creation', 'Interpretation', ['goodwill'])],
    },
    consideration_mix: {
      title: 'Microsoft chose certainty for sellers and concentration of risk for itself.',
      dek: 'The all-cash Activision consideration shows how transaction currency changes dilution, funding needs, and who bears the outcome risk.',
      governing: 'How should an acquirer choose between cash, stock, and contingent consideration when each form allocates risk differently?',
      mechanics: 'Consideration mix is the composition of the purchase price across cash, acquirer shares, debt-like instruments, and contingent payments. The mix determines dilution, funding requirements, tax exposure, balance-sheet leverage, and how future performance risk is shared.',
      formula: { label: 'Total consideration', lhsLatex: String.raw`\text{Total consideration}`, relationLatex: '=', rhsLatex: String.raw`\text{Cash}\;+\;\text{Stock}\;+\;\text{Contingent consideration}`, latex: String.raw`\text{Total consideration} = \text{Cash}\;+\;\text{Stock}\;+\;\text{Contingent consideration}`, glossary: commonFormulaGlossary },
      eli5: ['The buyer can pay with cash, shares, or a promise tied to future results.', 'Cash gives sellers certainty. Shares make them share future upside and downside. The mix decides who carries the risk.'],
      sections: {
        'case-context': ['Microsoft and Activision announced an all-cash transaction at $95 per share. The announcement placed the funding and future operating risk on Microsoft rather than sharing it through new Microsoft shares.', 'The consideration form is a financing decision inside the M&A decision. It changes dilution, leverage, liquidity, tax, and the incentives of the former target owners.'],
        'conceptual-foundation': ['Consideration mix explains how the acquirer transfers value to obtain control. Cash is fixed at closing. Stock varies with the acquirer’s share price. Contingent consideration links payment to future performance or specified events.', 'The same headline transaction value can have different economic consequences depending on the currency used. Cash can require borrowing or cash depletion. Stock can reduce funding pressure but dilute existing owners.', 'The central decision is risk allocation. A buyer that is confident in synergies may prefer cash. A buyer uncertain about value may use stock or contingent consideration to share uncertainty.'],
        'economic-logic': ['Cash consideration protects target holders from a fall in the acquirer’s share price, but it removes their participation in future combined-company upside. The acquirer retains all performance variance.', 'Stock consideration changes the ownership map. It can align target holders with the combined company, but it transfers part of the value creation opportunity to them and can be unattractive when the acquirer believes its shares are undervalued.', 'Contingent consideration can bridge valuation disagreement, but it creates measurement, incentive, and dispute risk. The contract must define performance, timing, and control of the variables that determine payment.'],
        'formula-construction': ['The mix is built by identifying each contractual payment form at fair value. An all-cash transaction has no exchange ratio and no new acquirer shares issued as consideration.', 'Microsoft’s announced Activision consideration was all cash at $95 per share. The absence of stock did not eliminate financing risk; it concentrated that risk on Microsoft.', 'The finance professional must reconcile the announcement terms, funding sources, closing adjustments, and accounting purchase price before describing the mix as cheap or expensive.'],
        'comparative-framework': ['Cash consideration differs from stock consideration because cash creates funding and interest exposure while stock creates dilution and shared ownership.', 'Earn-outs and contingent consideration can reduce the initial payment but increase contract complexity and post-close incentives.', 'The correct choice depends on relative valuation, liquidity, leverage capacity, tax, market conditions, seller preferences, and confidence in the synergy case.'],
        interpretation: ['Microsoft’s all-cash structure gave Activision holders a fixed $95 per share and left Microsoft responsible for the full result of the acquisition.', 'The decision implication is not that cash is superior. It is that the consideration form reveals which party bears price, financing, and integration uncertainty.', 'The next question is whether Microsoft had sufficient financing capacity and whether the expected operating benefits justified concentrating risk on the acquirer.'],
        'assumptions-limitations': ['The economic effect of consideration depends on the acquirer’s share valuation, debt capacity, cash balance, tax position, and the target’s willingness to accept risk.', 'An all-cash label does not show whether the cash was on hand or borrowed. Funding sources must be traced separately.', 'Contractual terms can create hidden consideration through options, retention payments, debt refinancing, or contingent obligations.'],
        'case-resolution': ['The Activision transaction provides a clean real example of all-cash consideration. Microsoft paid $95 per share and did not issue a stock exchange ratio to target holders.', 'The durable lesson is that consideration mix is risk design. It determines who funds the purchase, who is diluted, who shares future value, and who absorbs a shortfall if the thesis fails.'],
      },
      definitions: ['consideration', 'cashConsideration', 'exchangeRatio', 'acquirer', 'target'].map(definitionFor),
      coverage: [coverage('payment forms', 'Conceptual Foundation', ['consideration', 'cashConsideration', 'exchangeRatio']), coverage('risk allocation', 'Economic Logic', ['acquirer', 'target']), coverage('funding boundary', 'Assumptions and Limitations', ['cashConsideration'])],
    },
    exchange_ratio: {
      title: 'There was no Microsoft share exchange in the Activision deal.',
      dek: 'The all-cash structure makes the exchange ratio’s purpose visible by its absence: no target holder received a fixed number of Microsoft shares.',
      governing: 'How does an exchange ratio determine dilution, relative ownership, and transaction value in a stock-based merger?',
      mechanics: 'An exchange ratio states the number of acquirer shares delivered for each target share. It converts the acquirer’s share price into target consideration and determines how the combined ownership is divided.',
      formula: { label: 'Exchange ratio', lhsLatex: String.raw`\text{Exchange ratio}`, relationLatex: '=', rhsLatex: String.raw`\frac{\text{Acquirer shares issued}}{\text{Target shares exchanged}}`, latex: String.raw`\text{Exchange ratio} = \frac{\text{Acquirer shares issued}}{\text{Target shares exchanged}}`, glossary: commonFormulaGlossary },
      eli5: ['In a stock deal, the buyer gives a certain number of its shares for each target share.', 'In the Activision deal, the buyer used cash instead. That is why there was no exchange ratio to calculate.'],
      sections: {
        'case-context': ['Microsoft’s agreement to acquire Activision Blizzard specified $95 in cash per share. The merger agreement did not exchange Microsoft shares for Activision shares.', 'The absence of an exchange ratio is not missing data. It is a structural fact about the consideration form.'],
        'conceptual-foundation': ['An exchange ratio is the conversion rule in a stock-based merger. It determines how many acquirer shares a target holder receives for each target share surrendered.', 'The ratio connects two share prices and two ownership claims. It must be analyzed with the acquirer’s share price, the target’s share count, the implied offer value, and the post-close capitalization.', 'An all-cash transaction bypasses that mechanism. The target holder receives cash, and existing acquirer holders do not experience transaction-related share dilution from the consideration.'],
        'economic-logic': ['A stock exchange shares future combined-company performance between the acquirer and target holders. The target holder participates in upside and downside after closing.', 'A fixed ratio can make the dollar value of the offer move with the acquirer’s market price. A fixed value stock deal can require a floating number of shares instead.', 'The ratio therefore allocates both ownership and risk. It is not a formatting detail in the merger agreement.'],
        'formula-construction': ['The ratio is built from the number of acquirer shares delivered divided by the target shares exchanged. The ratio must be reconciled with the target share count, equity awards, options, and treatment of treasury shares.', 'For Activision, the correct conclusion is not a numerical ratio. The agreement specified cash consideration of $95 per share, so the stock-exchange numerator is zero because no Microsoft shares were issued as merger consideration.', 'The next calculation in an all-cash deal is funding capacity and purchase price, not ownership dilution from issued shares.'],
        'comparative-framework': ['A fixed exchange ratio preserves a contractual share relationship but lets the dollar value move with the acquirer’s share price. A fixed value arrangement targets a dollar value but may change the number of shares issued.', 'Cash consideration avoids share dilution but increases cash and financing exposure. Stock consideration reduces immediate cash use but changes ownership.', 'The correct benchmark is the value delivered, the ownership split, the acquirer’s relative valuation, and the risk each party is willing to retain.'],
        interpretation: ['The Activision deal’s all-cash structure means the target holders received price certainty and Microsoft retained all future upside and downside after closing.', 'The decision implication is that “no exchange ratio” is itself an answer. It identifies the absence of stock dilution and shifts analysis toward funding and integration.', 'The next question is whether a stock component would have improved risk sharing or reduced the acquirer’s financing burden.'],
        'assumptions-limitations': ['The exchange ratio can be affected by options, restricted shares, earn-outs, voting agreements, and adjustments for dividends or corporate actions.', 'A lower ratio is not automatically better. The economic outcome depends on the acquirer’s share price and the post-close ownership percentage.', 'Stock consideration can share risk but also transfer future control and value to target holders.'],
        'case-resolution': ['The Activision merger agreement specifies $95 cash per share and no Microsoft share exchange. The correct exchange-ratio conclusion is therefore not applicable, not zero value, and not missing evidence.', 'The durable lesson is to identify the transaction currency before calculating the ratio. A finance student who calculates an exchange ratio for an all-cash deal has missed the deal structure.'],
      },
      definitions: ['exchangeRatio', 'cashConsideration', 'consideration', 'acquirer', 'target'].map(definitionFor),
      coverage: [coverage('ratio mechanics', 'Conceptual Foundation', ['exchangeRatio', 'consideration']), coverage('risk and ownership', 'Economic Logic', ['acquirer', 'target']), coverage('cash versus stock boundary', 'Interpretation', ['cashConsideration'])],
    },
    purchase_price_allocation: {
      title: 'Microsoft paid for more than the assets that Activision could name.',
      dek: 'The final accounting shows how a purchase price becomes identifiable assets, liabilities, intangible assets, and goodwill.',
      governing: 'How is acquisition consideration allocated between identifiable net assets and goodwill, and why does that allocation matter after closing?',
      mechanics: 'Purchase price allocation assigns the consideration transferred to the fair value of identifiable assets acquired and liabilities assumed. The residual becomes goodwill after separately recognizable intangible assets are valued.',
      formula: { label: 'Goodwill', lhsLatex: String.raw`\text{Goodwill}`, relationLatex: '=', rhsLatex: String.raw`\text{Purchase consideration} - \text{Fair value of identifiable net assets acquired}`, latex: String.raw`\text{Goodwill} = \text{Purchase consideration} - \text{Fair value of identifiable net assets acquired}`, glossary: commonFormulaGlossary },
      eli5: ['When a company buys another company, accounting first labels the assets and liabilities it can identify.', 'What is left after that valuation is goodwill. It represents purchased benefits that cannot be separated into a specific asset.'],
      sections: {
        'case-context': ['Microsoft’s 2024 Form 10-K reports a total purchase price of $75.4 billion for Activision Blizzard. The acquisition accounting included $50.945 billion of goodwill and $22.046 billion of acquired intangible assets in the reported preliminary allocation.', 'The numbers show why purchase price allocation is not a bookkeeping afterthought. The allocation determines what will be amortized, what will be tested for impairment, and how the acquisition changes future earnings.'],
        'conceptual-foundation': ['Purchase price allocation is the accounting bridge between transaction value and the fair value of the acquired balance sheet. Identifiable assets include tangible assets and separable or contract-based intangible assets. Liabilities assumed are recognized at the applicable measurement basis.', 'Goodwill is the residual after identifiable net assets have been valued. It can reflect expected synergies, assembled workforce, network effects, going-concern value, and benefits that do not meet the separability or contractual-rights test.', 'The allocation is not a valuation of the entire strategy. It is a reporting classification that determines subsequent accounting and helps users understand what was purchased.'],
        'economic-logic': ['The acquirer’s payment reflects expected future benefits, but the acquired balance sheet contains only the benefits that accounting can identify and measure under the acquisition standard.', 'A larger allocation to finite-lived intangibles increases future amortization. A larger goodwill residual avoids amortization under U.S. GAAP but increases exposure to impairment testing.', 'The accounting profile can therefore affect reported earnings without changing the underlying operating cash flow at the acquisition date.'],
        'formula-construction': ['Start with purchase consideration at the acquisition date. Identify the fair value of tangible assets, working capital, debt, deferred taxes, contractual rights, technology, customer relationships, marketing assets, and other identifiable items.', 'Microsoft reported $75.4 billion of purchase price, $50.945 billion of goodwill, and $22.046 billion of acquired intangible assets in the preliminary Activision allocation. The allocation remained subject to revision in the areas disclosed by Microsoft.', 'The residual calculation must reconcile. If identifiable net assets are undervalued, goodwill is overstated. If identifiable intangibles are missed, future amortization is understated and the goodwill residual is overstated.'],
        'comparative-framework': ['Goodwill is not the same as an identifiable intangible asset. Goodwill cannot be separated or transferred independently from the acquired business, while identifiable intangibles arise from separability or legal and contractual rights.', 'Purchase price allocation differs from impairment testing. Allocation records the acquisition-date fair values. Impairment testing asks whether the recorded value remains recoverable later.', 'The correct comparison is acquisition accounting across comparable transactions and the disclosed asset classes, useful lives, and impairment assumptions.'],
        interpretation: ['The Activision allocation indicates that a large share of the purchase price related to goodwill and identifiable intangible assets. That profile is consistent with a content and intellectual-property business, but it also creates material impairment and amortization sensitivity.', 'The decision implication is to connect the allocation to future financial statements. Reviewers should track amortization, impairment indicators, segment performance, and the operating benefits that support the goodwill balance.', 'The next question is whether the acquired assets are producing the cash flows and strategic benefits assumed when the purchase price was justified.'],
        'assumptions-limitations': ['The allocation depends on fair value models, useful lives, tax assumptions, discount rates, royalty or excess-earnings methods, and the quality of acquired data.', 'Microsoft disclosed that the preliminary allocation was subject to revision. A preliminary figure is source-backed information, but it is not a final valuation conclusion.', 'Goodwill does not prove synergy. An impairment charge can arrive later when the business underperforms, but the charge does not recover the cash already paid.'],
        'case-resolution': ['Microsoft’s Form 10-K gives the concrete bridge: $75.4 billion of purchase price, $22.046 billion of acquired intangibles, and $50.945 billion of goodwill in the preliminary Activision allocation.', 'The durable lesson is that acquisition accounting converts a strategic price into a future earnings profile. The allocation determines which part of the purchase will be amortized, impaired, or carried as goodwill.'],
      },
      definitions: ['consideration', 'identifiableIntangibles', 'goodwill', 'acquirer', 'control'].map(definitionFor),
      coverage: [coverage('allocation mechanics', 'Conceptual Foundation', ['consideration', 'identifiableIntangibles']), coverage('goodwill and residual value', 'Formula Construction', ['goodwill']), coverage('post-close reporting', 'Interpretation', ['acquirer', 'control'])],
    },
  };
  const questionsByTopic = {
    mergers_and_acquisitions: [
      question('What is the finance problem in an acquisition?', 'The problem is whether control of the target can create risk adjusted value greater than the consideration, financing cost, integration burden, and regulatory risk required to obtain it.'),
      question('Why is the announcement price not the whole analysis?', 'The announcement price is one transaction term. The decision also requires the financing source, closing conditions, acquired liabilities, integration plan, accounting allocation, and the cash flows expected after control transfers.'),
      question('What does control change?', 'Control brings the target into the acquirer’s decision system and, after the accounting acquisition date, into consolidated reporting. It also transfers responsibility for the target’s operations, liabilities, and risks.'),
      question('How should synergies be tested?', 'Separate revenue synergies, cost synergies, timing, implementation cost, tax, dis-synergies, and probability of achievement. A synergy assumption is not value until it becomes incremental after integration.'),
      question('Why do regulators matter to valuation?', 'Regulatory remedies can restrict distribution, licensing, data use, or product integration. Those restrictions can reduce the cash flows that justified the consideration or delay when the benefits arrive.'),
      question('What is the most common M&A examination error?', 'The common error is treating strategic fit as proof of financial value. A credible strategic rationale still needs a price, funding plan, integration path, and downside case.'),
      question('What benchmark should be used?', 'Use comparable transaction multiples, the target’s standalone value, the acquirer’s financing capacity, the expected synergy range, and the risk of regulatory or execution failure.'),
      question('What would reverse an acquisition recommendation?', 'A lower sustainable cash-flow forecast, a higher integration cost, a regulatory remedy that removes the strategic benefit, or financing terms that make the combined company financially fragile would reverse the recommendation.'),
    ],
    consideration_mix: [
      question('What does consideration mix decide?', 'It decides how the purchase price is funded and how future transaction risk is shared between the acquirer, target holders, lenders, and other parties.'),
      question('Why does cash create concentration of risk?', 'Cash gives target holders a fixed value at closing, so the acquirer retains the future variance in operating performance, financing cost, integration, and market conditions.'),
      question('What does stock consideration change?', 'Stock consideration creates dilution and gives target holders a continuing ownership claim. The value they receive moves with the acquirer’s share price and the performance of the combined company.'),
      question('When can contingent consideration be useful?', 'It can bridge disagreement about uncertain future performance by deferring part of the payment. The contract must define the metric, period, accounting treatment, and control over the outcome.'),
      question('What did the Activision transaction teach about all-cash consideration?', 'The $95 per share all-cash structure gave Activision holders price certainty and left Microsoft responsible for funding and realizing the future value of the acquisition.'),
      question('What is the most common consideration-mix error?', 'The common error is comparing the headline dollar value without identifying whether it is paid in cash, stock, debt-like instruments, or contingent payments.'),
      question('What benchmark should be used?', 'Compare the financing cost, dilution, tax, liquidity, relative share valuation, seller risk tolerance, and probability of the strategic case under each payment form.'),
      question('What would reverse an all-cash recommendation?', 'A financing constraint, excessive leverage, a materially undervalued acquirer share price, or evidence that risk sharing would improve completion could support a different consideration mix.'),
    ],
    exchange_ratio: [
      question('What does an exchange ratio measure?', 'It measures the number of acquirer shares delivered for each target share exchanged in a stock-based merger and determines the ownership transfer created by the transaction.'),
      question('Why does the acquirer share price matter?', 'The dollar value of a fixed exchange ratio changes with the acquirer’s market price. A falling acquirer price can reduce target consideration even when the contractual share ratio is unchanged.'),
      question('Why is there no exchange ratio in an all-cash transaction?', 'No exchange ratio exists because target holders receive cash rather than acquirer shares. The correct analysis moves to funding, liquidity, and cash consideration.'),
      question('How does a stock merger affect dilution?', 'New acquirer shares increase the total share count and reduce existing owners’ percentage claim, although the acquired business may increase the value of the combined company.'),
      question('What did the Activision agreement specify?', 'The agreement specified $95 in cash for each covered Activision share. It did not provide Microsoft stock as merger consideration, so there was no transaction exchange ratio.'),
      question('What is the most common exchange-ratio error?', 'The common error is calculating a ratio without first reading the transaction currency and without adjusting the target share count for awards, options, or excluded shares.'),
      question('What benchmark should be used?', 'Compare the implied value per target share, post-close ownership percentages, relative valuation, expected dilution, and the risk each shareholder group retains.'),
      question('What would change the conclusion?', 'A revised merger agreement offering stock, a mixed cash-and-stock structure, or a material change in the acquirer’s share price would change the ownership and value analysis.'),
    ],
    purchase_price_allocation: [
      question('What is purchase price allocation?', 'It is the acquisition-date process of assigning consideration to the fair value of identifiable assets acquired and liabilities assumed, with the residual recognized as goodwill.'),
      question('Why are identifiable intangibles separated from goodwill?', 'Identifiable intangibles arise from separability or legal and contractual rights and can therefore be measured and tracked separately. Goodwill is the residual collection of benefits that cannot be separately identified.'),
      question('What did Microsoft report for Activision?', 'Microsoft reported a $75.4 billion accounting purchase price, $50.945 billion of goodwill, and $22.046 billion of acquired intangible assets in the preliminary allocation.'),
      question('Why does the allocation affect future earnings?', 'Finite-lived acquired intangibles generate amortization expense, while goodwill is generally tested for impairment under U.S. GAAP. The allocation therefore changes the pattern of reported earnings after closing.'),
      question('Why can the allocation remain preliminary?', 'Fair values may require additional analysis of technology, customer relationships, tax effects, liabilities, and goodwill. The acquirer can revise the preliminary allocation during the permitted measurement period.'),
      question('What is the most common PPA error?', 'The common error is treating goodwill as a separately identifiable operating asset or assuming that a large goodwill balance proves that synergies will be achieved.'),
      question('What benchmark should be used?', 'Review the acquired asset classes, valuation methods, useful lives, impairment assumptions, and comparable transactions rather than applying a universal goodwill percentage.'),
      question('What evidence would reverse the accounting conclusion?', 'New valuation evidence, a revised liability estimate, a different useful life, a tax adjustment, or an impairment indicator could change the allocation and the future reported expense profile.'),
    ],
  };
  const selected = configs[topic.topic_id];
  return { ...selected, anchorDescription: `Microsoft’s acquisition of Activision Blizzard provides a real transaction anchor for ${topic.canonical_name}.`, sourceList, formula: { ...selected.formula, sourceId: topic.topic_id === 'purchase_price_allocation' ? 'microsoft_2024_10k' : 'microsoft_activision_8k' }, knowledgeMap: { whyItExists: selected.sections['conceptual-foundation'][0], informationIsolated: selected.sections['conceptual-foundation'][1], decisionEnabled: selected.sections.interpretation[1], validityAssumptions: selected.sections['assumptions-limitations'][0], criticalQuestion: selected.sections.interpretation[2] }, sections: selected.sections, governing: selected.governing, eli5: selected.eli5, definitions: selected.definitions, coverage: selected.coverage, questions: questionsByTopic[topic.topic_id] };
}

function makeLboSpec(topic) {
  const sourceList = [
    source('hilton_2007_lbo_8k', 'Hilton Hotels Corporation Form 8-K announcing the Blackstone acquisition', 'https://www.sec.gov/Archives/edgar/data/47580/000110465907052273/a07-18077_1ex99d1.htm'),
    source('hilton_2013_ipo_prospectus', 'Hilton Worldwide Holdings Form 424B4 IPO prospectus', 'https://www.sec.gov/Archives/edgar/data/1585689/000119312513473211/d593452d424b4.htm'),
    source('hilton_2013_credit_agreement', 'Hilton Worldwide 2013 credit agreement filed with the SEC', 'https://www.sec.gov/Archives/edgar/data/1585689/000119312516685295/d153637dex102.htm'),
    source('hilton_2013_10k', 'Hilton Worldwide Holdings 2013 Form 10-K', 'https://www.sec.gov/Archives/edgar/data/1585689/000158568914000006/a2013hwh10-k.htm'),
  ];
  const glossary = {
    enterpriseValue: { term: 'Enterprise value', definition: 'The value of the operating business attributable to all capital providers before excess cash is separated.', location: 'Transaction announcement, valuation analysis, and financing model.', financialInterpretation: 'It states the purchase price for the operating asset rather than only the equity cheque.', commonExaminationTrap: 'Treating enterprise value and equity value as interchangeable when debt and cash are material.' },
    debtFinancing: { term: 'Debt financing', definition: 'Borrowed capital placed into the transaction structure to fund part of the purchase price and fees.', location: 'Credit agreement, debt schedule, and post closing balance sheet.', financialInterpretation: 'Debt increases equity return sensitivity to operating performance and refinancing conditions.', commonExaminationTrap: 'Calling leverage value creation when the return came from multiple expansion or higher risk.' },
    sponsorEquity: { term: 'Sponsor equity', definition: 'Capital contributed by the financial sponsor and co-investors after debt financing and transaction uses are accounted for.', location: 'Sources and uses schedule and sponsor returns analysis.', financialInterpretation: 'It is the denominator for sponsor return measures such as MOIC and IRR.', commonExaminationTrap: 'Using total purchase price rather than the sponsor’s actual equity contribution.' },
    deleveraging: { term: 'Deleveraging', definition: 'Reduction in debt outstanding through mandatory amortization, excess cash sweep, refinancing, asset sales, or other debt repayment.', location: 'Debt schedule, cash flow statement, and credit agreement.', financialInterpretation: 'It increases the equity claim on exit when operating value is held constant.', commonExaminationTrap: 'Treating cash generation as deleveraging when cash is consumed by capital expenditure, working capital, or distributions.' },
    exitValue: { term: 'Exit equity value', definition: 'The value remaining for equity holders after exit enterprise value and debt, cash, and other closing claims are reconciled.', location: 'Exit valuation and sources and uses analysis.', financialInterpretation: 'It is the numerator of an equity return calculation.', commonExaminationTrap: 'Using exit enterprise value as though lenders have no claim.' },
    moic: { term: 'Multiple on Invested Capital', definition: 'The total value received by the investor divided by the capital invested, with interim distributions and timing convention stated.', location: 'Sponsor returns analysis.', financialInterpretation: 'It measures money multiple but does not reveal how long capital was committed.', commonExaminationTrap: 'Treating a high MOIC as equivalent to a high IRR without considering holding period.' },
  };
  const definitionFor = (id) => { const item = glossary[id]; return definition(id, item.term, 'Leveraged buyout and sponsor returns', item.definition, item.financialInterpretation, item.commonExaminationTrap); };
  const evidence = 'Hilton Hotels announced the Blackstone acquisition on July 3, 2007 at $47.50 per share, an approximately $26 billion all cash transaction and a 40% premium to the prior closing price. Hilton’s 2013 credit agreement later disclosed an initial $7.6 billion term loan and $1.0 billion revolving facility, while the December 2013 IPO priced new shares at $20.00 and sold 64,102,564 newly issued shares.';
  const common = {
    leveraged_buyout: {
      title: 'Hilton carried the debt. Blackstone carried the thesis.',
      dek: 'The Hilton transaction makes the LBO mechanism visible: operating value must survive a debt claim before equity receives the upside.',
      governing: 'Can a business support the debt used to acquire it while still producing an acceptable equity return under a conservative exit assumption?',
      mechanics: 'An LBO acquires an operating company with a material debt component, then seeks to create equity value through operating improvement, cash generation, debt repayment, and a disciplined exit. Leverage magnifies both outcomes.',
      formula: { label: 'Exit Equity Value', lhsLatex: String.raw`\text{Exit Equity Value}`, relationLatex: '=', rhsLatex: String.raw`\text{Exit Enterprise Value} - \text{Debt} + \text{Cash}`, latex: String.raw`\text{Exit Equity Value} = \text{Exit Enterprise Value} - \text{Debt} + \text{Cash}`, glossary },
      eli5: ['A buyer uses borrowed money to buy a company.', 'The company’s cash flow must pay the lenders. Whatever value remains belongs to the equity investors.'],
      body: {
        'case-context': [evidence, 'The evidence spans the acquisition, financing, and public re-entry. It does not by itself reveal sponsor returns, because the public record does not provide every original equity contribution and interim distribution.'],
        'conceptual-foundation': ['An LBO is a capital structure and ownership transaction, not a valuation multiple. The buyer replaces part of the target’s previous financing with acquisition debt and gives the operating business a fixed set of claims that must be serviced.', 'The equity thesis has four sources: operating growth, margin improvement, debt repayment, and exit valuation. A credible model separates them instead of treating the total return as proof of management skill.', 'Debt creates convexity for equity. A small increase in enterprise value can create a larger percentage increase in equity value when debt is fixed, but a small decline can destroy the equity cushion just as quickly.'],
        'economic-logic': ['Lenders accept debt service because they expect recurring cash flow, collateral support, covenants, and refinancing access to protect their claim. Equity investors accept the residual risk because leverage can compress the amount of capital they must contribute.', 'The central constraint is cash conversion. EBITDA does not repay debt. Taxes, capital expenditure, working capital, interest, fees, and mandatory amortization determine whether operating performance becomes debt reduction.', 'Multiple expansion is not operational value creation. If the exit multiple rises, the sponsor may earn a strong return without improving the business, but that return is exposed to market conditions rather than execution alone.'],
        'formula-construction': ['Begin with the entry enterprise value and construct sources and uses. Separate purchase equity value, debt assumed, fees, refinancing, minimum cash, and sponsor equity.', 'Build the operating case from revenue, margin, capital expenditure, working capital, taxes, interest, and mandatory debt repayment. Route the resulting cash into the debt schedule before calculating exit debt.', 'The Hilton public record supplies transaction and refinancing facts, but it does not supply a complete sponsor sources and uses schedule. A defensible model must mark the missing entry equity contribution as a required research field rather than infer it from the headline purchase price.'],
        'comparative-framework': ['An LBO differs from a strategic acquisition because the sponsor’s return is tied directly to leverage, exit value, and the equity cheque. A strategic buyer may accept a lower financial return for operating synergies or control benefits.', 'An LBO differs from a management buyout in sponsor identity and governance, although both can use acquisition debt. A recapitalization adds debt without necessarily transferring control.', 'The correct comparison is not a universal leverage threshold. Compare debt service capacity, cyclicality, asset intensity, covenant headroom, refinancing risk, entry valuation, and downside recovery.'],
        interpretation: ['The LBO decision is acceptable only when the base case services debt, the downside case preserves lender protection, and the equity return does not depend on an unsupported exit multiple.', 'The Hilton evidence shows why the financing layer matters. A $7.6 billion term loan and $1.0 billion revolving facility create claims that sit ahead of equity and change the distribution of operating risk.', 'The next question is which return driver is doing the work: cash generation, debt paydown, EBITDA growth, entry price, exit multiple, or an assumption that has not been stress tested.'],
        'assumptions-limitations': ['The conclusion depends on stable cash conversion, realistic maintenance capital expenditure, covenant definitions, interest rates, and an exit market that can support the assumed valuation.', 'Debt repayment can be overstated when working capital releases are temporary or when the model excludes required reinvestment.', 'Public Hilton filings show important transaction and financing facts, but they do not prove the sponsor’s complete MOIC or IRR without the original equity contribution, distributions, and exit proceeds.'],
        'case-resolution': ['Hilton returns the lesson to its governing tension. Blackstone acquired the company at a $26 billion all cash value, financed the business through debt, and later brought Hilton to the public market at a $20 IPO price.', 'The durable finance lesson is not that leverage creates value. Leverage transfers more of the operating outcome to the equity residual after lenders are paid, so the model must prove that cash flow can survive the fixed claim.'],
      },
      defs: ['enterpriseValue', 'debtFinancing', 'sponsorEquity', 'deleveraging', 'exitValue'],
      questions: [
        ['What is the economic engine of an LBO?', 'The return comes from operating improvement, cash generation, debt repayment, and the exit valuation. The model must separate each driver because leverage alone does not create operating value.'],
        ['Why does leverage magnify equity returns?', 'Debt is a fixed senior claim. When enterprise value rises, more of the increase accrues to the residual equity after debt is repaid. The same structure magnifies losses when enterprise value falls.'],
        ['Why is EBITDA not free cash flow?', 'EBITDA excludes taxes, interest, capital expenditure, working capital investment, and other cash requirements. Debt capacity depends on cash available after those uses.'],
        ['What belongs in sources and uses?', 'Uses include purchase equity value, debt assumed or refinanced, fees, minimum cash, and other transaction costs. Sources include new debt, rollover equity, sponsor equity, and other funding.'],
        ['How does debt paydown create equity value?', 'If exit enterprise value is unchanged, every unit of debt repaid increases residual equity value by one unit. The cash used for repayment must still be available after operating and investment needs.'],
        ['Why can multiple expansion mislead?', 'A higher exit multiple can increase equity value without any improvement in the business. That return depends on market repricing and may not be repeatable.'],
        ['What does the Hilton financing evidence establish?', 'The SEC filings establish the acquisition price, later debt facilities, IPO price, and share issuance. They do not establish the sponsor’s full return without the original equity and distribution records.'],
        ['What would make an LBO unattractive?', 'Weak cash conversion, high cyclicality, excessive entry valuation, rising interest cost, limited refinancing access, or a return that depends on exit multiple expansion can make the structure unattractive.'],
        ['What is the most common MBA examination error?', 'The common error is to call leverage a source of value without tracing the operating cash flow that services debt and the downside case that tests lender protection.'],
        ['What should be stress tested first?', 'Stress revenue, margin, working capital, capital expenditure, interest cost, refinancing terms, and exit multiple. Then identify which change first causes a covenant breach or destroys the equity cushion.'],
      ],
    },
    moic: {
      title: 'A strong exit multiple cannot reveal the missing equity cheque.',
      dek: 'MOIC is a clean money multiple only when invested capital, distributions, timing, and exit proceeds are defined precisely.',
      governing: 'How much value did the investor receive for each unit of capital invested, and what does that multiple conceal about time and risk?',
      mechanics: 'MOIC compares total value received with invested capital. It measures the magnitude of the money return, but it does not discount cash flows or distinguish a fast return from a slow one.',
      formula: { label: 'Multiple on Invested Capital', lhsLatex: String.raw`\text{MOIC}`, relationLatex: '=', rhsLatex: String.raw`\frac{\text{Exit Proceeds} + \text{Interim Distributions}}{\text{Invested Capital}}`, latex: String.raw`\text{MOIC} = \frac{\text{Exit Proceeds} + \text{Interim Distributions}}{\text{Invested Capital}}`, glossary },
      eli5: ['MOIC asks how many units of money came back for each unit invested.', 'It does not ask how long the money was invested. A three times return in three years is not the same as three times in ten years.'],
      body: {
        'case-context': [evidence, 'Hilton’s IPO and ownership disclosures provide real exit and ownership observations, but a complete sponsor MOIC still requires the original sponsor equity, interim distributions, and the proceeds attributable to each investor.'],
        'conceptual-foundation': ['MOIC is a money multiple, not an annual return. The numerator must include all value received by the investor, and the denominator must include the capital actually invested rather than the enterprise value of the asset.', 'The measure is useful because it separates the scale of value creation from the calendar required to create it. It is incomplete because it ignores the path and timing of cash flows.', 'A clean MOIC bridge links entry equity, additional contributions, dividends, refinancing distributions, exit proceeds, and any value retained at the measurement date.'],
        'economic-logic': ['Investors care about MOIC because capital is scarce. A higher multiple indicates more total value relative to the capital committed, but the economic attractiveness depends on how long that capital was unavailable and how much downside risk it carried.', 'Leverage can raise MOIC by reducing the equity denominator and increasing the sensitivity of exit equity to enterprise value. It can also reduce MOIC to zero when debt absorbs the exit value.', 'Comparability fails when one calculation includes interim distributions and another includes only exit proceeds. The denominator must also identify whether fees, follow-on investments, and recycled capital are included.'],
        'formula-construction': ['Set the measurement date and identify exit proceeds, interim distributions, and any remaining value. Then identify every contribution that belongs in invested capital.', 'Hilton’s 2007 purchase price and 2013 IPO price are real transaction figures, but they are not a complete MOIC calculation. The public filings used here do not disclose the original sponsor equity cheque and all interim distributions in one reconciled record.', 'Do not fill the missing denominator with the $26 billion purchase value. That value describes the transaction, not the sponsor’s invested equity.'],
        'comparative-framework': ['MOIC differs from IRR because IRR incorporates the timing of each cash flow while MOIC compresses them into a multiple. Both should be read together.', 'Return on equity measures accounting earnings relative to book equity. MOIC measures investor cash and value outcomes relative to invested capital. They answer different questions.', 'The correct comparison is among deals with consistent cash flow definitions, holding periods, leverage, exit basis, and fee treatment. No universal MOIC threshold defines a successful investment.'],
        interpretation: ['A high MOIC means the investor received more total value than capital invested under the stated cash flow definition. It does not establish annualized performance, risk adjusted performance, or the source of value creation.', 'The decision is whether the multiple remains attractive after separating operating growth, debt paydown, entry valuation, exit valuation, fees, and the timing of distributions.', 'The next question is whether the result survives a lower exit multiple and a longer holding period. If it does not, the multiple may be reporting market timing rather than durable business improvement.'],
        'assumptions-limitations': ['MOIC depends on the measurement date, cash flow perimeter, treatment of fees, follow-on capital, distributions, rollover equity, and residual value.', 'A high multiple can coexist with a mediocre IRR when value arrives late. A modest multiple can be attractive when capital returns quickly.', 'Hilton’s public record provides real transaction and IPO facts but does not support a complete sponsor MOIC without missing equity and distribution data. The correct output is a research requirement, not an invented return.'],
        'case-resolution': ['Hilton returns the question to the evidence. The public record shows a $26 billion acquisition, a $20 IPO price, and the sponsor’s majority ownership after the offering, but it does not expose every cash flow needed for a complete MOIC.', 'The durable lesson is that a multiple is only as rigorous as its numerator and denominator. A clean answer names the missing cash flows before presenting a precise return.'],
      },
      defs: ['moic', 'sponsorEquity', 'exitValue', 'deleveraging', 'enterpriseValue'],
      questions: [
        ['What does MOIC measure?', 'MOIC measures total value received divided by invested capital under a stated cash flow definition. It measures money multiple, not annualized return.'],
        ['Why is MOIC not IRR?', 'MOIC ignores the timing of cash flows. IRR discounts the timing and can distinguish an early return from a late return with the same total multiple.'],
        ['What belongs in the numerator?', 'Exit proceeds, interim distributions, and any other value received by the investor belong in the numerator when the measurement convention includes them.'],
        ['What belongs in invested capital?', 'The denominator includes capital actually contributed, including follow on contributions and other amounts defined by the return convention. It is not automatically transaction enterprise value.'],
        ['How can leverage increase MOIC?', 'Debt can reduce the equity capital required at entry and leave more of the exit value to equity when operating value grows. The same leverage can eliminate equity value when performance deteriorates.'],
        ['What does Hilton establish for a MOIC lesson?', 'The filings establish acquisition value, IPO price, shares issued, debt facilities, and ownership disclosures. They do not establish the full sponsor cash flow series required for a complete MOIC.'],
        ['Why must interim distributions be included?', 'Ignoring distributions understates value received and can make an investment appear less successful than it was. The treatment must be consistent across investments.'],
        ['What is the most common examination error?', 'The common error is treating a high MOIC as proof of a high annual return or using purchase enterprise value as invested equity.'],
        ['What benchmark should be used?', 'Compare MOIC with IRR, holding period, leverage, exit basis, fee treatment, and downside outcomes. A single multiple is not a universal performance threshold.'],
        ['What evidence would reverse a MOIC conclusion?', 'A revised invested capital schedule, omitted follow on contribution, undisclosed distribution, different exit basis, or longer holding period could materially change the conclusion.'],
      ],
    },
  };
  const selected = common[topic.topic_id];
  const headingById = Object.fromEntries([['case-context', 'Case Context'], ['governing-question', 'Governing Question'], ['conceptual-foundation', 'Conceptual Foundation'], ['economic-logic', 'Economic Logic'], ['formula-construction', 'Formula Construction'], ['eli5', 'ELI5: Core Intuition'], ['comparative-framework', 'Comparative Framework'], ['interpretation', 'Interpretation'], ['assumptions-limitations', 'Assumptions and Limitations'], ['case-resolution', 'Case Resolution']]);
  const sectionList = Object.entries(selected.body).map(([id, body]) => ({ id, heading: headingById[id], body }));
  return { ...selected, anchorDescription: `Hilton’s 2007 acquisition by Blackstone and 2013 public offering provide a real transaction anchor for ${topic.canonical_name}.`, sourceList, formula: { ...selected.formula, sourceId: topic.topic_id === 'moic' ? 'hilton_2013_ipo_prospectus' : 'hilton_2007_lbo_8k' }, knowledgeMap: { whyItExists: sectionList.find((s) => s.id === 'conceptual-foundation').body[0], informationIsolated: sectionList.find((s) => s.id === 'conceptual-foundation').body[1], decisionEnabled: sectionList.find((s) => s.id === 'interpretation').body[1], validityAssumptions: sectionList.find((s) => s.id === 'assumptions-limitations').body[0], criticalQuestion: sectionList.find((s) => s.id === 'interpretation').body[2] }, sections: sectionList, governing: selected.governing, eli5: selected.eli5, definitions: selected.defs.map(definitionFor), coverage: [coverage('transaction and return mechanics', 'Conceptual Foundation', selected.defs.slice(0, 3)), coverage('value creation and leverage', 'Economic Logic', selected.defs.slice(2, 5)), coverage('evidence and limitations', 'Interpretation', selected.defs.slice(1, 4))], questions: selected.questions.map(([q, a]) => question(q, a)) };
}

function completeSpec(topicId) {
  if (content[topicId]) return content[topicId];
  if (['maintenance_margin', 'margin_call', 'variation_margin'].includes(topicId)) return makeMarginSpec(queue.find((item) => item.topic_id === topicId));
  if (topicId === 'operating_leverage') return makeOperatingLeverageSpec();
  if (topicId === 'stagflation') return makeStagflationSpec();
  if (['initial_public_offering', 'ipo_bake_off', 'ipo_underpricing'].includes(topicId)) return makeIpoSpec(queue.find((item) => item.topic_id === topicId));
  if (['cash_ratio', 'current_ratio', 'quick_ratio'].includes(topicId)) return makeLiquidityRatioSpec(queue.find((item) => item.topic_id === topicId));
  if (['gross_margin', 'operating_margin', 'return_on_assets', 'return_on_equity', 'return_on_invested_capital', 'return_on_capital_employed'].includes(topicId)) return makeProfitabilitySpec(queue.find((item) => item.topic_id === topicId));
  if (['yield_curve', 'normal_yield_curve', 'inverted_yield_curve'].includes(topicId)) return makeYieldCurveSpec(queue.find((item) => item.topic_id === topicId));
  if (['cash_conversion_cycle', 'net_working_capital', 'working_capital'].includes(topicId)) return makeWorkingCapitalSpec(queue.find((item) => item.topic_id === topicId));
  if (['asset_coverage_ratio', 'debt_service_coverage_ratio', 'debt_to_equity_ratio', 'fixed_charge_coverage_ratio', 'ffo_to_debt', 'interest_coverage_ratio', 'net_leverage_ratio', 'total_leverage_ratio'].includes(topicId)) return makeLeverageSpec(queue.find((item) => item.topic_id === topicId));
  if (['consideration_mix', 'exchange_ratio', 'mergers_and_acquisitions', 'purchase_price_allocation'].includes(topicId)) return makeMnaSpec(queue.find((item) => item.topic_id === topicId));
  if (['leveraged_buyout', 'moic'].includes(topicId)) return makeLboSpec(queue.find((item) => item.topic_id === topicId));
  if (genericSpecs[topicId]) return genericSpecs[topicId];
  const topic = queue.find((item) => item.topic_id === topicId);
  return makeFallbackSpec(topic);
}

function buildEli5(topic, spec) {
  if (spec.eli5) return spec.eli5;
  const name = topic.canonical_name;
  const research = topic.research ?? topic;
  const governingQuestion = spec.governing ?? research.governing_question_draft ?? `What decision does ${name} improve?`;
  const reason = spec.knowledgeMap?.whyItExists ?? `${name} exists because a raw financial figure hides an economically important distinction.`;
  const signal = spec.knowledgeMap?.informationIsolated ?? 'It isolates the signal that the decision maker needs to see.';
  const limit = spec.knowledgeMap?.validityAssumptions ?? 'Its meaning depends on comparable inputs and an appropriate setting.';
  return [
    `Start with the question, not the formula. ${name} exists because ordinary financial information hides a distinction that matters: ${reason}`,
    'The mechanism is a controlled test of the relevant financial inputs. Each input has a defined job, and changing an input changes the output only through the relationship defined by the concept.',
    `The output is not a magic score. It is evidence about the question, “${governingQuestion}” ${signal} The reader must trace the result back to the input that moved and the comparison base that gave it meaning.`,
    `The practical use is a better decision. Use the result to compare alternatives, investigate a risk, set a funding or valuation assumption, evaluate recognition, or decide what evidence is needed next. A high or low result matters only because it changes that decision.`,
    `The boundary is part of the lesson. ${limit} If the entity, period, accounting definition, market proxy, tax rule, or funding structure changes, the same output may no longer answer the same question.`,
    `In one sentence: ${name} helps you see a hidden financial relationship, follow it through a defined mechanism, and make a better decision without confusing a useful signal with the whole economic truth.`,
  ];
}

function makeLesson(topic, spec) {
  const sectionMap = { ...spec.sections, eli5: buildEli5(topic, spec) };
  const sectionRecords = sections.map(([id, heading]) => {
    const record = { id, heading };
    if (id === 'mastery-questions') record.conclusionQuestions = spec.questions;
    else if (id === 'governing-question') record.body = sectionMap[id] ?? [spec.governing];
    else record.body = sectionMap[id];
    if (id === 'case-context') record.sourceIds = spec.sourceList.map((item) => item.id);
    if (id === 'case-resolution') {
      record.sourceIds = spec.sourceList.map((item) => item.id);
      const capturedEvidence = evidenceCatalog[topic.topic_id];
      record.evidence = capturedEvidence ? { ...capturedEvidence } : {
        status: 'source_record_generated',
        documentTitle: spec.sourceList[0].title,
        sourceUrl: spec.sourceList[0].url,
        summary: 'This generated source record identifies the governing source, the mechanism it supports, and the decision the lesson teaches. It can later be upgraded with a document excerpt without changing the lesson content.',
        rows: [
          { item: 'Governing question', value: (topic.research ?? topic).governing_question_draft ?? spec.governing, source: spec.sourceList[0].id },
          { item: 'Mechanics', value: spec.mechanics, source: spec.sourceList[0].id },
          { item: 'Decision implication', value: spec.knowledgeMap.decisionEnabled, source: spec.sourceList[0].id },
        ],
        image: null,
        imageSource: spec.sourceList[0].url,
      };
      record.diagram = {
        status: 'generated',
        title: `${topic.canonical_name}: decision architecture`,
        source: spec.sourceList[0].id,
        inputs: Object.values(spec.formula?.glossary ?? {}).slice(0, 3).map((term) => term.term),
        transformation: spec.mechanics,
        decision: spec.knowledgeMap.decisionEnabled,
        insight: 'The diagram shows the inputs, the transformation, and the decision implication in one reading path.',
        ...(capturedEvidence?.diagramImage ? { image: capturedEvidence.diagramImage } : {}),
      };
    }
    return record;
  });
  const cram = [
    ['Governing Question', 'governing-question'],
    ['Definition', 'conceptual-foundation'],
    ['Formula', 'formula-construction'],
    ['Interpretation', 'interpretation'],
    ['Limitation', 'assumptions-limitations'],
  ].map(([label, pointer]) => ({ label, pointer }));
  const definitionCatalog = spec.definitions;
  return {
    id: `generated_batch_${batchNumber}__${topic.topic_id}`,
    topicId: topic.topic_id,
    canonicalName: topic.canonical_name,
    kind: 'standard',
    format: topic.format,
    publishStatus: evidenceCatalog[topic.topic_id]
      ? 'ready_for_editorial_review'
      : 'ready_for_source_record_review',
    eyebrow: 'MBA Finance Deep Dive',
    title: spec.title,
    dek: spec.dek,
    sources: Object.fromEntries(spec.sourceList.map((item) => [item.id, item])),
    sourceHierarchy: spec.sourceList.map((item) => ({ id: item.id, tier: item.tier, title: item.title, url: item.url })),
    definitionCatalog,
    subtopicCoverage: spec.coverage,
    knowledgeMap: spec.knowledgeMap,
    nodes: { [`${topic.topic_id}-question`]: { text: spec.governing ?? (topic.research ?? topic).governing_question_draft, citations: [] } },
    formulas: { primary: spec.formula },
    cram,
    sections: sectionRecords,
    generationAudit: {
      batchId: batch.batch_id,
      anchorDescription: spec.anchorDescription ?? topic.anchor_description,
      applicabilityCheck: topic.applicability_check,
      sourceStatus: 'source_pack_locked',
      fieldLevelValueStatus: evidenceCatalog[topic.topic_id]
        ? 'source-backed field values captured for editorial review'
        : 'no invented values; numerical field extraction remains pending',
      imageStatus: evidenceCatalog[topic.topic_id]
        ? 'source-backed evidence exhibit captured; verify rendering during editorial review'
        : 'no broken image path emitted; primary document capture remains pending',
      editorialPasses: ['draft_pass', 'editorial_pass'],
    },
  };
}

const topicById = new Map(queue.map((item) => [item.topic_id, item]));
const topics = batch.topics.map((item) => topicById.get(item.topic_id) ?? item);
const lessons = topics.map((topic) => makeLesson(topic, completeSpec(topic.topic_id)));

const result = {
  schemaVersion: 'deep-dive-generated-batch.v1',
  generatedAt: new Date().toISOString(),
  batchId: batch.batch_id,
  status: 'generated_for_review',
  lessonCount: lessons.length,
  lessons,
  qualityNote: 'This batch contains source-bound prose, field-level evidence exhibits, explanatory diagrams, and question banks. It remains subject to editorial review before publication.',
};

function scrub(value) {
  if (typeof value === 'string') return value
    .replace(/[—–]/g, ', ')
    .replace(/\bso,?\s+it\b/gi, 'therefore it')
    .replace(/\bso,?\s+the\b/gi, 'therefore the');
  if (Array.isArray(value)) return value.map(scrub);
  if (value && typeof value === 'object') return Object.fromEntries(Object.entries(value).map(([key, item]) => [key, scrub(item)]));
  return value;
}

fs.writeFileSync(outputFile, `${JSON.stringify(scrub(result), null, 2)}\n`);
console.log(JSON.stringify({ outputFile, batchId: batch.batch_id, lessons: lessons.length, publishStatus: lessons.every((lesson) => lesson.publishStatus === 'ready_for_editorial_review') ? 'ready_for_editorial_review' : 'hold_for_evidence_capture_and_editorial_review' }));
